@app.delete("/users/{id}")
def delete_user(id: int, _current_user: dict = Depends(require_roles(*LEADERSHIP_ROLES))):
    if int(id) == int(_current_user.get("id") or 0):
        raise HTTPException(status_code=400, detail="Нельзя отключить свой аккаунт")
    conn = get_db()
    cur = conn.cursor()
    cur.execute("SELECT name,email,role,COALESCE(project_name,'') FROM users WHERE id=%s", (id,))
    user_row = cur.fetchone()
    if not user_row:
        conn.rollback()
        cur.close()
        conn.close()
        raise HTTPException(status_code=404, detail="Пользователь не найден")
    cur.execute("UPDATE users SET active=FALSE, locked_until=NULL WHERE id=%s", (id,))
    if cur.rowcount == 0:
        conn.rollback()
        cur.close()
        conn.close()
        raise HTTPException(status_code=404, detail="Пользователь не найден")
    conn.commit()
    log_audit(
        _current_user.get("name", ""),
        _current_user.get("role", ""),
        "deactivate",
        "user",
        id,
        ("Отключен пользователь: " + str(user_row[0] or user_row[1] or "") + ", роль " + str(user_row[2] or ""))[:250],
        user_row[3] or "",
    )
    cur.close()
    conn.close()
    return {"ok": True}

@app.get("/pricelists")
def get_pricelists(_current_user: dict = Depends(get_current_user)):
    conn = get_db()
    cur = conn.cursor(cursor_factory=psycopg2.extras.RealDictCursor)
    role = _current_user.get("role")
    if role in WORKER_EXECUTION_ROLES:
        projects = user_project_names(_current_user)
        if not projects:
            cur.close(); conn.close()
            return []
        cur.execute("""SELECT DISTINCT pl.id,pl.name,pl.description,pl.for_who as "forWho",pl.coefficient
                       FROM pricelists pl
                       JOIN projects p ON p.pricelist_id=pl.id
                       WHERE p.name = ANY(%s)
                         AND NOT EXISTS (
                             SELECT 1 FROM estimates e
                             WHERE e.project_name=p.name
                               AND e.status='Активная'
                               AND COALESCE(e.smeta_type,'Заказчик')='Заказчик'
                         )""", (projects,))
    elif role not in PRICELIST_VIEW_ROLES:
        cur.close(); conn.close()
        raise HTTPException(status_code=403, detail="Нет доступа к прайс-листам")
    else:
        cur.execute("SELECT id,name,description,for_who as \"forWho\",coefficient FROM pricelists")
    rows = cur.fetchall()
    conn.close()
    return [dict(r) for r in rows]

