def _material_family_tags(tokens: set[str]) -> set[str]:
    t = set(tokens or [])
    families: set[str] = set()
    if t.intersection({"клей"}):
        families.add("adhesive")
    if t.intersection({"штукатурка", "ротбанд"}) or ("смесь" in t and t.intersection({"хабез", "старт"})):
        families.add("plaster")
    if t.intersection({"шпатлевка"}) and "штукатурка" not in t:
        families.add("putty")
    if t.intersection({"грунтовка"}):
        families.add("primer")
    if t.intersection({"цемент"}) and not families.intersection({"plaster", "putty", "adhesive"}):
        families.add("cement")
    if t.intersection({"бетон"}):
        families.add("concrete")
    if t.intersection({"песок"}):
        families.add("sand")
    if not t.intersection({"клей"}) and t.intersection({"керамогранит", "плитка", "гранит", "керамическ"}):
        families.add("tile")
    if t.intersection({"гкл", "гипсокартон"}):
        families.add("gkl")
    if t.intersection({"гвл", "гипсоволокно"}):
        families.add("gvl")
    if t.intersection({"профиль", "уголок", "подвес", "маяк", "рейка", "направляющая", "пн", "пп", "пс", "псу", "cd", "ud", "cw", "uw"}):
        families.add("metal_profile")
    if t.intersection({"саморез", "анкер", "болт", "гайка", "шайба", "дюбель", "крепеж", "гвоздь", "шпилька", "скрепа", "прессшайба", "скоба", "хомут", "клин", "кронштейн"}):
        families.add("fastener")
    if t.intersection({"кабель", "провод"}):
        families.add("cable")
    if t.intersection({"труба", "фитинг", "муфта", "клапан", "американка", "кран", "полипропилен", "канализация", "тройник", "отвод", "ниппель", "переход", "заглушка", "коллектор", "инженерия"}):
        families.add("pipe")
    if t.intersection({"светильник", "лампа", "свет", "светодиод", "прожектор"}):
        families.add("light")
    if t.intersection({"розетка", "выключатель", "автомат", "щит", "электрика"}):
        families.add("electrical_device")
    if t.intersection({"радиатор", "биметалл", "воздухоотводчик"}):
        families.add("heating")
    if t.intersection({"металлочерепица", "черепица", "кровля", "монтеррей"}):
        families.add("roofing")
    if t.intersection({"доска", "брус", "фанера", "осп"}):
        families.add("wood_sheet")
    if t.intersection({"арматура"}):
        families.add("rebar")
    if t.intersection({"краска", "эмаль", "лак"}):
        families.add("paint")
    if t.intersection({"герметик", "силикон", "пена"}):
        families.add("sealant")
    if t.intersection({"раствор", "алебастр", "гипс", "известь"}) and not families.intersection({"plaster", "putty"}):
        families.add("binder_mix")
    return families

def _material_family_match_score(left_tokens: set[str], right_tokens: set[str]) -> float:
    common_families = _material_family_tags(left_tokens).intersection(_material_family_tags(right_tokens))
    if not common_families:
        return 0.0
    high_confidence = {
        "plaster", "putty", "primer", "cement", "tile", "gkl", "gvl",
        "metal_profile", "fastener", "cable", "pipe", "roofing",
        "paint", "sealant", "adhesive", "light", "heating", "electrical_device",
    }
    if common_families.intersection(high_confidence):
        return 0.82
    return 0.76

def _material_name_match_score(left: str, right: str) -> float:
    left_key = _norm_key_text(left or "")
    right_key = _norm_key_text(right or "")
    if not left_key or not right_key:
        return 0.0
    if left_key == right_key:
        return 1.0
    if len(left_key) >= 10 and len(right_key) >= 10 and (left_key in right_key or right_key in left_key):
        return 0.92
    left_tokens = _material_match_tokens(left_key)
    right_tokens = _material_match_tokens(right_key)
    if not left_tokens or not right_tokens:
        return 0.0
    common = left_tokens.intersection(right_tokens)
    family_score = _material_family_match_score(left_tokens, right_tokens)
    if not common:
        return 0.0
    # Типовые накладные часто называют один и тот же материал иначе, чем ГРАНД:
    # "керамогранит" против "гранит керамический", "ГКЛ" против "лист гипсокартонный".
    strong_families = {
        "керамогранит", "гранит", "керамическ", "гкл", "гипсокартон", "гвл",
        "гипсоволокно", "грунтовка", "штукатурка", "шпатлевка", "профиль",
        "кабель", "провод", "труба", "радиатор", "скрепа", "дюбель",
        "кронштейн", "направляющая", "цемент", "бетон", "песок",
        "саморез", "анкер", "болт", "гайка", "шайба", "прессшайба", "светильник",
        "свет", "светодиод", "прожектор", "розетка", "выключатель", "автомат",
        "щит", "электрика", "втулка", "хомут", "скоба", "крепеж",
        "кран", "клей", "плитка", "металлочерепица", "черепица", "кровля",
        "монтеррей", "livorno", "axima", "смесь", "ротбанд", "кнауф",
        "пескобетон", "наливной", "ровнитель", "затирка", "уголок", "подвес",
        "маяк", "рейка", "лента", "серпянка", "пн", "пп", "пс", "псу",
        "cd", "ud", "cw", "uw", "лампа", "фитинг", "муфта", "тройник",
        "отвод", "ниппель", "переход", "заглушка", "коллектор", "клапан",
        "американка", "воздухоотводчик", "полипропилен", "канализация",
        "доска", "брус", "фанера", "осп", "арматура", "гвоздь", "шпилька",
        "перфолента", "краска", "эмаль", "лак", "герметик", "силикон",
        "пена", "раствор", "алебастр", "гипс", "известь",
    }
    if {"металлочерепица", "черепица"}.intersection(left_tokens) and {"металлочерепица", "черепица"}.intersection(right_tokens):
        return 0.84
    if {"керамогранит", "плитка"}.intersection(left_tokens) and {"керамогранит", "плитка"}.intersection(right_tokens) and {"livorno", "axima", "гранит", "керамическ", "матов", "глазур"}.intersection(common):
        return 0.86
    if {"ротбанд", "кнауф", "смесь", "хабез", "старт"}.intersection(left_tokens) and {"ротбанд", "кнауф", "смесь", "хабез", "старт"}.intersection(right_tokens) and {"штукатурка", "шпатлевка", "смесь", "ротбанд", "кнауф"}.intersection(common):
        return 0.84
    if {"гранит", "керамическ"}.issubset(common):
        return 0.86
    if {"гкл", "гипсокартон"}.intersection(left_tokens) and {"гкл", "гипсокартон"}.intersection(right_tokens):
        return 0.84
    if {"гвл", "гипсоволокно"}.intersection(left_tokens) and {"гвл", "гипсоволокно"}.intersection(right_tokens):
        return 0.84
    if family_score:
        return max(family_score, 0.78)
    strong_common = common.intersection(strong_families)
    score = len(common) / max(1, min(len(left_tokens), len(right_tokens)))
    long_common = [t for t in common if len(t) >= 6]
    if strong_common and len(common) >= 2:
        return min(0.82, max(score + 0.2, 0.62))
    if len(common) >= 3 and score >= 0.45:
        return min(0.9, score + 0.15)
    if len(common) >= 2 and long_common and score >= 0.4:
        return min(0.82, score + 0.1)
    if len(long_common) >= 1 and score >= 0.65:
        return min(0.72, score)
    return score if score >= 0.7 else 0.0

def _material_units_compatible(unit_a: str = "", unit_b: str = "") -> bool:
    base_a = _norm_base_unit(unit_a or "")
    base_b = _norm_base_unit(unit_b or "")
    return not base_a or not base_b or base_a == base_b

def _supply_material_estimate_control(cur, project: str, material_name: str, unit: str = "", work_package: str = "", exclude_request_id=None, exclude_stock_qty: float = 0.0):
    project = (project or "").strip()
    material_name = (material_name or "").strip()
    if not project or not material_name:
        return None
    package = _supply_work_package(work_package)
    target_key = _material_control_key_resolved(cur, project, material_name, unit)
    planned_qty = planned_sum = 0.0
    matched_rows = 0
    fuzzy_matched_rows = 0
    unit_mismatch_matched_rows = 0
    matched_package = package
    best_match = None
    params = [project]
    package_clause = ""
    # Если пользователь принял накладную/перемещение без явного пакета, не блокируем
    # сразу по "Основная": сначала пробуем найти материал во всех активных пакетах.
    if package and package != "Основная":
        package_clause = " AND COALESCE(NULLIF(work_package,''),'Основная')=%s"
        params.append(package)
    cur.execute("""SELECT id, name, sections_json, COALESCE(work_package,'Основная') AS work_package
                   FROM estimates
                   WHERE project_name=%s
                     AND status='Активная'
                     AND COALESCE(smeta_type,'Заказчик') IN ('Заказчик','Материалы')""" + package_clause, tuple(params))
    estimates = _cursor_rows_as_dicts(cur, cur.fetchall())
    estimate_count = len(estimates)
    for est in estimates:
        for section in _estimate_sections(est.get("sections_json")):
            section_name = section.get("name") or ""
            for item in section.get("items") or []:
                if _estimate_item_type_backend(item, section_name) != "material":
                    continue
                if _estimate_material_plan_issue_backend(item, section_name):
                    continue
                raw_qty = _float_or_zero(item.get("quantity"))
                imported_qty = _estimate_imported_quantity(item)
                imported_line_total = _estimate_import_line_total_backend(item)
                material_sum = _estimate_material_sum_backend(item)
                if raw_qty <= 0 and imported_qty <= 0:
                    continue
                if raw_qty < 0 or imported_qty < 0 or imported_line_total < 0 or material_sum < 0:
                    continue
                item_name = (item.get("name") or "").strip()
                item_unit = item.get("unit") or ""
                item_key = _material_control_key_resolved(cur, project, item_name, item_unit)
                exact_match = item_key == target_key
                fuzzy_score = 0.0 if exact_match else _material_name_match_score(material_name, item_name)
                units_compatible = _material_units_compatible(unit, item_unit)
                fuzzy_match = (not exact_match) and fuzzy_score >= 0.55 and (units_compatible or fuzzy_score >= 0.78)
                if not exact_match and not fuzzy_match:
                    continue
                match_score = 1.0 if exact_match else fuzzy_score
                qty = imported_qty
                if qty <= 0:
                    qty = raw_qty
                planned_qty += qty
                planned_sum += material_sum if material_sum > 0 else _estimate_item_sum_backend(item)
                matched_rows += 1
                if fuzzy_match:
                    fuzzy_matched_rows += 1
                    if not units_compatible:
                        unit_mismatch_matched_rows += 1
                matched_package = est.get("work_package") or package
                candidate = {
                    "name": item_name,
                    "unit": _norm_base_unit(item_unit or "") or item_unit or "",
                    "workPackage": matched_package,
                    "score": match_score,
                    "exact": exact_match,
                    "unitsCompatible": units_compatible,
                }
                candidate_rank = (
                    1 if candidate["unitsCompatible"] else 0,
                    1 if candidate["exact"] else 0,
                    candidate["score"],
                    len(_material_match_tokens(item_name)),
                )
                best_rank = best_match.get("rank") if best_match else None
                if best_rank is None or candidate_rank > best_rank:
                    candidate["rank"] = candidate_rank
                    best_match = candidate

    stock_qty = 0.0
    stock_packages = [matched_package]
    if matched_package != "Основная":
        stock_packages.append("Основная")
    cur.execute("""SELECT name, unit, quantity FROM materials
                   WHERE project=%s AND COALESCE(NULLIF(work_package,''),'Основная') = ANY(%s)""",
                (project, stock_packages))
    for row in _cursor_rows_as_dicts(cur, cur.fetchall()):
        if _material_control_key_resolved(cur, project, row.get("name"), row.get("unit")) == target_key or (
            _material_units_compatible(unit, row.get("unit")) and _material_name_match_score(material_name, row.get("name")) >= 0.55
        ):
            stock_qty += _float_or_zero(row.get("quantity"))

    transferred_qty = 0.0
    transferred_signed_qty = 0.0
    transferred_pending_qty = 0.0
    cur.execute("""SELECT material_name, unit, quantity, COALESCE(signed,FALSE) AS signed
                   FROM material_transfers
                   WHERE project_name=%s
                     AND COALESCE(NULLIF(work_package,''),'Основная')=%s
                     AND COALESCE(status,'Активна') <> 'Аннулирована'""", (project, matched_package))
    for row in _cursor_rows_as_dicts(cur, cur.fetchall()):
        if _material_control_key_resolved(cur, project, row.get("material_name"), row.get("unit")) == target_key or (
            _material_units_compatible(unit, row.get("unit")) and _material_name_match_score(material_name, row.get("material_name")) >= 0.55
        ):
            qty = _float_or_zero(row.get("quantity"))
            transferred_qty += qty
            if row.get("signed"):
                transferred_signed_qty += qty
            else:
                transferred_pending_qty += qty

    returned_qty = 0.0
    cur.execute("""SELECT material, unit, quantity
                   FROM warehouse_history
                   WHERE project=%s
                     AND COALESCE(NULLIF(work_package,''),'Основная')=%s
                     AND LOWER(COALESCE(type,'')) LIKE %s""", (project, matched_package, "возврат от мастера%"))
    for row in _cursor_rows_as_dicts(cur, cur.fetchall()):
        if _material_control_key_resolved(cur, project, row.get("material"), row.get("unit")) == target_key or (
            _material_units_compatible(unit, row.get("unit")) and _material_name_match_score(material_name, row.get("material")) >= 0.55
        ):
            returned_qty += _float_or_zero(row.get("quantity"))

    written_off_qty = 0.0
    cur.execute("""SELECT materials_used
                   FROM work_journal
                   WHERE project=%s
                     AND COALESCE(NULLIF(work_package,''),'Основная')=%s
                     AND COALESCE(status,'') NOT IN ('Аннулировано','Отклонено')
                     AND COALESCE(materials_used,'') <> ''""", (project, matched_package))
    for row in _cursor_rows_as_dicts(cur, cur.fetchall()):
        for item in _json_list_or_empty(row.get("materials_used")):
            if not isinstance(item, dict):
                continue
            item_name = item.get("name") or item.get("materialName") or ""
            item_unit = item.get("unit") or unit
            if _material_control_key_resolved(cur, project, item_name, item_unit) == target_key or (
                _material_units_compatible(unit, item_unit) and _material_name_match_score(material_name, item_name) >= 0.55
            ):
                written_off_qty += _float_or_zero(item.get("quantity"))

    requested_qty = 0.0
    request_params = [project, matched_package]
    request_exclude_clause = ""
    if exclude_request_id:
        request_exclude_clause = " AND id<>%s"
        request_params.append(int(exclude_request_id))
    cur.execute("""SELECT id, status, items_json, material_name, quantity, unit, COALESCE(work_package,'Основная') AS work_package
                   FROM supply_requests
                   WHERE project=%s
                     AND COALESCE(status,'') NOT IN ('Отклонена','Отменена','Отменена с откатом','Поставлено')
                     AND COALESCE(NULLIF(work_package,''),'Основная')=%s""" + request_exclude_clause,
                tuple(request_params))
    for row in _cursor_rows_as_dicts(cur, cur.fetchall()):
        raw_items = _json_list_or_empty(row.get("items_json"))
        if not raw_items:
            raw_items = [{
                "materialName": row.get("material_name") or "",
                "quantity": row.get("quantity") or 0,
                "unit": row.get("unit") or "",
                "workPackage": row.get("work_package") or matched_package,
            }]
        for item in raw_items:
            if not isinstance(item, dict):
                continue
            item_name = item.get("materialName") or item.get("name") or ""
            item_unit = item.get("unit") or row.get("unit") or unit
            item_package = _supply_work_package(item.get("workPackage") or item.get("work_package") or row.get("work_package"))
            if item_package != matched_package:
                continue
            if _material_control_key_resolved(cur, project, item_name, item_unit) == target_key or (
                _material_units_compatible(unit, item_unit) and _material_name_match_score(material_name, item_name) >= 0.55
            ):
                item_qty = _float_or_zero(item.get("quantity"))
                delivered_qty = 0.0
                cur.execute("""SELECT material_name, unit, received_quantity, COALESCE(work_package,'Основная') AS work_package
                               FROM supply_deliveries
                               WHERE request_id=%s
                                 AND COALESCE(status,'') NOT IN ('Отменена','Отклонена')""", (row.get("id"),))
                for delivery_row in _cursor_rows_as_dicts(cur, cur.fetchall()):
                    delivery_package = _supply_work_package(delivery_row.get("work_package"))
                    if delivery_package != item_package:
                        continue
                    if _material_control_key_resolved(cur, project, delivery_row.get("material_name"), delivery_row.get("unit")) == target_key or (
                        _material_units_compatible(unit, delivery_row.get("unit")) and _material_name_match_score(material_name, delivery_row.get("material_name")) >= 0.55
                    ):
                        delivered_qty += _float_or_zero(delivery_row.get("received_quantity"))
                requested_qty += max(0.0, item_qty - delivered_qty)

    stock_qty = max(0.0, stock_qty - max(0.0, _float_or_zero(exclude_stock_qty)))
    issued_or_consumed_qty = max(written_off_qty, max(0.0, transferred_qty - returned_qty))
    covered_qty = stock_qty + issued_or_consumed_qty
    remaining = planned_qty - covered_qty - requested_qty
    return {
        "status": "no_active_estimate" if estimate_count == 0 else ("no_estimate_material" if matched_rows == 0 else ("shortage_open" if remaining > 0 else "covered")),
        "estimateCount": estimate_count,
        "matchedRows": matched_rows,
        "plannedQty": round(planned_qty, 6),
        "plannedSum": round(planned_sum, 2),
        "stockQty": round(stock_qty, 6),
        "transferredQty": round(transferred_qty, 6),
        "transferredSignedQty": round(transferred_signed_qty, 6),
        "transferredPendingQty": round(transferred_pending_qty, 6),
        "returnedQty": round(returned_qty, 6),
        "writtenOffQty": round(written_off_qty, 6),
        "coveredQty": round(covered_qty, 6),
        "requestedQty": round(requested_qty, 6),
        "remainingQty": round(remaining, 6),
        "workPackage": matched_package,
        "requestedWorkPackage": package,
        "matchedByFuzzy": fuzzy_matched_rows,
        "matchedWithDifferentUnit": unit_mismatch_matched_rows,
        "canonicalName": (best_match or {}).get("name") or "",
        "canonicalUnit": (best_match or {}).get("unit") or "",
        "canonicalWorkPackage": (best_match or {}).get("workPackage") or matched_package,
        "canonicalMatchScore": round(_float_or_zero((best_match or {}).get("score")), 4),
        "canonicalMatchType": "exact" if (best_match or {}).get("exact") else ("fuzzy" if best_match else ""),
    }

def _canonicalize_invoice_items_from_estimate_control(items: list):
    for item in items or []:
        if not isinstance(item, dict):
            continue
        control = item.get("estimateControl") or {}
        if not isinstance(control, dict):
            continue
        if _float_or_zero(control.get("matchedRows")) <= 0:
            continue
        if _float_or_zero(control.get("matchedWithDifferentUnit")) > 0:
            continue
        canonical_name = str(control.get("canonicalName") or "").strip()
        if not canonical_name:
            continue
        raw_name = str(item.get("name") or item.get("materialName") or "").strip()
        if raw_name and _norm_key_text(raw_name) != _norm_key_text(canonical_name):
            item.setdefault("invoiceOriginalName", raw_name)
            item.setdefault("originalName", raw_name)
            control["invoiceOriginalName"] = raw_name
            control["canonicalizedForStock"] = True
        item["name"] = canonical_name
        item["materialName"] = canonical_name
        canonical_unit = _norm_base_unit(control.get("canonicalUnit") or item.get("unit") or "") or item.get("unit") or ""
        if canonical_unit:
            item["unit"] = canonical_unit
        canonical_package = _supply_work_package(control.get("canonicalWorkPackage") or control.get("workPackage") or item.get("workPackage") or item.get("work_package"))
        item["workPackage"] = canonical_package
        control["workPackage"] = canonical_package
        item["estimateControl"] = control
    return items

def _supply_linked_work_estimate_control(cur, project: str, item: dict, work_package: str = ""):
    project = (project or "").strip()
    if not project or not isinstance(item, dict):
        return None
    package = _supply_work_package(work_package or item.get("workPackage") or item.get("work_package"))
    target_keys = {
        str(item.get("estimateItemKey") or item.get("estimate_item_key") or "").strip(),
        str(item.get("parentWorkKey") or item.get("parent_work_key") or "").strip(),
        str(item.get("workKey") or item.get("work_key") or "").strip(),
    }
    target_keys.discard("")
    target_name = _norm_key_text(
        item.get("parentWorkName")
        or item.get("parent_work_name")
        or item.get("estimateWorkName")
        or item.get("estimate_work_name")
        or item.get("workName")
        or item.get("work_name")
        or ""
    )
    if not target_keys and not target_name:
        return None

    params = [project]
    package_clause = ""
    if package:
        package_clause = " AND COALESCE(NULLIF(work_package,''),'Основная')=%s"
        params.append(package)
    cur.execute("""SELECT id, name, sections_json, COALESCE(NULLIF(work_package,''),'Основная') AS work_package
                   FROM estimates
                   WHERE project_name=%s
                     AND status='Активная'
                     AND COALESCE(smeta_type,'Заказчик')='Заказчик'""" + package_clause, tuple(params))
    for est in _cursor_rows_as_dicts(cur, cur.fetchall()):
        est_id = est.get("id")
        for section_idx, section in enumerate(_estimate_sections(est.get("sections_json"))):
            section_name = section.get("name") or ""
            for item_idx, work in enumerate(section.get("items") or []):
                if not isinstance(work, dict) or _estimate_item_type_backend(work, section_name) != "work":
                    continue
                keys = set(_estimate_item_key_candidates(work, est_id, section_idx, item_idx))
                work_name = work.get("workName") or work.get("name") or ""
                work_name_key = _norm_key_text(work_name)
                if (target_keys and target_keys.intersection(keys)) or (target_name and work_name_key and (target_name == work_name_key or target_name in work_name_key or work_name_key in target_name)):
                    work_qty = _estimate_imported_quantity(work)
                    if work_qty <= 0:
                        work_qty = _float_or_zero(work.get("quantity"))
                    message = "Материал не найден отдельной ресурсной строкой сметы, но привязан к укрупненной работе"
                    if work_name:
                        message += f" «{work_name}»"
                    if section_name:
                        message += f" в разделе «{section_name}»"
                    return {
                        "status": "composite_work_material",
                        "controlLabel": "Комплектация укрупненной работы",
                        "controlMessage": message + ". Учитывать как фактическую комплектацию работы, не как отдельную сметную потребность.",
                        "isCompositeWorkMaterial": True,
                        "estimateId": est_id,
                        "estimateName": est.get("name") or "",
                        "estimateItemKey": next(iter(keys), ""),
                        "workName": work_name,
                        "workPackage": est.get("work_package") or package,
                        "sectionName": section_name,
                        "plannedWorkQty": round(work_qty, 6),
                        "plannedWorkSum": round(_estimate_item_sum_backend(work), 2),
                    }
    return None

def _attach_supply_estimate_control(cur, project: str, items: list, exclude_request_id=None, exclude_stock_by_key=None):
    if not project:
        return items
    exclude_stock_by_key = exclude_stock_by_key or {}
    for item in items or []:
        if not isinstance(item, dict):
            continue
        control = _supply_material_estimate_control(
            cur,
            project,
            item.get("materialName") or item.get("name") or "",
            item.get("unit") or "",
            item.get("workPackage") or item.get("work_package") or "",
            exclude_request_id=exclude_request_id,
            exclude_stock_qty=exclude_stock_by_key.get(_material_control_key_resolved(cur, project, item.get("materialName") or item.get("name") or "", item.get("unit") or ""), 0),
        )
        if not control:
            continue
        if control.get("status") == "no_estimate_material":
            linked_work = _supply_linked_work_estimate_control(
                cur,
                project,
                item,
                item.get("workPackage") or item.get("work_package") or "",
            )
            if linked_work:
                control.update(linked_work)
                control["matchedRows"] = control.get("matchedRows") or 0
            elif _is_invoice_consumable_material(item.get("materialName") or item.get("name") or ""):
                control["status"] = "consumable_outside_estimate"
                control["controlLabel"] = "Расходник вне сметы"
                control["controlMessage"] = "Позиция похожа на расходный инструмент/расходник. Приход разрешен, но она остается видимой в контроле как закупка вне сметной ресурсной строки."
                control["isConsumableOutsideEstimate"] = True
        control_package = _supply_work_package(control.get("workPackage") or item.get("workPackage") or item.get("work_package"))
        item_package = _supply_work_package(item.get("workPackage") or item.get("work_package"))
        if control_package and item_package == "Основная" and control_package != item_package:
            item["workPackage"] = control_package
        qty = _float_or_zero(item.get("quantity"))
        remaining_after = control["remainingQty"] - qty
        control["requestQty"] = round(qty, 6)
        control["remainingAfterRequest"] = round(remaining_after, 6)
        if control["matchedRows"] > 0 and remaining_after < -max(0.01, control["plannedQty"] * 0.05):
            control["status"] = "over_estimate_need"
        item["estimateControl"] = control
    return items

def _enforce_supply_estimate_control(
    items: list,
    *,
    source: str = "заявка",
    allow_manual_project_override: bool = False,
    override_by: str = "",
):
    blockers = []
    for item in items or []:
        if not isinstance(item, dict):
            continue
        control = item.get("estimateControl") or {}
        status = control.get("status")
        if status not in ("no_active_estimate", "no_estimate_material", "over_estimate_need"):
            continue
        name = item.get("materialName") or item.get("name") or ""
        unit = item.get("unit") or ""
        qty = _float_or_zero(item.get("quantity"))
        package = control.get("workPackage") or item.get("workPackage") or item.get("work_package") or "Основная"
        if status == "no_active_estimate":
            blockers.append(f"{name} ({package}) — по объекту нет активной заказной или нормативной сметы материалов")
        elif status == "no_estimate_material":
            blockers.append(f"{name} ({package}) — материала нет в активной смете")
        else:
            remaining = _float_or_zero(control.get("remainingQty"))
            blockers.append(f"{name} ({package}) — запрошено {qty:g} {unit}, по смете осталось {remaining:g} {unit}")
    if blockers:
        if allow_manual_project_override:
            for item in items or []:
                if not isinstance(item, dict):
                    continue
                control = item.get("estimateControl") or {}
                if control.get("status") in ("no_active_estimate", "no_estimate_material", "over_estimate_need"):
                    control["manualProjectInvoiceOverride"] = True
                    control["manualProjectInvoiceOverrideBy"] = override_by or "Система"
                    control["manualProjectInvoiceWarning"] = "Ручной приход на объект принят как прямой заказ/вне цепочки снабжения. Позиция остается под контролем сметы."
                    item["estimateControl"] = control
            return
        prefix = "Заявка" if source == "заявка" else ("Перемещение" if source == "перемещение" else ("Выдача исполнителю" if source == "выдача исполнителю" else "Накладная"))
        raise HTTPException(
            status_code=400,
            detail=prefix + " не проходит сметный контроль. " + "; ".join(blockers[:5]) + ". Сначала добавьте материал в активную/доп. смету или исправьте раздел сметы."
        )

def _copy_approved_supply_request_control(cur, request_id, project: str, items: list) -> bool:
    if not request_id or not items:
        return False
    cur.execute("SELECT status, items_json FROM supply_requests WHERE id=%s", (request_id,))
    req = cur.fetchone()
    if not req:
        return False
    status = (req.get("status") if isinstance(req, dict) else req[0]) or ""
    if status not in ("Утверждена", "В пути", "Поставлено", "Частично поставлено", "Проблема поставки"):
        return False
    request_items = _json_list_or_empty(req.get("items_json") if isinstance(req, dict) else req[1])
    if not request_items:
        return True
    for item in items or []:
        if not isinstance(item, dict):
            continue
        item_package = _supply_work_package(item.get("workPackage") or item.get("work_package"))
        item_key = _material_control_key_resolved(
            cur,
            project,
            item.get("materialName") or item.get("name") or "",
            item.get("unit") or "",
        )
        for req_item in request_items:
            if not isinstance(req_item, dict):
                continue
            req_package = _supply_work_package(req_item.get("workPackage") or req_item.get("work_package"))
            if req_package != item_package:
                continue
            req_key = _material_control_key_resolved(
                cur,
                project,
                req_item.get("materialName") or req_item.get("name") or "",
                req_item.get("unit") or "",
            )
            if req_key != item_key:
                continue
            if isinstance(req_item.get("estimateControl"), dict):
                item["estimateControl"] = dict(req_item["estimateControl"])
                item["estimateControl"]["receiptLockedByRequest"] = request_id
            break
    return True

@app.get("/supply-requests")
def get_supply_requests(limit: Optional[int] = None, offset: int = 0, current_user: dict = Depends(get_current_user)):
    conn = get_db()
    cur = conn.cursor(cursor_factory=psycopg2.extras.RealDictCursor)
    role = current_user.get("role")
    page_sql, page_params = limit_offset_sql(limit, offset)
    if can_see_all_company_data(current_user):
        cur.execute(SUPPLY_SELECT + " ORDER BY id DESC" + page_sql, page_params)
    elif role in ("снабженец", "кладовщик"):
        project_sql, project_params = scoped_project_where(current_user, "project")
        cur.execute(SUPPLY_SELECT + project_sql + " ORDER BY id DESC" + page_sql, project_params + page_params)
    elif role == "поставщик":
        supplier_id = current_supplier_id(cur, current_user)
        if not supplier_id:
            cur.close(); conn.close()
            return []
        cur.execute(SUPPLY_SELECT + " WHERE %s = ANY(COALESCE(selected_suppliers, '{}'::int[])) ORDER BY id DESC" + page_sql,
                    [int(supplier_id)] + page_params)
    elif role == "прораб":
        projects = user_project_names(current_user)
        clauses = ["requested_by_id=%s", "created_by=%s"]
        params = [current_user.get("id"), current_user.get("name") or ""]
        if projects:
            clauses.append("project = ANY(%s)")
            params.append(projects)
        package_sql, package_params = package_access_filter(current_user)
        cur.execute(SUPPLY_SELECT + " WHERE (" + " OR ".join(clauses) + ")" + package_sql + " ORDER BY id DESC" + page_sql, params + package_params + page_params)
    elif role in WORKER_EXECUTION_ROLES:
        package_sql, package_params = package_access_filter(current_user)
        cur.execute(SUPPLY_SELECT + " WHERE (requested_by_id=%s OR created_by=%s)" + package_sql + " ORDER BY id DESC" + page_sql,
                    [current_user.get("id"), current_user.get("name") or ""] + package_params + page_params)
    else:
        cur.close(); conn.close()
        return []
    rows = cur.fetchall()
    conn.close()
    return [_supply_response_for_role(r, current_user) for r in rows]

@app.post("/supply-requests")
def create_supply_request(r: SupplyRequestModel, _current_user: dict = Depends(require_roles(*SUPPLY_ROLES))):
    import json as _json
    from datetime import datetime
    role = (_current_user.get("role") or "").strip()
    project_name = (r.project or "").strip()
    if not project_name:
        raise HTTPException(status_code=400, detail="Заявка снабжения должна быть привязана к объекту или складу")
    created_by = _current_user.get("name") or r.createdBy or ""
    requested_by_id = _current_user.get("id")
    if role in ("директор", "зам_директора"):
        initial_status = "Утверждена"
    elif role == "прораб":
        initial_status = "Подтверждена прорабом"
    else:
        initial_status = "Новая"
    now = datetime.now()
    prorab_id = requested_by_id if role == "прораб" else None
    prorab_name = created_by if role == "прораб" else None
    prorab_at = now if role == "прораб" else None
    director_id = requested_by_id if role in ("директор", "зам_директора") else None
    director_name = created_by if role in ("директор", "зам_директора") else None
    director_at = now if role in ("директор", "зам_директора") else None
    # Нормализация items: если items пустой, но есть materialName, упаковываем как single-item.
    request_package = _supply_work_package(r.workPackage)
    items = _normalize_supply_request_items(r.items, r.materialName, r.quantity, r.unit, request_package)
    if not items:
        raise HTTPException(status_code=400, detail="Заявка должна содержать хотя бы одну позицию")
    require_project_or_warehouse_access(_current_user, project_name)
    request_package = _resolve_supply_request_package(_current_user, items, request_package)
    # material_name / quantity / unit заполняем агрегатом для совместимости со старым UI
    # Если позиций больше одной — пишем «N позиций» в material_name; quantity = сумма всех
    if len(items) == 1:
        agg_name = items[0]["materialName"]
        agg_qty = float(items[0].get("quantity") or 0)
        agg_unit = items[0].get("unit") or r.unit
    else:
        agg_name = items[0]["materialName"] + " и ещё " + str(len(items)-1) + " поз."
        agg_qty = float(len(items))  # количество позиций
        agg_unit = "поз."
    selected_suppliers = _normalize_supplier_ids(r.selectedSuppliers)
    conn = get_db()
    cur = conn.cursor(cursor_factory=psycopg2.extras.RealDictCursor)
    _ensure_supply_runtime_columns(cur)
    conn.commit()
    items = _attach_supply_estimate_control(cur, project_name, items)
    if project_name != "Основной склад":
        _enforce_supply_estimate_control(items, source="заявка")
    items_json = _json.dumps(items, ensure_ascii=False)
    cur.execute(
        "INSERT INTO supply_requests "
        "(material_name,quantity,unit,project,work_package,created_by,date,notes,selected_suppliers,"
        "status,requested_by_role,requested_by_id,urgency,category,"
        "prorab_id,prorab_name,prorab_confirmed_at,"
        "director_id,director_name,director_approved_at,items_json) "
        "VALUES (%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s) RETURNING id",
        (agg_name, agg_qty, agg_unit, project_name, request_package, created_by, r.date, r.notes,
         selected_suppliers, initial_status, role, requested_by_id, r.urgency, r.category,
         prorab_id, prorab_name, prorab_at,
         director_id, director_name, director_at, items_json))
    new_id = cur.fetchone()['id']
    cur.execute(SUPPLY_SELECT + " WHERE id=%s", (new_id,))
    row = cur.fetchone()
    conn.commit()
    conn.close()
    log_audit(
        _current_user.get("name", ""),
        _current_user.get("role", ""),
        "create",
        "supply_request",
        new_id,
        ("Заявка снабжения: " + str(agg_name or "") + ", " + str(agg_qty) + " " + str(agg_unit or "") + ", статус " + str(initial_status or ""))[:250],
        project_name,
    )
    return _supply_response_for_role(row, _current_user)

@app.put("/supply-requests/{id}")
def update_supply_request(id: int, data: dict, _current_user: dict = Depends(require_roles(*SUPPLY_ROLES))):
    from datetime import datetime
    conn = get_db()
    cur = conn.cursor(cursor_factory=psycopg2.extras.RealDictCursor)
    action = data.get('action')
    now = datetime.now()
    role = _current_user.get("role") or ""
    user_id = _current_user.get("id")
    user_name = _current_user.get("name") or ""
    cur.execute("""SELECT project, COALESCE(work_package,'') as work_package, items_json,
                          requested_by_id, created_by, status
                   FROM supply_requests WHERE id=%s""", (id,))
    req = cur.fetchone()
    if not req:
        conn.close()
        raise HTTPException(status_code=404, detail="Заявка не найдена")
    if req.get("project"):
        require_project_or_warehouse_access(_current_user, req.get("project"))
    request_items = _json_list_or_empty(req.get("items_json"))
    request_packages = sorted(set([
        _supply_work_package(item.get("workPackage") or item.get("work_package") or req.get("work_package"))
        for item in request_items
    ] or [_supply_work_package(req.get("work_package"))]))
    for package_name in request_packages:
        if not has_package_access(_current_user, package_name or "Основная"):
            conn.close()
            raise HTTPException(status_code=403, detail="Нет доступа к разделу сметы заявки: " + (package_name or "Основная"))
    if role in WORKER_EXECUTION_ROLES:
        owns_request = (
            str(req.get("requested_by_id") or "") == str(user_id or "")
            or (req.get("created_by") or "").strip().lower() == user_name.strip().lower()
        )
        if not owns_request:
            conn.close()
            raise HTTPException(status_code=403, detail="Исполнитель может менять только свою заявку")
        if action != "cancel":
            conn.close()
            raise HTTPException(status_code=403, detail="Исполнитель может только отменить свою заявку до обработки")
        if (req.get("status") or "Новая") not in ("Новая", "Подтверждена прорабом"):
            conn.close()
            raise HTTPException(status_code=400, detail="Заявка уже в обработке, отмену делает снабжение или руководитель")
    if action == 'confirm_prorab':
        if role not in (*LEADERSHIP_ROLES, "прораб", "главный_инженер"):
            conn.close()
            raise HTTPException(status_code=403, detail="Подтвердить заявку может прораб, главный инженер или руководство")
        cur.execute(
            "UPDATE supply_requests SET status=%s, prorab_id=%s, prorab_name=%s, prorab_confirmed_at=%s WHERE id=%s",
            ('Подтверждена прорабом', user_id, user_name, now, id))
    elif action == 'approve_director':
        if role not in LEADERSHIP_ROLES:
            conn.close()
            raise HTTPException(status_code=403, detail="Утвердить заявку может только директор или замдиректора")
        refreshed_items = _attach_supply_estimate_control(cur, req.get("project") or "", request_items, exclude_request_id=id)
        if req.get("project") and req.get("project") != "Основной склад":
            _enforce_supply_estimate_control(refreshed_items, source="заявка")
            cur.execute("UPDATE supply_requests SET items_json=%s WHERE id=%s", (json.dumps(refreshed_items, ensure_ascii=False), id))
        cur.execute(
            "UPDATE supply_requests SET status=%s, director_id=%s, director_name=%s, director_approved_at=%s WHERE id=%s",
            ('Утверждена', user_id, user_name, now, id))
    elif action == 'reject':
        if role not in (*LEADERSHIP_ROLES, "прораб", "главный_инженер", "снабженец", "кладовщик"):
            conn.close()
            raise HTTPException(status_code=403, detail="Отклонить заявку может прораб, снабжение или руководство")
        cur.execute(
            "UPDATE supply_requests SET status=%s, reject_reason=%s WHERE id=%s",
            ('Отклонена', data.get('rejectReason') or data.get('reason') or '', id))
    elif action == 'cancel':
        current_status = req.get("status") or "Новая"
        if role in WORKER_EXECUTION_ROLES:
            pass
        elif role in LEADERSHIP_ROLES:
            pass
        elif role in ("прораб", "главный_инженер"):
            if current_status not in ("Новая", "Подтверждена прорабом"):
                conn.close()
                raise HTTPException(status_code=400, detail="Заявка уже в снабжении: отменить может директор или замдиректора")
        elif role in ("снабженец", "кладовщик"):
            if current_status not in ("Новая", "Подтверждена прорабом", "Утверждена"):
                conn.close()
                raise HTTPException(status_code=400, detail="Поставка уже началась: отменить может директор или замдиректора")
        else:
            conn.close()
            raise HTTPException(status_code=403, detail="Нет прав на отмену заявки")
        cur.execute("UPDATE supply_requests SET status=%s WHERE id=%s", ('Отменена', id))
    elif 'status' in data:
        conn.close()
        raise HTTPException(status_code=400, detail="Статус заявки меняется только через действия confirm_prorab / approve_director / reject / cancel")
    cur.execute(SUPPLY_SELECT + " WHERE id=%s", (id,))
    row = cur.fetchone()
    conn.commit()
    conn.close()
    audit_action = str(action or data.get("status") or "update")
    log_audit(
        _current_user.get("name", ""),
        _current_user.get("role", ""),
        audit_action,
        "supply_request",
        id,
        ("Заявка снабжения обновлена: " + str((row or {}).get("materialName") or (row or {}).get("material_name") or "") + ", статус " + str((row or {}).get("status") or ""))[:250],
        ((row or {}).get("project") or req.get("project") or ""),
    )
    return _supply_response_for_role(row, _current_user) if row else {"ok": True}

@app.delete("/supply-requests/{id}")
def delete_supply_request(id: int, rollback_received: bool = False, _current_user: dict = Depends(require_roles("директор", "зам_директора", "снабженец", "кладовщик", "прораб"))):
    from datetime import datetime
    conn = get_db()
    conn.autocommit = False
    cur = conn.cursor(cursor_factory=psycopg2.extras.RealDictCursor)
    try:
        cur.execute("SELECT id, project, material_name, status, COALESCE(work_package,'') as work_package, items_json FROM supply_requests WHERE id=%s FOR UPDATE", (id,))
        req = cur.fetchone()
        if not req:
            conn.rollback()
            raise HTTPException(status_code=404, detail="Заявка не найдена")
        if req.get("project"):
            require_project_access(_current_user, req.get("project"))
        request_items = _json_list_or_empty(req.get("items_json"))
        request_packages = sorted(set([
            _supply_work_package(item.get("workPackage") or item.get("work_package") or req.get("work_package"))
            for item in request_items
        ] or [_supply_work_package(req.get("work_package"))]))
        for package_name in request_packages:
            if not has_package_access(_current_user, package_name or "Основная"):
                conn.rollback()
                raise HTTPException(status_code=403, detail="Нет доступа к разделу сметы заявки: " + (package_name or "Основная"))
        current_status = req.get("status") or ""
        if current_status == "Отменена с откатом":
            conn.rollback()
            return {"ok": True, "cancelled": True, "alreadyRolledBack": True}
        if current_status == "Отменена" and not rollback_received:
            conn.rollback()
            return {"ok": True, "cancelled": True, "alreadyCancelled": True}

        cur.execute("SELECT * FROM supply_deliveries WHERE request_id=%s FOR UPDATE", (id,))
        deliveries = cur.fetchall()
        received_deliveries = [d for d in deliveries if float(d.get("received_quantity") or 0) > 0]
        if rollback_received and (_current_user.get("role") not in LEADERSHIP_ROLES):
            conn.rollback()
            raise HTTPException(status_code=403, detail="Откат принятой поставки доступен только директору или замдиректора")
        if received_deliveries and not rollback_received:
            conn.rollback()
            raise HTTPException(status_code=400, detail="По заявке уже есть принятая поставка. Можно только отменить без удаления истории или выполнить откат руководителем.")
        if rollback_received and received_deliveries:
            delivery_ids = [int(d.get("id") or 0) for d in received_deliveries if int(d.get("id") or 0) > 0]
            cur.execute("""SELECT
                              (SELECT COUNT(*) FROM warehouse_invoices
                               WHERE supply_request_id=%s
                                  OR (supply_delivery_id = ANY(%s))) AS invoice_count,
                              (SELECT COUNT(*) FROM supply_history
                               WHERE request_id=%s
                                  OR (delivery_id = ANY(%s))) AS history_count""",
                        (id, delivery_ids, id, delivery_ids))
            doc_links = cur.fetchone() or {}
            linked_docs = int(doc_links.get("invoice_count") or 0) + int(doc_links.get("history_count") or 0)
            if linked_docs:
                conn.rollback()
                raise HTTPException(
                    status_code=400,
                    detail="Откат принятой поставки запрещён после формирования накладной или истории. Оформите сторно отдельным документом, чтобы не потерять связь складского учёта."
                )

        if not rollback_received:
            cur.execute("UPDATE supply_requests SET status=%s WHERE id=%s", ("Отменена", id))
            conn.commit()
            log_audit(
                _current_user.get("name", ""),
                _current_user.get("role", ""),
                "cancel",
                "supply_request",
                id,
                ("Заявка снабжения отменена: " + str(req.get("material_name") or "") + ", статус " + str(req.get("status") or ""))[:250],
                req.get("project") or "",
            )
            return {"ok": True, "cancelled": True, "deliveriesKept": len(deliveries)}

        restored = 0
        if rollback_received:
            for d in received_deliveries:
                qty = float(d.get("received_quantity") or 0)
                name = d.get("material_name") or ""
                project = d.get("project") or ""
                unit = _norm_base_unit(d.get("unit") or "шт") or "шт"
                work_package = _supply_work_package(d.get("work_package") or d.get("workPackage") or req.get("work_package"))
                if not name or not project or qty <= 0:
                    continue
                cur.execute("""SELECT id, quantity FROM materials
                               WHERE name=%s AND project=%s AND COALESCE(NULLIF(work_package,''),'Основная')=%s
                                 AND """ + _sql_norm_unit("unit") + """=%s
                               ORDER BY id LIMIT 1 FOR UPDATE""", (name, project, work_package, unit))
                mat = cur.fetchone()
                if not mat:
                    conn.rollback()
                    raise HTTPException(status_code=400, detail="Нельзя откатить поставку: материал «"+name+"» не найден на складе объекта" + (" по пакету «"+work_package+"»" if work_package else "") + ".")
                stock_qty = float(mat.get("quantity") or 0)
                if stock_qty + 0.000001 < qty:
                    conn.rollback()
                    raise HTTPException(status_code=400, detail="Нельзя откатить поставку «"+name+"»: на складе осталось "+str(stock_qty)+" "+unit+", а принять было "+str(qty)+" "+unit+". Материал уже списывали.")
                remaining_qty = stock_qty - qty
                if remaining_qty <= 0.000001:
                    cur.execute("DELETE FROM materials WHERE id=%s", (mat.get("id"),))
                else:
                    cur.execute("UPDATE materials SET quantity=%s WHERE id=%s", (remaining_qty, mat.get("id")))
                cur.execute("INSERT INTO warehouse_history (material,type,quantity,unit,date,project,issued_by,work_package,date_time) VALUES (%s,%s,%s,%s,%s,%s,%s,%s,%s)",
                            (name, "откат поставки (удаление заявки)", qty, unit, datetime.now().date().isoformat(), project, _current_user.get("name") or "", work_package, datetime.now().strftime("%d.%m.%Y, %H:%M")))
                restored += 1

        cur.execute("UPDATE supply_requests SET status=%s WHERE id=%s", ("Отменена с откатом", id))
        conn.commit()
        log_audit(
            _current_user.get("name", ""),
            _current_user.get("role", ""),
            "rollback",
            "supply_request",
            id,
            ("Заявка снабжения отменена с откатом: " + str(req.get("material_name") or "") + ", восстановлено " + str(restored))[:250],
            req.get("project") or "",
        )
        return {"ok": True, "cancelled": True, "deliveriesKept": len(deliveries), "materialsRolledBack": restored}
    except HTTPException:
        conn.rollback()
        raise
    except Exception as e:
        conn.rollback()
        raise HTTPException(status_code=500, detail=str(e))
    finally:
        cur.close()
        conn.close()

@app.get("/supply-requests/{id}/stock-check")
def supply_request_stock_check(id: int, current_user: dict = Depends(require_roles(*SUPPLY_ROLES))):
    """Возвращает остатки похожих материалов на складе и бюджет проекта.
       Используется UI чтобы показать «есть X из Y, закупить Z»."""
    conn = None
    try:
        conn = get_db()
        cur = conn.cursor(cursor_factory=psycopg2.extras.RealDictCursor)
        is_worker = current_user.get("role") in WORKER_EXECUTION_ROLES
        cur.execute("""SELECT material_name, quantity, unit, project, COALESCE(work_package,'') AS work_package,
                              items_json, requested_by_id, created_by
                       FROM supply_requests WHERE id=%s""", (id,))
        req = cur.fetchone()
        if not req:
            return {"error": "Заявка не найдена"}
        if is_worker:
            current_user_id = str(current_user.get("id") or "")
            current_user_name = (current_user.get("name") or "").strip().lower()
            request_user_id = str(req.get("requested_by_id") or "")
            request_author = (req.get("created_by") or "").strip().lower()
            if request_user_id != current_user_id and request_author != current_user_name:
                raise HTTPException(status_code=403, detail="Исполнитель может проверять склад только по своей заявке")
        request_items = _json_list_or_empty(req.get("items_json"))
        if not request_items:
            request_items = [{"materialName": req.get("material_name") or "", "quantity": req.get("quantity") or 0, "unit": req.get("unit") or "шт", "workPackage": req.get("work_package") or ""}]
        request_items = [
            {
                "materialName": (it.get("materialName") or it.get("name") or "").strip(),
                "quantity": _float_or_zero(it.get("quantity")),
                "unit": it.get("unit") or req.get("unit") or "шт",
                "workPackage": _supply_work_package(it.get("workPackage") or it.get("work_package") or req.get("work_package")),
            }
            for it in request_items if isinstance(it, dict)
        ]
        request_items = [it for it in request_items if it["materialName"] and it["quantity"] > 0]
        for req_item in request_items:
            if not has_package_access(current_user, req_item["workPackage"]):
                raise HTTPException(status_code=403, detail="Нет доступа к разделу сметы заявки: " + req_item["workPackage"])
        display_name = (request_items[0]["materialName"] if len(request_items) == 1 else (req['material_name'] or '')).strip()
        project = (req['project'] or '').strip()
        if project:
            require_project_access(current_user, project)
        needed = sum(_float_or_zero(it.get("quantity")) for it in request_items) if request_items else float(req['quantity'] or 0)
        # Поиск похожих материалов на основном складе (ILIKE по части имени)
        stock_matches = []
        total_available = 0.0
        item_checks = []
        for req_item in request_items:
            name = req_item["materialName"]
            item_package = _supply_work_package(req_item.get("workPackage"))
            item_available = 0.0
            # Берём первое значащее слово (>=4 символа) для гибкого поиска
            tokens = [t for t in name.split() if len(t) >= 4]
            search = tokens[0] if tokens else name
            cur.execute(
                "SELECT id, name, quantity, unit, price, category FROM warehouse_main WHERE name ILIKE %s ORDER BY quantity DESC LIMIT 10",
                ('%' + search + '%',))
            for row in cur.fetchall():
                stock_matches.append({
                    "id": row['id'], "name": row['name'],
                    "quantity": float(row['quantity'] or 0),
                    "unit": row['unit'], "price": 0 if is_worker else float(row['price'] or 0),
                    "category": row['category'],
                    "workPackage": "",
                    "requestItem": name,
                })
                item_available += float(row['quantity'] or 0)
            # Также ищем на складе объекта (materials)
            if project:
                try:
                    cur.execute(
                        """SELECT id, name, quantity, unit, price, category, COALESCE(work_package,'') AS work_package
                           FROM materials
                           WHERE project=%s AND name ILIKE %s AND COALESCE(NULLIF(work_package,''),'Основная')=%s
                           LIMIT 10""",
                        (project, '%' + search + '%', item_package))
                    for row in cur.fetchall():
                        stock_matches.append({
                            "id": row['id'], "name": '[На объекте] ' + (row['name'] or ''),
                            "quantity": float(row['quantity'] or 0),
                            "unit": row['unit'], "price": 0 if is_worker else float(row['price'] or 0),
                            "category": row['category'],
                            "workPackage": _supply_work_package(row.get("work_package")),
                            "requestItem": name,
                        })
                        item_available += float(row['quantity'] or 0)
                except Exception:
                    pass
            item_checks.append({
                "materialName": name,
                "needed": req_item["quantity"],
                "unit": req_item["unit"],
                "workPackage": item_package,
                "available": item_available,
                "shortage": max(0.0, req_item["quantity"] - item_available),
            })
            total_available += item_available
        # Бюджет проекта
        project_budget = 0.0
        project_approved_cost = 0.0
        project_pending_cost = 0.0
        if project:
            try:
                cur.execute("SELECT budget FROM projects WHERE name=%s", (project,))
                pr = cur.fetchone()
                project_budget = float(pr['budget'] or 0) if pr else 0.0
            except Exception:
                project_budget = 0.0
            # Считаем оценочную стоимость уже утверждённых/ожидающих заявок по реальным строкам items_json.
            # Старые агрегаты вида «N позиций» нельзя умножать как материал: это ломает бюджет и пакеты работ.
            try:
                cur.execute(
                    "SELECT material_name, quantity, unit, status, COALESCE(work_package,'') AS work_package, items_json FROM supply_requests WHERE project=%s",
                    (project,))
                requests_rows = cur.fetchall()
                for row in requests_rows:
                    raw_items = _json_list_or_empty(row.get("items_json"))
                    if not raw_items:
                        raw_items = [{
                            "materialName": row.get("material_name") or "",
                            "quantity": row.get("quantity") or 0,
                            "unit": row.get("unit") or "шт",
                            "workPackage": _supply_work_package(row.get("work_package")),
                        }]
                    for item in raw_items:
                        if not isinstance(item, dict):
                            continue
                        mname = (item.get("materialName") or item.get("name") or "").strip()
                        qty = _float_or_zero(item.get("quantity"))
                        if not mname or qty <= 0:
                            continue
                        first_word = mname.split()[0]
                        try:
                            cur.execute(
                                "SELECT AVG(price) AS avg_price FROM warehouse_main WHERE name ILIKE %s",
                                ('%' + first_word + '%',))
                            avg_row = cur.fetchone()
                            avg_price = float(avg_row['avg_price'] or 0) if avg_row else 0.0
                        except Exception:
                            avg_price = 0.0
                        est_cost = qty * avg_price
                        if row['status'] == 'Утверждена':
                            project_approved_cost += est_cost
                        elif row['status'] in ('Новая', 'Подтверждена прорабом'):
                            project_pending_cost += est_cost
            except Exception:
                pass
        shortage = sum(item["shortage"] for item in item_checks) if item_checks else max(0.0, needed - total_available)
        budget_risk = 0.0
        if project_budget > 0:
            budget_risk = (project_approved_cost + project_pending_cost) / project_budget * 100
        return {
            "requestId": id,
            "materialName": display_name,
            "needed": needed,
            "unit": req['unit'],
            "workPackage": req.get("work_package") or "",
            "items": request_items,
            "itemChecks": item_checks,
            "totalAvailable": total_available,
            "shortage": shortage,
            "stockMatches": stock_matches,
            "project": project,
            "projectBudget": 0 if is_worker else project_budget,
            "projectApprovedCost": 0 if is_worker else project_approved_cost,
            "projectPendingCost": 0 if is_worker else project_pending_cost,
            "budgetRiskPercent": 0 if is_worker else budget_risk,
        }
    except Exception as e:
        import traceback
        print("STOCK-CHECK ERROR id=" + str(id) + ": " + str(e))
        print(traceback.format_exc())
        return {"error": "Ошибка сервера: " + str(e)[:200]}
    finally:
        if conn:
            try: conn.close()
            except Exception: pass

OFFERS_SELECT = ("SELECT id, request_id as \"requestId\", supplier_id as \"supplierId\","
                 "price_per_unit as \"pricePerUnit\", total_price as \"totalPrice\","
                 "delivery_days as \"deliveryDays\", notes, status,"
                 "delivery_status as \"deliveryStatus\","
                 "payment_terms as \"paymentTerms\", vat_included as \"vatIncluded\","
                 "pdf_url as \"pdfUrl\", valid_until as \"validUntil\","
                 "supplier_message as \"supplierMessage\","
                 "requested_at as \"requestedAt\", responded_at as \"respondedAt\","
                 "ai_recommended as \"aiRecommended\","
                 "items_kp_json as \"itemsKpJson\" "
                 "FROM supplier_offers")

@app.get("/supplier-offers")
def get_supplier_offers(current_user: dict = Depends(get_current_user)):
    conn = get_db()
    cur = conn.cursor(cursor_factory=psycopg2.extras.RealDictCursor)
    role = current_user.get("role")
    if role in ("директор", "зам_директора", "снабженец", "кладовщик", "бухгалтер"):
        cur.execute(OFFERS_SELECT + " ORDER BY id DESC")
    elif role == "поставщик":
        supplier_id = current_supplier_id(cur, current_user)
        if not supplier_id:
            cur.close(); conn.close()
            return []
        cur.execute(OFFERS_SELECT + " WHERE supplier_id=%s ORDER BY id DESC", (supplier_id,))
    elif role == "прораб":
        projects = user_project_names(current_user)
        if not projects:
            cur.close(); conn.close()
            return []
        package_sql, package_params = package_access_filter(current_user)
        cur.execute(OFFERS_SELECT + " WHERE request_id IN (SELECT id FROM supply_requests WHERE project = ANY(%s)" + package_sql + ") ORDER BY id DESC", [projects] + package_params)
    elif role in WORKER_EXECUTION_ROLES:
        cur.close(); conn.close()
        return []
    else:
        cur.close(); conn.close()
        return []
    rows = cur.fetchall()
    conn.close()
    return [dict(r) for r in rows]

@app.post("/supplier-offers")
def create_supplier_offer(o: SupplierOfferModel, _current_user: dict = Depends(require_roles(*SUPPLY_ROLES))):
    conn = get_db()
    cur = conn.cursor(cursor_factory=psycopg2.extras.RealDictCursor)
    cur.execute("SELECT id, project, selected_suppliers, status FROM supply_requests WHERE id=%s", (o.requestId,))
    req = cur.fetchone()
    if not req:
        cur.close(); conn.close()
        raise HTTPException(status_code=404, detail="Заявка не найдена")
    if (req.get("status") or "Новая") not in ("Утверждена", "КП запрошены"):
        cur.close(); conn.close()
        raise HTTPException(status_code=400, detail="КП можно создать только после утверждения заявки директором")
    supplier_id = o.supplierId
    role = _current_user.get("role")
    if role == "поставщик":
        own_supplier_id = current_supplier_id(cur, _current_user)
        if not own_supplier_id:
            cur.close(); conn.close()
            raise HTTPException(status_code=403, detail="Поставщик не найден")
        if not supplier_is_selected(req.get("selected_suppliers"), own_supplier_id):
            cur.close(); conn.close()
            raise HTTPException(status_code=403, detail="Нет доступа к заявке")
        supplier_id = own_supplier_id
    else:
        if role not in SUPPLY_INTERNAL_ROLES:
            cur.close(); conn.close()
            raise HTTPException(status_code=403, detail="Недостаточно прав для создания КП")
        if req.get("project"):
            require_project_or_warehouse_access(_current_user, req.get("project") or "")
    cur.execute("INSERT INTO supplier_offers (request_id,supplier_id,price_per_unit,total_price,delivery_days,notes) VALUES (%s,%s,%s,%s,%s,%s) RETURNING id",
                (o.requestId,supplier_id,o.pricePerUnit,o.totalPrice,o.deliveryDays,o.notes))
    new_id = cur.fetchone()['id']
    cur.execute(OFFERS_SELECT + " WHERE id=%s", (new_id,))
    row = cur.fetchone()
    conn.commit()
    conn.close()
    return dict(row)

@app.put("/supplier-offers/{id}")
def update_supplier_offer(id: int, data: dict, _current_user: dict = Depends(require_roles(*SUPPLY_ROLES))):
    from datetime import datetime
    conn = get_db()
    cur = conn.cursor(cursor_factory=psycopg2.extras.RealDictCursor)
    action = data.get('action')
    cur.execute("""
        SELECT o.id, o.supplier_id, o.request_id, r.project
        FROM supplier_offers o
        LEFT JOIN supply_requests r ON r.id=o.request_id
        WHERE o.id=%s
    """, (id,))
    offer_access = cur.fetchone()
    if not offer_access:
        cur.close(); conn.close()
        raise HTTPException(status_code=404, detail="КП не найдено")
    role = _current_user.get("role")
    if role == "поставщик":
        supplier_id = current_supplier_id(cur, _current_user)
        if not supplier_id or supplier_id != offer_access.get("supplier_id"):
            cur.close(); conn.close()
            raise HTTPException(status_code=403, detail="Нет доступа к КП")
        if action != 'respond':
            cur.close(); conn.close()
            raise HTTPException(status_code=403, detail="Поставщик может только ответить на своё КП")
    else:
        if role not in SUPPLY_INTERNAL_ROLES:
            cur.close(); conn.close()
            raise HTTPException(status_code=403, detail="Недостаточно прав для изменения КП")
        if offer_access.get("project"):
            require_project_or_warehouse_access(_current_user, offer_access.get("project") or "")

    def _offer_line_key(item):
        return (
            _norm_key_text((item or {}).get("materialName") or (item or {}).get("name") or ""),
            _norm_base_unit((item or {}).get("unit") or ""),
            _supply_work_package((item or {}).get("workPackage") or (item or {}).get("work_package") or ""),
        )

    def _require_valid_supplier_offer_for_approval():
        cur.execute("""SELECT o.status, o.total_price, o.price_per_unit, o.items_kp_json,
                              r.items_json, r.quantity
                       FROM supplier_offers o
                       LEFT JOIN supply_requests r ON r.id=o.request_id
                       WHERE o.id=%s""", (id,))
        guard = cur.fetchone()
        if not guard:
            raise HTTPException(status_code=404, detail="КП не найдено")
        if (guard.get("status") or "") != "Получено":
            raise HTTPException(status_code=400, detail="Нельзя утвердить КП, пока поставщик не прислал цены")
        request_items = _json_list_or_empty(guard.get("items_json"))
        kp_items = _json_list_or_empty(guard.get("items_kp_json"))
        total_price = _float_or_zero(guard.get("total_price"))
        price_per_unit = _float_or_zero(guard.get("price_per_unit"))
        if request_items:
            if not kp_items:
                raise HTTPException(status_code=400, detail="В КП нет постатейных цен по материалам заявки")
            request_by_key = {}
            for req_item in request_items:
                if not isinstance(req_item, dict):
                    continue
                request_by_key[_offer_line_key(req_item)] = req_item
            priced_keys = set()
            kp_total = 0.0
            for kp_item in kp_items:
                if not isinstance(kp_item, dict):
                    continue
                key = _offer_line_key(kp_item)
                req_item = request_by_key.get(key)
                if not req_item:
                    continue
                kp_qty = _float_or_zero(kp_item.get("quantity"))
                req_qty = _float_or_zero(req_item.get("quantity"))
                price = _float_or_zero(kp_item.get("pricePerUnit"))
                line_total = _float_or_zero(kp_item.get("totalPrice"))
                if price <= 0 or line_total <= 0:
                    continue
                if abs(kp_qty - req_qty) > 0.000001:
                    raise HTTPException(
                        status_code=400,
                        detail="Количество в КП не совпадает с заявкой: " + str(req_item.get("materialName") or req_item.get("name") or "позиция")
                    )
                expected_line_total = round(price * req_qty, 2)
                if abs(line_total - expected_line_total) > 0.05:
                    raise HTTPException(
                        status_code=400,
                        detail="Сумма строки КП не сходится с ценой и количеством: " + str(req_item.get("materialName") or req_item.get("name") or "позиция")
                    )
                kp_total += line_total
                priced_keys.add(key)
            missing = []
            for req_item in request_items:
                if not isinstance(req_item, dict):
                    continue
                if _offer_line_key(req_item) not in priced_keys:
                    missing.append(req_item.get("materialName") or req_item.get("name") or "позиция")
            if missing:
                raise HTTPException(status_code=400, detail="В КП нет цены по позициям: " + ", ".join(missing[:5]))
            if abs(total_price - round(kp_total, 2)) > 0.05:
                raise HTTPException(status_code=400, detail="Итог КП не совпадает с суммой строк заявки")
        else:
            request_qty = _float_or_zero(guard.get("quantity"))
            if request_qty > 0 and price_per_unit <= 0:
                raise HTTPException(status_code=400, detail="В КП не указана цена за единицу")
        if total_price <= 0:
            raise HTTPException(status_code=400, detail="Нельзя утвердить КП с нулевой суммой")

    if action == 'respond':
        # Поставщик отвечает на КП: цена, срок, условия, НДС, PDF, комментарий
        import json as _json
        items_kp = data.get('itemsKp') or []
        # Если пришёл массив постатейного КП — считаем итог автоматически
        items_kp_json = None
        if items_kp and isinstance(items_kp, list):
            # Нормализация: каждый item должен иметь pricePerUnit и quantity
            normalized = []
            calc_total = 0.0
            for it in items_kp:
                if not isinstance(it, dict): continue
                p = float(it.get('pricePerUnit') or 0)
                q = float(it.get('quantity') or 0)
                line_total = p * q
                normalized.append({
                    'materialName': it.get('materialName',''),
                    'quantity': q,
                    'unit': it.get('unit','шт'),
                    'workPackage': (it.get('workPackage') or it.get('work_package') or '').strip(),
                    'pricePerUnit': p,
                    'totalPrice': line_total,
                    'deliveryDays': int(it.get('deliveryDays') or 0) if it.get('deliveryDays') else None,
                    'notes': it.get('notes','')
                })
                calc_total += line_total
            items_kp_json = _json.dumps(normalized, ensure_ascii=False)
            # Для совместимости: pricePerUnit = средневзвешенная, totalPrice = сумма
            total = float(data.get('totalPrice') or calc_total)
            ppu = float(data.get('pricePerUnit') or (calc_total / max(1, len(normalized))))
        else:
            # Старый путь — одна цена за единицу
            ppu = float(data.get('pricePerUnit') or 0)
            qty_for_total = float(data.get('quantity') or 0)
            total = float(data.get('totalPrice') or (ppu * qty_for_total))
            cur.execute("""SELECT items_json, material_name, quantity, unit, COALESCE(work_package,'Основная') AS work_package
                           FROM supply_requests WHERE id=%s""", (offer_access.get("request_id"),))
            req_line = cur.fetchone()
            req_items = _json_list_or_empty(req_line.get("items_json") if req_line else None)
            if not req_items and req_line:
                req_items = [{
                    "materialName": req_line.get("material_name") or "",
                    "quantity": req_line.get("quantity") or qty_for_total,
                    "unit": req_line.get("unit") or "",
                    "workPackage": req_line.get("work_package") or "Основная",
                }]
            if len(req_items) == 1:
                req_item = req_items[0]
                req_qty = _float_or_zero(req_item.get("quantity") or qty_for_total)
                items_kp_json = _json.dumps([{
                    "materialName": req_item.get("materialName") or req_item.get("name") or "",
                    "quantity": req_qty,
                    "unit": req_item.get("unit") or "",
                    "workPackage": (req_item.get("workPackage") or req_item.get("work_package") or (req_line.get("work_package") if req_line else "") or "Основная").strip(),
                    "pricePerUnit": ppu,
                    "totalPrice": round(ppu * req_qty, 2),
                    "deliveryDays": int(data.get("deliveryDays") or 0) if data.get("deliveryDays") else None,
                    "notes": data.get("supplierMessage") or "",
                }], ensure_ascii=False)
        cur.execute(
            "UPDATE supplier_offers SET status=%s, price_per_unit=%s, total_price=%s, delivery_days=%s, "
            "payment_terms=%s, vat_included=%s, pdf_url=%s, valid_until=%s, supplier_message=%s, "
            "items_kp_json=COALESCE(%s, items_kp_json), responded_at=%s WHERE id=%s",
            ('Получено', ppu, total, int(data.get('deliveryDays') or 0),
             data.get('paymentTerms') or 'Постоплата',
             bool(data.get('vatIncluded', True)),
             data.get('pdfUrl') or None,
             data.get('validUntil') or None,
             data.get('supplierMessage') or '',
             items_kp_json,
             datetime.now(), id))
    elif action == 'select':
        # Директор выбрал это КП
        if role not in LEADERSHIP_ROLES:
            cur.close(); conn.close()
            raise HTTPException(status_code=403, detail="Утвердить КП может только директор или замдиректора")
        try:
            _require_valid_supplier_offer_for_approval()
        except HTTPException:
            cur.close(); conn.close()
            raise
        cur.execute("UPDATE supplier_offers SET status=%s WHERE id=%s", ('Утверждено', id))
        # Остальные КП по этой заявке — отклонены
        cur.execute("SELECT request_id FROM supplier_offers WHERE id=%s", (id,))
        r = cur.fetchone()
        if r and r['request_id']:
            cur.execute("UPDATE supplier_offers SET status=%s WHERE request_id=%s AND id<>%s AND status<>%s",
                ('Отклонено', r['request_id'], id, 'Отклонено'))
    elif action == 'reject':
        cur.execute("UPDATE supplier_offers SET status=%s WHERE id=%s", ('Отклонено', id))
    else:
        if 'status' in data:
            new_status = str(data.get('status') or '').strip()
            if new_status in ("Утверждено", "Выбрано", "Принято") and role not in LEADERSHIP_ROLES:
                cur.close(); conn.close()
                raise HTTPException(status_code=403, detail="Утвердить КП может только директор или замдиректора")
            if new_status in ("Утверждено", "Выбрано", "Принято"):
                try:
                    _require_valid_supplier_offer_for_approval()
                except HTTPException:
                    cur.close(); conn.close()
                    raise
            cur.execute("UPDATE supplier_offers SET status=%s WHERE id=%s", (data['status'], id))
            if new_status in ("Утверждено", "Выбрано", "Принято"):
                cur.execute("SELECT request_id FROM supplier_offers WHERE id=%s", (id,))
                r = cur.fetchone()
                if r and r['request_id']:
                    cur.execute("UPDATE supplier_offers SET status=%s WHERE request_id=%s AND id<>%s AND status<>%s",
                        ('Отклонено', r['request_id'], id, 'Отклонено'))
        if 'deliveryStatus' in data:
            cur.execute("UPDATE supplier_offers SET delivery_status=%s WHERE id=%s", (data['deliveryStatus'], id))
    cur.execute(OFFERS_SELECT + " WHERE id=%s", (id,))
    row = cur.fetchone()
    conn.commit()
    conn.close()
    return dict(row) if row else {"ok": True}

@app.post("/supply-requests/{id}/request-kp")
def request_kp_from_suppliers(id: int, data: dict, _current_user: dict = Depends(require_roles(*SUPPLY_INTERNAL_ROLES))):
    """Директор отправляет запрос КП нескольким поставщикам.
       data: {supplierIds: [1,2,3], aiRecommendedIds: [1,2]}"""
    try:
        supplier_ids = sorted({int(x) for x in (data.get('supplierIds') or []) if int(x) > 0})
        ai_ids = {int(x) for x in (data.get('aiRecommendedIds') or []) if int(x) > 0}
    except Exception:
        raise HTTPException(status_code=400, detail="Некорректный список поставщиков")
    if not supplier_ids:
        return {"error": "Не выбраны поставщики"}
    conn = get_db()
    cur = conn.cursor(cursor_factory=psycopg2.extras.RealDictCursor)
    # Получаем количество из заявки для preview total
    cur.execute("SELECT quantity, project, status FROM supply_requests WHERE id=%s", (id,))
    req = cur.fetchone()
    if not req:
        cur.close(); conn.close()
        raise HTTPException(status_code=404, detail="Заявка не найдена")
    if req.get('project'):
        require_project_or_warehouse_access(_current_user, req.get('project') or "")
    if (req.get("status") or "Новая") not in ("Утверждена", "КП запрошены"):
        cur.close(); conn.close()
        raise HTTPException(status_code=400, detail="Запрашивать КП можно только после утверждения заявки директором")
    qty = float(req['quantity']) if req else 0
    created = []
    for sid in supplier_ids:
        # Не создаём дубль если уже есть offer
        cur.execute("SELECT id FROM supplier_offers WHERE request_id=%s AND supplier_id=%s", (id, sid))
        if cur.fetchone():
            continue
        cur.execute(
            "INSERT INTO supplier_offers (request_id, supplier_id, status, ai_recommended, requested_at) "
            "VALUES (%s, %s, %s, %s, NOW()) RETURNING id",
            (id, sid, 'Ожидает ответа', sid in ai_ids))
        created.append(cur.fetchone()['id'])
    # Обновляем статус заявки
    cur.execute("""UPDATE supply_requests
                   SET status=CASE WHEN status='Утверждена' THEN %s ELSE status END,
                       selected_suppliers=(
                           SELECT ARRAY(
                               SELECT DISTINCT unnest(COALESCE(selected_suppliers, '{}'::int[]) || %s::int[])
                           )
                       )
                   WHERE id=%s""",
        ('КП запрошены', supplier_ids, id))
    conn.commit()
    conn.close()
    return {"ok": True, "created": len(created), "ids": created}

@app.get("/supply-requests/{id}/suggest-suppliers")
def suggest_suppliers_for_request(id: int, current_user: dict = Depends(require_roles(*SUPPLY_INTERNAL_ROLES))):
    """Возвращает список поставщиков подходящих под категорию материала, ранжированных
       по рейтингу + истории успешных поставок. AI-комментарий опциональный."""
    conn = get_db()
    cur = conn.cursor(cursor_factory=psycopg2.extras.RealDictCursor)
    cur.execute("SELECT material_name, category, project FROM supply_requests WHERE id=%s", (id,))
    req = cur.fetchone()
    if not req:
        conn.close()
        return {"error": "not found"}
    if req.get('project'):
        require_project_access(current_user, req.get('project') or "")
    category = (req['category'] or '').strip()
    material_name = (req['material_name'] or '').lower()
    # Фильтр по категории если задана. Иначе берём всех активных
    if category:
        cur.execute(
            "SELECT id, name, category, specialization, rating, phone, email, status FROM suppliers "
            "WHERE (status IS NULL OR status='Активный' OR status='') AND category=%s ORDER BY rating DESC NULLS LAST",
            (category,))
    else:
        cur.execute(
            "SELECT id, name, category, specialization, rating, phone, email, status FROM suppliers "
            "WHERE (status IS NULL OR status='Активный' OR status='') ORDER BY rating DESC NULLS LAST")
    suppliers = [dict(r) for r in cur.fetchall()]
    # Считаем историю успешных поставок (status='Доставлено') по каждому поставщику
    cur.execute("SELECT supplier_id, COUNT(*) as deliveries FROM supply_history WHERE status='Доставлено' GROUP BY supplier_id")
    deliveries_map = {r['supplier_id']: r['deliveries'] for r in cur.fetchall()}
    # Считаем уже отправленные КП этой заявке
    cur.execute("SELECT supplier_id FROM supplier_offers WHERE request_id=%s", (id,))
    already_requested = {r['supplier_id'] for r in cur.fetchall()}
    conn.close()
    for s in suppliers:
        s['deliveriesCount'] = int(deliveries_map.get(s['id'], 0))
        s['alreadyRequested'] = s['id'] in already_requested
        # Простая логика: AI рекомендует если category совпадает + (rating>=4 OR deliveries>=1)
        score = 0
        if s['rating']: score += float(s['rating'])
        if s['deliveriesCount']: score += min(s['deliveriesCount'], 5)
        if material_name and (s.get('specialization') or '').lower() and any(w in material_name for w in (s['specialization'] or '').lower().split()):
            score += 2
        s['_score'] = score
        s['aiRecommend'] = score >= 5  # порог рекомендации
    suppliers.sort(key=lambda x: -x['_score'])
    return {
        "requestId": id,
        "materialName": req['material_name'],
        "category": category,
        "suppliers": suppliers[:15],  # топ 15
        "aiRecommendedCount": sum(1 for s in suppliers if s.get('aiRecommend')),
    }

@app.get("/supply-requests/{id}/compare-kp")
def compare_kp_for_request(id: int, current_user: dict = Depends(require_roles(*SUPPLY_INTERNAL_ROLES))):
    """Сравнивает все полученные КП по заявке и возвращает AI-вердикт.
       Учитывает цену, срок поставки, условия оплаты, НДС, рейтинг поставщика."""
    conn = get_db()
    cur = conn.cursor(cursor_factory=psycopg2.extras.RealDictCursor)
    cur.execute("SELECT material_name, quantity, unit, project FROM supply_requests WHERE id=%s", (id,))
    req = cur.fetchone()
    if not req:
        conn.close()
        return {"error": "Заявка не найдена"}
    if req.get('project'):
        require_project_access(current_user, req.get('project') or "")
    cur.execute(
        "SELECT o.id, o.supplier_id, o.price_per_unit, o.total_price, o.delivery_days, "
        "o.payment_terms, o.vat_included, o.valid_until, o.supplier_message, o.status, "
        "s.name as supplier_name, s.rating "
        "FROM supplier_offers o LEFT JOIN suppliers s ON s.id=o.supplier_id "
        "WHERE o.request_id=%s AND o.status IN ('Получено','Утверждено')",
        (id,))
    offers = [dict(r) for r in cur.fetchall()]
    conn.close()
    if len(offers) < 2:
        return {
            "error": "Нужно минимум 2 полученных КП для сравнения",
            "offersCount": len(offers),
        }
    # Готовим короткую сводку для AI
    offers_summary = []
    for o in offers:
        offers_summary.append({
            "offerId": o['id'],
            "supplier": o['supplier_name'] or 'Поставщик #'+str(o['supplier_id']),
            "rating": float(o['rating'] or 0),
            "pricePerUnit": float(o['price_per_unit'] or 0),
            "totalPrice": float(o['total_price'] or 0),
            "deliveryDays": int(o['delivery_days'] or 0),
            "paymentTerms": o['payment_terms'] or '',
            "vatIncluded": bool(o['vat_included']),
            "validUntil": str(o['valid_until']) if o['valid_until'] else None,
            "message": o['supplier_message'] or '',
        })
    # Считаем простой score:
    # - ниже цена = лучше
    # - меньше срок = лучше
    # - предоплата = чуть хуже (риск)
    # - выше рейтинг = лучше
    prices = [o['pricePerUnit'] for o in offers_summary if o['pricePerUnit']>0] or [1]
    days = [o['deliveryDays'] for o in offers_summary if o['deliveryDays']>0] or [1]
    min_price = min(prices); max_price = max(prices)
    min_days = min(days); max_days = max(days)
    def _terms_risk(t):
        t = (t or '').lower()
        if 'предоплат' in t and '100' in t: return 0.0  # риск для покупателя
        if '50' in t: return 0.5
        if 'постоплат' in t or 'отсрочк' in t: return 1.0
        return 0.5
    for o in offers_summary:
        sc_price = 1.0 - (o['pricePerUnit']-min_price)/(max_price-min_price) if max_price>min_price else 1.0
        sc_days = 1.0 - (o['deliveryDays']-min_days)/(max_days-min_days) if max_days>min_days else 1.0
        sc_terms = _terms_risk(o['paymentTerms'])
        sc_rating = o['rating']/5.0 if o['rating'] else 0.5
        # веса: цена 40%, срок 20%, условия 20%, рейтинг 20%
        o['score'] = round((sc_price*0.4 + sc_days*0.2 + sc_terms*0.2 + sc_rating*0.2) * 100, 1)
    offers_summary.sort(key=lambda x: -x['score'])
    best = offers_summary[0]
    # AI вердикт текстом
    ai_text = None
    try:
        import openai as oa
        prompt = (
            f"Сравни {len(offers_summary)} коммерческих предложений на материал "
            f"«{req['material_name']}» (нужно {req['quantity']} {req['unit']}).\n"
            f"Предложения:\n"
        )
        for o in offers_summary:
            prompt += (
                f"- {o['supplier']} (рейтинг {o['rating']}/5): "
                f"{o['pricePerUnit']} ₽/ед, итого {o['totalPrice']} ₽, "
                f"срок {o['deliveryDays']} дн, оплата «{o['paymentTerms']}», "
                f"{'с НДС' if o['vatIncluded'] else 'без НДС'}"
                + (f", «{o['message']}»" if o['message'] else "")
                + "\n"
            )
        prompt += (
            "\nДай короткий вывод (2-3 предложения по-русски): кого выбрать и почему. "
            "Учитывай не только цену но и срок, условия оплаты, рейтинг поставщика. "
            "Не используй markdown, не используй ```."
        )
        client = oa.OpenAI(api_key=YANDEX_API_KEY, base_url="https://ai.api.cloud.yandex.net/v1", project=YANDEX_FOLDER_ID)
        r = client.responses.create(
            model="gpt://"+YANDEX_FOLDER_ID+"/yandexgpt-5.1/latest",
            temperature=0.2,
            instructions="Ты помощник директора строительной компании. Сравниваешь коммерческие предложения и даёшь короткий вывод.",
            input=prompt,
            max_output_tokens=400,
        )
        ai_text = (r.output_text or '').strip()
    except Exception as e:
        print("compare-kp AI error:", e)
        ai_text = None
    return {
        "requestId": id,
        "materialName": req['material_name'],
        "quantity": float(req['quantity'] or 0),
        "unit": req['unit'],
        "offersCount": len(offers_summary),
        "bestOfferId": best['offerId'],
        "bestSupplier": best['supplier'],
        "ranking": offers_summary,
        "aiText": ai_text,
    }

@app.post("/supplier-offers/{id}/create-invoice")
def create_invoice_from_offer(id: int, data: dict, _current_user: dict = Depends(require_roles(*SUPPLY_ROLES))):
    """Поставщик выставляет счёт по выигранному КП.
       Автоматически создаёт supplier_invoice."""
    conn = get_db()
    cur = conn.cursor(cursor_factory=psycopg2.extras.RealDictCursor)
    cur.execute(
        "SELECT o.id, o.supplier_id, o.request_id, o.total_price, o.payment_terms, o.vat_included, "
        "s.name as supplier_name, r.project as project_name, r.material_name, "
        "COALESCE(r.work_package,'') AS work_package, r.items_json "
        "FROM supplier_offers o "
        "LEFT JOIN suppliers s ON s.id=o.supplier_id "
        "LEFT JOIN supply_requests r ON r.id=o.request_id "
        "WHERE o.id=%s AND o.status=%s",
        (id, 'Утверждено'))
    offer = cur.fetchone()
    if not offer:
        cur.close(); conn.close()
        return {"error": "Утверждённое КП не найдено"}
    if _current_user.get("role") == "поставщик":
        supplier_id = current_supplier_id(cur, _current_user)
        if not supplier_id or supplier_id != offer['supplier_id']:
            cur.close(); conn.close()
            raise HTTPException(status_code=403, detail="нет доступа к КП")
    else:
        if _current_user.get("role") not in SUPPLY_INTERNAL_ROLES:
            cur.close(); conn.close()
            raise HTTPException(status_code=403, detail="Счёт поставщика создаёт снабжение, склад, бухгалтерия или руководство")
        require_project_access(_current_user, offer['project_name'] or "")
        if _current_user.get("role") in PACKAGE_LIMIT_ROLES and not has_package_access(_current_user, offer.get("work_package") or "Основная"):
            cur.close(); conn.close()
            raise HTTPException(status_code=403, detail="Нет доступа к пакету КП")
    invoice_number = data.get('invoiceNumber') or ''
    invoice_date = data.get('invoiceDate') or None
    amount = float(data.get('amount') or offer['total_price'] or 0)
    offer_total = _float_or_zero(offer.get('total_price'))
    if offer_total > 0 and amount > offer_total + max(1.0, offer_total * 0.02):
        cur.close(); conn.close()
        raise HTTPException(status_code=400, detail=f"Сумма счёта не может быть выше утверждённого КП: {round(offer_total, 2)} ₽")
    vat_amount = float(data.get('vatAmount') or 0)
    file_url = data.get('fileUrl') or data.get('photoUrl') or ''
    description = data.get('description') or ('Материал: '+(offer['material_name'] or ''))
    cur.execute("""SELECT id FROM supplier_invoices
                   WHERE offer_id=%s AND COALESCE(status,'') <> 'Аннулирован'
                   ORDER BY id DESC LIMIT 1""", (id,))
    existing_invoice = cur.fetchone()
    if existing_invoice:
        existing_id = existing_invoice.get('id') if isinstance(existing_invoice, dict) else existing_invoice[0]
        conn.commit()
        cur.close(); conn.close()
        return {"ok": True, "id": existing_id, "alreadyExists": True}
    item_packages = {
        (it.get("workPackage") or it.get("work_package") or offer.get("work_package") or "").strip()
        for it in _json_list_or_empty(offer.get("items_json")) if isinstance(it, dict)
    }
    item_packages = {p for p in item_packages if p}
    invoice_package = data.get('workPackage') or (next(iter(item_packages)) if len(item_packages) == 1 else (offer.get("work_package") or ""))
    cur.execute(
        "INSERT INTO supplier_invoices "
        "(supplier_id, supplier_name, project_name, invoice_number, invoice_date, "
        "amount, vat_amount, description, file_url, status, offer_id, request_id, "
        "payment_terms, material_name, work_package) "
        "VALUES (%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s) RETURNING id",
        (offer['supplier_id'], offer['supplier_name'], offer['project_name'],
         invoice_number, invoice_date, amount, vat_amount, description, file_url,
         'На утверждении', offer['id'], offer['request_id'],
         offer['payment_terms'], offer['material_name'], invoice_package))
    new_id = cur.fetchone()['id']
    conn.commit()
    cur.close(); conn.close()
    return {"ok": True, "id": new_id}

