def _find_supplier_invoice_for_supply(cur, request_id=None, offer_id=None):
    offer_id = int(offer_id or 0)
    request_id = int(request_id or 0)
    if offer_id:
        cur.execute("""SELECT id FROM supplier_invoices
                       WHERE offer_id=%s AND COALESCE(status,'') <> 'Аннулирован'
                       ORDER BY id DESC LIMIT 1""", (offer_id,))
        row = cur.fetchone()
        invoice_id = _row_get(row, "id", 0)
        if invoice_id:
            return invoice_id
    if request_id:
        cur.execute("""SELECT id FROM supplier_invoices
                       WHERE request_id=%s AND COALESCE(status,'') <> 'Аннулирован'
                       ORDER BY id DESC LIMIT 1""", (request_id,))
        row = cur.fetchone()
        return _row_get(row, "id", 0)
    return None

def _detect_cable_info(name):
    import re as _re
    raw = (name or "").strip()
    up = raw.upper().replace("Ё", "Е")
    compact = _re.sub(r"[\s\"'«»()\\/._-]", "", up)
    start_prefixes = [
        "ВВГ", "АВВГ", "ВББШВ", "ПВВ", "ПВС", "СИП", "КВВГ", "КГ",
        "ТППЭП", "ТПВ", "КВПЭФ", "NYM", "NYY", "ПУНП",
        "UTP", "FTP", "SFTP", "FUTP", "UUTP", "SFUTP",
        "КПС", "КПСЭ", "КПСВВ", "КСВВ", "КСПВ", "КСПЭВ", "ППГ",
        "JYSTY", "JEH", "JHSTH"
    ]
    non_cable_markers = [
        "КОРОБ", "РАСПАЕЧ", "РАСПРЕДЕЛ", "РАЗВЕТВ", "ПОДРОЗЕТ", "РОЗЕТК",
        "ВЫКЛЮЧАТ", "КЛЕММ", "НАКОНЕЧ", "ГИЛЬЗ", "МУФТ", "ВВОД", "САЛЬНИК",
        "КАБЕЛЬКАНАЛ", "КАБЕЛКАНАЛ", "КАНАЛКАБЕЛ", "ЛОТОК", "ГОФР", "ТРУБ",
        "КЛИПС", "СКОБ", "ХОМУТ", "ДЕРЖАТЕЛ", "ЗАЖИМ", "СТЯЖК",
        "ДЮБЕЛ", "САМОРЕЗ", "ШУРУП", "ГВОЗД", "БОЛТ", "ГАЙК", "ШАЙБ", "АНКЕР",
        "ПЕРЧАТ", "МЕШОК", "ВЕДРО", "ШПАТЕЛ", "ВАЛИК", "КИСТ",
        "КРАСК", "ШТУКАТУР", "ШПАКЛ"
    ]
    if any(p in compact for p in non_cable_markers):
        return {"isCable": False, "cableType": "", "cores": None, "section": None}
    brand_match = any(compact.startswith(p) for p in start_prefixes)
    named_cable = any(compact.startswith(p) for p in ["КАБЕЛ", "ПРОВОД", "ШНУР"])
    has_cable_mark = any(p in compact for p in start_prefixes if len(p) >= 3)
    is_cable = brand_match or named_cable or has_cable_mark
    cable_type = ""
    if any(p in compact for p in ["КПС", "КПСЭ", "КПСВВ", "ОПС", "ПОЖАР"]):
        cable_type = "Пожарная сигнализация"
    elif any(p in compact for p in ["UTP", "FTP", "SFTP", "FUTP", "UUTP", "SFUTP"]):
        cable_type = "СКС / интернет"
    elif any(p in compact for p in ["КСВВ", "КСПВ", "КСПЭВ", "КВПЭФ", "ТППЭП", "ТПВ", "JYSTY", "JEH", "JHSTH"]):
        cable_type = "Слаботочка / сигнализация"
    elif is_cable:
        cable_type = "Силовой кабель"
    cores = None
    section = None
    if is_cable:
        m3 = _re.search(r"(\d+)\s*[х×x*]\s*(\d+)\s*[х×x*]\s*(\d+(?:[.,]\d+)?)", raw, _re.IGNORECASE)
        if m3:
            cores = int(m3.group(1)) * int(m3.group(2))
            section = float(m3.group(3).replace(",", "."))
        else:
            m2 = _re.search(r"(\d+)\s*[х×x*]\s*(\d+(?:[.,]\d+)?)", raw, _re.IGNORECASE)
            if m2:
                cores = int(m2.group(1))
                section = float(m2.group(2).replace(",", "."))
    return {"isCable": is_cable, "cableType": cable_type, "cores": cores, "section": section}

def _add_project_material(cur, name, unit, qty, price, project, work_package=""):
    if not name or not project or qty <= 0:
        return
    package_name = (work_package or "").strip()
    unit_name = _norm_base_unit(unit or "шт") or "шт"
    cur.execute(f"""SELECT id FROM materials
                   WHERE name=%s
                     AND project=%s
                     AND COALESCE(work_package,'')=%s
                     AND {_sql_norm_unit('unit')}=%s
                   LIMIT 1""", (name, project, package_name, unit_name))
    existing = cur.fetchone()
    if existing:
        cur.execute("UPDATE materials SET quantity=COALESCE(quantity,0)+%s, unit=%s, price=%s WHERE id=%s",
                    (qty, unit_name, price or 0, existing['id'] if isinstance(existing, dict) else existing[0]))
    else:
        cur.execute("""INSERT INTO materials (name, unit, quantity, price, min_quantity, project, category, work_package)
                       VALUES (%s,%s,%s,%s,%s,%s,%s,%s)""",
                    (name, unit_name, qty, price or 0, 0, project, "Закупка", package_name))
    cur.execute("INSERT INTO warehouse_history (material,type,quantity,unit,date,project,issued_by,work_package,date_time) VALUES (%s,%s,%s,%s,%s,%s,%s,%s,%s)",
                (name, "приход (поставка)", qty, unit_name, __import__("datetime").date.today().isoformat(), project, "Снабжение", package_name, __import__("datetime").datetime.now().strftime("%d.%m.%Y, %H:%M")))

def _create_delivery_quality_records(cur, delivery):
    name = (delivery.get('material_name') or '').strip()
    if not name:
        return
    delivery_id = delivery.get('id')
    project = delivery.get('project') or ''
    supplier = delivery.get('supplier_name') or ''
    qty = _float_or_zero(delivery.get('received_quantity'))
    unit = delivery.get('unit') or 'шт'
    work_package = (delivery.get('work_package') or delivery.get('workPackage') or '').strip()
    received_at = delivery.get('received_at') or __import__("datetime").date.today()
    has_inspection = False
    if delivery_id:
        try:
            cur.execute("SELECT id FROM material_inspection_journal WHERE delivery_id=%s LIMIT 1", (delivery_id,))
            has_inspection = bool(cur.fetchone())
        except Exception as e:
            print("DELIVERY INSPECTION CHECK ERROR:", str(e))
    if not has_inspection:
        try:
            cur.execute("""INSERT INTO material_inspection_journal
                           (project_name, delivery_id, material_name, unit, quantity, supplier, work_package,
                            received_at, visual_inspection_result, remarks, inspected)
                           VALUES (%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s)""",
                        (project, delivery_id, name, unit, qty, supplier, work_package, received_at,
                         delivery.get('quality_status') or 'Принято',
                         delivery.get('quality_notes') or '', True))
        except Exception as e:
            print("DELIVERY INSPECTION INSERT ERROR:", str(e))
            try:
                cur.execute("""INSERT INTO material_inspection_journal
                               (project_name, material_name, unit, quantity, supplier, work_package,
                                received_at, visual_inspection_result, remarks, inspected)
                               VALUES (%s,%s,%s,%s,%s,%s,%s,%s,%s,%s)""",
                            (project, name, unit, qty, supplier, work_package, received_at,
                             delivery.get('quality_status') or 'Принято',
                             delivery.get('quality_notes') or '', True))
            except Exception as legacy_error:
                print("DELIVERY INSPECTION LEGACY INSERT ERROR:", str(legacy_error))
    cable_info = _detect_cable_info(name)
    if cable_info["isCable"]:
        has_cable = False
        if delivery_id:
            try:
                cur.execute("SELECT id FROM cable_journal WHERE delivery_id=%s LIMIT 1", (delivery_id,))
                has_cable = bool(cur.fetchone())
            except Exception as e:
                print("DELIVERY CABLE CHECK ERROR:", str(e))
        if not has_cable:
            try:
                cur.execute("""SELECT id FROM cable_journal
                               WHERE project_name=%s AND cable_brand=%s AND COALESCE(length_received,0)=%s
                               LIMIT 1""", (project, name, qty))
                has_cable = bool(cur.fetchone())
            except Exception as e:
                print("DELIVERY CABLE LEGACY CHECK ERROR:", str(e))
        if not has_cable:
            try:
                cur.execute("""INSERT INTO cable_journal
                               (project_name, delivery_id, cable_brand, cable_type, cross_section, cores_count,
                                length_received, supplier, received_at)
                               VALUES (%s,%s,%s,%s,%s,%s,%s,%s,%s)""",
                            (project, delivery_id, name, cable_info["cableType"],
                             cable_info["section"], cable_info["cores"], qty, supplier, received_at))
            except Exception as e:
                print("DELIVERY CABLE INSERT ERROR:", str(e))
                try:
                    cur.execute("""INSERT INTO cable_journal
                                   (project_name, cable_brand, cross_section, cores_count,
                                    length_received, supplier, received_at)
                                   VALUES (%s,%s,%s,%s,%s,%s,%s)""",
                                (project, name, cable_info["section"], cable_info["cores"],
                                 qty, supplier, received_at))
                except Exception as legacy_error:
                    print("DELIVERY CABLE LEGACY INSERT ERROR:", str(legacy_error))

def _create_supply_delivery_history(cur, delivery, status=None, received_qty=None, confirmed_by=None):
    delivery_id = delivery.get('id')
    request_id = delivery.get('request_id')
    received_qty = _float_or_zero(received_qty if received_qty is not None else delivery.get('received_quantity'))
    status = status or delivery.get('status') or 'Принято'
    confirmed_by = confirmed_by if confirmed_by is not None else (delivery.get('received_by') or '')
    try:
        cur.execute("ALTER TABLE supply_history ADD COLUMN IF NOT EXISTS request_id INT")
        cur.execute("ALTER TABLE supply_history ADD COLUMN IF NOT EXISTS delivery_id INT")
        cur.execute("ALTER TABLE supply_history ADD COLUMN IF NOT EXISTS work_package VARCHAR(100)")
    except Exception as e:
        print("SUPPLY HISTORY MIGRATION ERROR:", str(e))
    if delivery_id:
        try:
            cur.execute("SELECT id FROM supply_history WHERE delivery_id=%s LIMIT 1", (delivery_id,))
            existing = cur.fetchone()
            if existing:
                cur.execute("""UPDATE supply_history SET quantity=%s, status=%s, confirmed_by=%s, work_package=%s
                               WHERE id=%s""",
                            (received_qty, status, confirmed_by, delivery.get('work_package') or delivery.get('workPackage') or '',
                             existing['id'] if isinstance(existing, dict) else existing[0]))
                return
        except Exception as e:
            print("SUPPLY HISTORY CHECK ERROR:", str(e))
    try:
        cur.execute("""INSERT INTO supply_history
                       (supplier_id, material_name, quantity, unit, price_per_unit, total_price,
                        project, date, status, confirmed_by, request_id, delivery_id, work_package)
                       VALUES (%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s)""",
                    (delivery.get('supplier_id'), delivery.get('material_name'), received_qty, delivery.get('unit'),
                     _float_or_zero(delivery.get('price_per_unit')),
                     _float_or_zero(delivery.get('price_per_unit')) * received_qty,
                     delivery.get('project'), (delivery.get('received_at') or __import__("datetime").date.today()).date().isoformat()
                     if hasattr(delivery.get('received_at'), 'date') else (delivery.get('received_at') or __import__("datetime").date.today().isoformat()),
                     status, confirmed_by, request_id, delivery_id, delivery.get('work_package') or delivery.get('workPackage') or ''))
    except Exception as e:
        print("SUPPLY HISTORY LINKED INSERT ERROR:", str(e))
        try:
            cur.execute("""INSERT INTO supply_history
                           (supplier_id, material_name, quantity, unit, price_per_unit, total_price,
                            project, date, status, confirmed_by)
                           VALUES (%s,%s,%s,%s,%s,%s,%s,%s,%s,%s)""",
                        (delivery.get('supplier_id'), delivery.get('material_name'), received_qty, delivery.get('unit'),
                         _float_or_zero(delivery.get('price_per_unit')),
                         _float_or_zero(delivery.get('price_per_unit')) * received_qty,
                         delivery.get('project'), __import__("datetime").date.today().isoformat(),
                         status, confirmed_by))
        except Exception as legacy_error:
            print("SUPPLY HISTORY LEGACY INSERT ERROR:", str(legacy_error))

def _ensure_supply_delivery_invoice(cur, delivery, received_qty=None, received_at=None, accepted_by=None):
    import json as _json
    from datetime import date as _date
    delivery_id = delivery.get('id')
    if not delivery_id:
        return None
    try:
        cur.execute("ALTER TABLE warehouse_invoices ADD COLUMN IF NOT EXISTS source_type VARCHAR(100)")
        cur.execute("ALTER TABLE warehouse_invoices ADD COLUMN IF NOT EXISTS source_id INT")
        cur.execute("ALTER TABLE warehouse_invoices ADD COLUMN IF NOT EXISTS supply_delivery_id INT")
        cur.execute("ALTER TABLE warehouse_invoices ADD COLUMN IF NOT EXISTS supply_request_id INT")
        cur.execute("ALTER TABLE warehouse_invoices ADD COLUMN IF NOT EXISTS warehouse_target VARCHAR(50)")
        cur.execute("ALTER TABLE warehouse_invoices ADD COLUMN IF NOT EXISTS selected_action VARCHAR(100)")
        cur.execute("ALTER TABLE warehouse_invoices ADD COLUMN IF NOT EXISTS material_match_json TEXT")
        _ensure_warehouse_invoice_accounting_columns(cur)
        _ensure_invoice_document_link_columns(cur)
    except Exception as e:
        raise HTTPException(status_code=500, detail="Не удалось подготовить поля накладной поставки: " + str(e))
    try:
        cur.execute("SELECT id FROM warehouse_invoices WHERE supply_delivery_id=%s LIMIT 1", (delivery_id,))
        existing = cur.fetchone()
        if existing:
            existing_id = existing['id'] if isinstance(existing, dict) else existing[0]
            linked_supplier_invoice_id = _find_supplier_invoice_for_supply(
                cur,
                request_id=delivery.get('request_id'),
                offer_id=delivery.get('offer_id'),
            )
            if linked_supplier_invoice_id:
                cur.execute("""UPDATE warehouse_invoices
                               SET supplier_invoice_id=COALESCE(supplier_invoice_id,%s)
                               WHERE id=%s""", (linked_supplier_invoice_id, existing_id))
                cur.execute("""UPDATE supplier_invoices
                               SET warehouse_invoice_id=COALESCE(warehouse_invoice_id,%s)
                               WHERE id=%s""", (existing_id, linked_supplier_invoice_id))
            return existing_id
    except Exception as e:
        print("SUPPLY INVOICE CHECK ERROR:", str(e))
    received_qty = _float_or_zero(received_qty if received_qty is not None else delivery.get('received_quantity'))
    if received_qty <= 0:
        return None
    price = _float_or_zero(delivery.get('price_per_unit'))
    total = round(received_qty * price, 2)
    received_at = received_at or delivery.get('received_at') or _date.today()
    if hasattr(received_at, "date"):
        date_value = received_at.date().isoformat()
    else:
        date_value = str(received_at)[:10] if received_at else _date.today().isoformat()
    item = {
        "name": delivery.get('material_name') or "",
        "quantity": received_qty,
        "unit": delivery.get('unit') or "шт",
        "price": price,
        "category": "Закупка",
        "total": total,
        "source": "supply_delivery",
        "deliveryId": delivery_id,
        "requestId": delivery.get('request_id'),
        "workPackage": _supply_work_package(delivery.get('work_package') or delivery.get('workPackage')),
    }
    project = delivery.get('project') or ""
    items = [item]
    if project:
        items = _attach_supply_estimate_control(cur, project, items, exclude_request_id=delivery.get('request_id'))
        _enforce_supply_estimate_control(items, source="накладная поставки")
    number = delivery.get('waybill_number') or ("Поставка-" + str(delivery_id))
    linked_supplier_invoice_id = _find_supplier_invoice_for_supply(
        cur,
        request_id=delivery.get('request_id'),
        offer_id=delivery.get('offer_id'),
    )
    try:
        cur.execute("""INSERT INTO warehouse_invoices
	                       (number,date,supplier_id,supplier_name,accepted_by,location,project,vat,
	                        items,total_base,total_vat,total_with_vat,status,added_by,photo_url,
	                        source_type,source_id,supply_delivery_id,supply_request_id,photo_urls,pages_count,
	                        warehouse_target,selected_action,material_match_json)
	                       VALUES (%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s)
	                       RETURNING id""",
	                    (number, date_value, delivery.get('supplier_id'), delivery.get('supplier_name') or "",
		                     accepted_by or delivery.get('received_by') or "", project, project, "Без НДС",
		                     _json.dumps(items, ensure_ascii=False), total, 0, total,
		                     "Принята", accepted_by or delivery.get('received_by') or "Снабжение",
		                     delivery.get('photo_url') or "", "supply_delivery", delivery_id,
		                     delivery_id, delivery.get('request_id'),
	                         _json.dumps(([delivery.get('photo_url')] if delivery.get('photo_url') else []), ensure_ascii=False),
	                         1, "object", "supply_receipt", _json.dumps([], ensure_ascii=False)))
        new_id = cur.fetchone()
        warehouse_invoice_id = new_id['id'] if isinstance(new_id, dict) else new_id[0]
        if linked_supplier_invoice_id:
            cur.execute("UPDATE warehouse_invoices SET supplier_invoice_id=%s WHERE id=%s", (linked_supplier_invoice_id, warehouse_invoice_id))
            cur.execute("UPDATE supplier_invoices SET warehouse_invoice_id=%s WHERE id=%s", (warehouse_invoice_id, linked_supplier_invoice_id))
        return warehouse_invoice_id
    except Exception as e:
        raise HTTPException(status_code=500, detail="Не удалось создать накладную по поставке: " + str(e))

def _update_supply_flow_status_after_delivery(cur, request_id=None, offer_id=None):
    request_id = int(request_id or 0)
    offer_id = int(offer_id or 0)
    if not request_id:
        return
    cur.execute("""SELECT status, planned_quantity, received_quantity
                   FROM supply_deliveries
                   WHERE request_id=%s
                   ORDER BY id""", (request_id,))
    delivery_rows = _cursor_rows_as_dicts(cur, cur.fetchall())
    if not delivery_rows:
        return
    statuses = [(r.get("status") or "") for r in delivery_rows]
    done_statuses = {"Принято", "Проблема"}
    any_done = any(s in done_statuses for s in statuses)
    all_done = all(s in done_statuses for s in statuses)
    any_problem = any(s == "Проблема" for s in statuses)
    planned_total = sum(max(0.0, _float_or_zero(r.get("planned_quantity"))) for r in delivery_rows)
    received_total = sum(max(0.0, _float_or_zero(r.get("received_quantity"))) for r in delivery_rows)
    request_fully_received = planned_total <= 0 or received_total + 0.000001 >= planned_total
    if all_done and request_fully_received:
        request_status = "Проблема поставки" if any_problem else "Поставлено"
    elif any_done:
        request_status = "Проблема поставки" if any_problem else "Частично поставлено"
    else:
        request_status = "В пути"
    cur.execute("UPDATE supply_requests SET status=%s WHERE id=%s", (request_status, request_id))

    if offer_id:
        cur.execute("""SELECT status, planned_quantity, received_quantity
                       FROM supply_deliveries
                       WHERE offer_id=%s
                       ORDER BY id""", (offer_id,))
        offer_rows = _cursor_rows_as_dicts(cur, cur.fetchall())
        if offer_rows:
            offer_statuses = [(r.get("status") or "") for r in offer_rows]
            offer_all_done = all(s in done_statuses for s in offer_statuses)
            offer_any_done = any(s in done_statuses for s in offer_statuses)
            offer_any_problem = any(s == "Проблема" for s in offer_statuses)
            offer_planned_total = sum(max(0.0, _float_or_zero(r.get("planned_quantity"))) for r in offer_rows)
            offer_received_total = sum(max(0.0, _float_or_zero(r.get("received_quantity"))) for r in offer_rows)
            offer_fully_received = offer_planned_total <= 0 or offer_received_total + 0.000001 >= offer_planned_total
            if offer_all_done and offer_fully_received:
                offer_status = "Проблема поставки" if offer_any_problem else "Поставлено"
            elif offer_any_done:
                offer_status = "Проблема поставки" if offer_any_problem else "Частично поставлено"
            else:
                offer_status = "В пути"
            cur.execute("UPDATE supplier_offers SET delivery_status=%s WHERE id=%s", (offer_status, offer_id))

def _ensure_cable_journal_row(cur, *, project, cable_brand, qty, supplier="", received_at=None, delivery_id=None, invoice_id=None):
    cable_info = _detect_cable_info(cable_brand)
    if not cable_info["isCable"]:
        return False
    exists = False
    if delivery_id:
        try:
            cur.execute("SELECT id FROM cable_journal WHERE delivery_id=%s LIMIT 1", (delivery_id,))
            exists = bool(cur.fetchone())
        except Exception as e:
            print("CABLE BACKFILL DELIVERY CHECK ERROR:", str(e))
    if not exists and invoice_id:
        try:
            cur.execute("SELECT id FROM cable_journal WHERE invoice_id=%s AND cable_brand=%s LIMIT 1", (invoice_id, cable_brand))
            exists = bool(cur.fetchone())
        except Exception as e:
            print("CABLE BACKFILL INVOICE CHECK ERROR:", str(e))
    if not exists:
        try:
            cur.execute("""SELECT id FROM cable_journal
                           WHERE project_name=%s AND cable_brand=%s AND COALESCE(length_received,0)=%s
                           LIMIT 1""", (project or "", cable_brand or "", _float_or_zero(qty)))
            exists = bool(cur.fetchone())
        except Exception as e:
            print("CABLE BACKFILL LEGACY CHECK ERROR:", str(e))
    if exists:
        return False
    try:
        cur.execute("""INSERT INTO cable_journal
                       (project_name, delivery_id, invoice_id, cable_brand, cable_type, cross_section, cores_count,
                        length_received, supplier, received_at)
                       VALUES (%s,%s,%s,%s,%s,%s,%s,%s,%s,%s)""",
                    (project or "", delivery_id, invoice_id, cable_brand or "", cable_info["cableType"],
                     cable_info["section"], cable_info["cores"], _float_or_zero(qty), supplier or "", received_at))
        return True
    except Exception as e:
        print("CABLE BACKFILL INSERT ERROR:", str(e))
        try:
            cur.execute("""INSERT INTO cable_journal
                           (project_name, cable_brand, cross_section, cores_count,
                            length_received, supplier, received_at)
                           VALUES (%s,%s,%s,%s,%s,%s,%s)""",
                        (project or "", cable_brand or "", cable_info["section"], cable_info["cores"],
                         _float_or_zero(qty), supplier or "", received_at))
            return True
        except Exception as legacy_error:
            print("CABLE BACKFILL LEGACY INSERT ERROR:", str(legacy_error))
    return False

def _backfill_cable_journal(cur, project_names=None):
    import json as _json
    repaired = 0
    project_names = list(project_names or [])
    delivery_where = "WHERE COALESCE(received_quantity,0)>0 AND status IN ('Принято','Проблема')"
    delivery_params = []
    if project_names:
        delivery_where += " AND project = ANY(%s)"
        delivery_params.append(project_names)
    cur.execute("""SELECT id, project, material_name, received_quantity, supplier_name, received_at
                   FROM supply_deliveries """ + delivery_where, delivery_params)
    for d in cur.fetchall():
        delivery_id, project, name, qty, supplier, received_at = d
        if _ensure_cable_journal_row(cur, project=project, cable_brand=name, qty=qty,
                                     supplier=supplier, received_at=received_at, delivery_id=delivery_id):
            repaired += 1
    invoice_where = ""
    invoice_params = []
    if project_names:
        invoice_where = " WHERE project = ANY(%s) OR location = ANY(%s)"
        invoice_params = [project_names, project_names]
    cur.execute("SELECT id, project, location, supplier_name, date, items FROM warehouse_invoices" + invoice_where, invoice_params)
    for inv in cur.fetchall():
        invoice_id, project, location, supplier, date_value, items_json = inv
        target_project = project or (location if location and location != "Основной склад" else "")
        if project_names and target_project not in project_names:
            continue
        items = _json_list_or_empty(items_json)
        for item in items:
            if not isinstance(item, dict):
                continue
            name = (item.get("name") or item.get("materialName") or "").strip()
            qty = _float_or_zero(item.get("quantity"))
            if _ensure_cable_journal_row(cur, project=target_project, cable_brand=name, qty=qty,
                                         supplier=supplier, received_at=date_value, invoice_id=invoice_id):
                repaired += 1
    material_where = "WHERE COALESCE(quantity,0)>0"
    material_params = []
    if project_names:
        material_where += " AND project = ANY(%s)"
        material_params.append(project_names)
    cur.execute("SELECT name, quantity, project FROM materials " + material_where, material_params)
    for material in cur.fetchall():
        name, qty, project = material
        if _ensure_cable_journal_row(cur, project=project, cable_brand=name, qty=qty):
            repaired += 1
    return repaired

@app.get("/supply-deliveries")
def list_supply_deliveries(limit: Optional[int] = None, offset: int = 0, current_user: dict = Depends(get_current_user)):
    conn = get_db()
    cur = conn.cursor(cursor_factory=psycopg2.extras.RealDictCursor)
    role = current_user.get("role")
    page_sql, page_params = limit_offset_sql(limit, offset)
    if can_see_all_company_data(current_user):
        cur.execute(DELIVERY_SELECT + " ORDER BY d.id DESC" + page_sql, page_params)
    elif role in ("снабженец", "кладовщик"):
        project_sql, project_params = scoped_project_where(current_user, "d.project")
        cur.execute(DELIVERY_SELECT + project_sql + " ORDER BY d.id DESC" + page_sql, project_params + page_params)
    elif role == "поставщик":
        supplier_id = current_supplier_id(cur, current_user)
        if not supplier_id:
            cur.close(); conn.close()
            return []
        cur.execute(DELIVERY_SELECT + " WHERE d.supplier_id=%s ORDER BY d.id DESC" + page_sql, [supplier_id] + page_params)
    elif role == "прораб":
        projects = user_project_names(current_user)
        if not projects:
            cur.close(); conn.close()
            return []
        package_sql, package_params = package_access_filter(current_user, "d.work_package")
        cur.execute(DELIVERY_SELECT + " WHERE d.project = ANY(%s)" + package_sql + " ORDER BY d.id DESC" + page_sql, [projects] + package_params + page_params)
    elif role in WORKER_EXECUTION_ROLES:
        cur.close(); conn.close()
        return []
    else:
        cur.close(); conn.close()
        return []
    rows = cur.fetchall()
    cur.close(); conn.close()
    return [dict(r) for r in rows]

@app.get("/supply-claims")
def list_supply_claims(current_user: dict = Depends(get_current_user)):
    conn = get_db()
    cur = conn.cursor(cursor_factory=psycopg2.extras.RealDictCursor)
    role = current_user.get("role")
    if role in ("директор", "зам_директора", "снабженец", "кладовщик", "бухгалтер"):
        cur.execute(CLAIM_SELECT + " ORDER BY id DESC")
    elif role == "поставщик":
        supplier_id = current_supplier_id(cur, current_user)
        if not supplier_id:
            cur.close(); conn.close()
            return []
        cur.execute(CLAIM_SELECT + " WHERE supplier_id=%s ORDER BY id DESC", (supplier_id,))
    elif role == "прораб":
        projects = user_project_names(current_user)
        if not projects:
            cur.close(); conn.close()
            return []
        package_sql, package_params = package_access_filter(current_user, "work_package")
        cur.execute(CLAIM_SELECT + " WHERE project = ANY(%s)" + package_sql + " ORDER BY id DESC",
                    [projects] + package_params)
    elif role in WORKER_EXECUTION_ROLES:
        package_sql, package_params = package_access_filter(current_user, "work_package")
        cur.execute(CLAIM_SELECT + " WHERE request_id IN (SELECT id FROM supply_requests WHERE requested_by_id=%s OR created_by=%s)" + package_sql + " ORDER BY id DESC",
                    [current_user.get("id"), current_user.get("name") or ""] + package_params)
    else:
        cur.close(); conn.close()
        return []
    rows = cur.fetchall()
    cur.close(); conn.close()
    return [dict(r) for r in rows]

@app.post("/supplier-offers/{id}/ship")
def ship_supplier_offer(id: int, data: dict, _current_user: dict = Depends(require_roles(*SUPPLY_ROLES))):
    from datetime import datetime
    conn = get_db()
    cur = conn.cursor(cursor_factory=psycopg2.extras.RealDictCursor)
    cur.execute("""
        SELECT o.id, o.request_id, o.supplier_id, o.price_per_unit, o.total_price,
               o.payment_terms, o.items_kp_json, s.name as supplier_name,
               r.project, COALESCE(r.work_package,'') as work_package,
               r.material_name, r.quantity, r.unit, r.items_json
        FROM supplier_offers o
        LEFT JOIN suppliers s ON s.id=o.supplier_id
        LEFT JOIN supply_requests r ON r.id=o.request_id
        WHERE o.id=%s AND o.status=%s
    """, (id, 'Утверждено'))
    offer = cur.fetchone()
    if not offer:
        cur.close(); conn.close()
        raise HTTPException(status_code=404, detail="Утверждённое КП не найдено")
    role = _current_user.get("role")
    if role == "поставщик":
        supplier_id = current_supplier_id(cur, _current_user)
        if not supplier_id or supplier_id != offer.get('supplier_id'):
            cur.close(); conn.close()
            raise HTTPException(status_code=403, detail="Нет доступа к КП")
    else:
        if role not in SUPPLY_INTERNAL_ROLES:
            cur.close(); conn.close()
            raise HTTPException(status_code=403, detail="Недостаточно прав для отгрузки")
        if offer.get('project'):
            require_project_or_warehouse_access(_current_user, offer.get('project') or "")
    cur.execute("SELECT id, status, paid_amount, amount FROM supplier_invoices WHERE offer_id=%s ORDER BY id DESC LIMIT 1", (id,))
    inv = cur.fetchone()
    terms = (offer.get('payment_terms') or '').lower()
    need_payment = ('предоплат' in terms) or ('50/50' in terms) or ('50' in terms and 'постоплат' not in terms)
    if need_payment:
        paid = _float_or_zero(inv['paid_amount']) if inv else 0
        amount = _float_or_zero(inv['amount']) if inv else _float_or_zero(offer['total_price'])
        required = amount if '100' in terms or 'предоплат' in terms else amount * 0.5
        if not inv:
            cur.close(); conn.close()
            raise HTTPException(status_code=400, detail="Сначала поставщик должен выставить счёт, а бухгалтерия — оплатить по условиям КП")
        if paid + 0.01 < required:
            cur.close(); conn.close()
            raise HTTPException(status_code=400, detail=f"По условиям «{offer.get('payment_terms') or ''}» перед отгрузкой нужно оплатить минимум {round(required, 2)} ₽. Сейчас оплачено {round(paid, 2)} ₽")
    def _line_key(item):
        if not isinstance(item, dict):
            return ("", "", "")
        return (
            str(item.get("materialName") or item.get("name") or "").strip().lower(),
            str(item.get("unit") or "").strip().lower(),
            _supply_work_package(item.get("workPackage") or item.get("work_package")).lower(),
        )

    request_items = []
    for item in _json_list_or_empty(offer.get("items_json")):
        if not isinstance(item, dict):
            continue
        name = (item.get("materialName") or item.get("name") or "").strip()
        qty = _float_or_zero(item.get("quantity"))
        if name and qty > 0:
            request_items.append({
                "materialName": name,
                "quantity": qty,
                "unit": item.get("unit") or offer.get("unit") or "шт",
                "workPackage": _supply_work_package(item.get("workPackage") or item.get("work_package") or offer.get("work_package")),
            })
    if not request_items:
        request_items = [{
            "materialName": offer.get("material_name") or "",
            "quantity": _float_or_zero(offer.get("quantity")),
            "unit": offer.get("unit") or "шт",
            "workPackage": _supply_work_package(offer.get("work_package")),
        }]

    kp_by_key = {}
    for item in _json_list_or_empty(offer.get("items_kp_json")):
        if isinstance(item, dict):
            kp_by_key[_line_key(item)] = item

    shipped_by_key = {}
    for item in _json_list_or_empty(data.get("shippedItems")):
        if isinstance(item, dict):
            shipped_by_key[_line_key(item)] = _float_or_zero(item.get("shippedQuantity") or item.get("quantity"))

    has_item_kp = bool(kp_by_key)
    fallback_total = _float_or_zero(offer.get("total_price"))
    fallback_line_total = fallback_total / len(request_items) if request_items and fallback_total > 0 else 0

    cur.execute("SELECT id, status FROM supply_deliveries WHERE offer_id=%s", (id,))
    existing_rows = cur.fetchall()
    if any((r.get('status') if isinstance(r, dict) else r[1]) in ('Принято', 'Проблема') for r in existing_rows):
        cur.close(); conn.close()
        raise HTTPException(status_code=400, detail="Поставка уже принята. Повторная отгрузка запрещена — создайте новую заявку/КП для допоставки.")
    if existing_rows:
        cur.execute("DELETE FROM supply_deliveries WHERE offer_id=%s", (id,))

    delivery_ids = []
    single_request = len(request_items) == 1
    for item in request_items:
        key = _line_key(item)
        kp = kp_by_key.get(key) or {}
        planned_qty = _float_or_zero(item.get("quantity"))
        shipped_qty = shipped_by_key.get(key)
        if shipped_qty is None:
            shipped_qty = _float_or_zero(data.get('shippedQuantity')) if single_request and data.get('shippedQuantity') not in (None, "") else planned_qty
        if shipped_qty <= 0:
            cur.close(); conn.close()
            raise HTTPException(status_code=400, detail="Количество к отгрузке должно быть больше нуля")
        if planned_qty > 0 and shipped_qty > planned_qty + 0.000001:
            cur.close(); conn.close()
            raise HTTPException(
                status_code=400,
                detail=f"Нельзя отгрузить больше заявки: {item.get('materialName') or ''} — заявлено {planned_qty:g}, отгружается {shipped_qty:g}",
            )
        price_per_unit = _float_or_zero(kp.get("pricePerUnit")) if has_item_kp else 0
        line_total = _float_or_zero(kp.get("totalPrice")) if has_item_kp else 0
        if line_total <= 0 and price_per_unit > 0:
            line_total = round(price_per_unit * planned_qty, 2)
        if line_total <= 0:
            line_total = fallback_line_total if not single_request else fallback_total
        if price_per_unit <= 0 and planned_qty > 0 and line_total > 0:
            price_per_unit = round(line_total / planned_qty, 6)
        shipped_line_total = round(price_per_unit * shipped_qty, 2) if price_per_unit > 0 else line_total
        vals = (
            offer['request_id'], offer['supplier_id'], offer['supplier_name'] or '',
            offer['project'] or '', _supply_work_package(item.get("workPackage") or offer.get('work_package')),
            item.get("materialName") or '',
            planned_qty, shipped_qty, item.get("unit") or offer.get("unit") or '',
            price_per_unit, shipped_line_total,
            data.get('waybillNumber') or '', data.get('waybillDate') or None,
            data.get('vehicleNumber') or '', data.get('driverName') or '',
            data.get('documentUrl') or '', data.get('photoUrl') or '', datetime.now()
        )
        cur.execute("""INSERT INTO supply_deliveries
                       (offer_id, request_id, supplier_id, supplier_name, project,
                        work_package, material_name, planned_quantity, shipped_quantity, unit,
                        price_per_unit, total_price, waybill_number, waybill_date,
                        vehicle_number, driver_name, document_url, photo_url, shipped_at, status)
                       VALUES (%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s)
                       RETURNING id""",
                    (id,) + vals + ('В пути',))
        delivery_ids.append(cur.fetchone()['id'])
    cur.execute("UPDATE supplier_offers SET delivery_status=%s WHERE id=%s", ('В пути', id))
    cur.execute("UPDATE supply_requests SET status=%s WHERE id=%s", ('В пути', offer['request_id']))
    cur.execute(DELIVERY_SELECT + " WHERE d.offer_id=%s ORDER BY d.id", (id,))
    rows = [dict(r) for r in cur.fetchall()]
    row = rows[0] if rows else None
    conn.commit()
    cur.close(); conn.close()
    if len(rows) == 1:
        return row
    return {"ok": True, "count": len(rows), "deliveries": rows}

@app.put("/supply-deliveries/{id}/receive")
def receive_supply_delivery(id: int, data: dict, _current_user: dict = Depends(require_roles(*WAREHOUSE_ROLES))):
    from datetime import datetime
    conn = get_db()
    conn.autocommit = False
    cur = conn.cursor(cursor_factory=psycopg2.extras.RealDictCursor)
    cur.execute("SELECT * FROM supply_deliveries WHERE id=%s FOR UPDATE", (id,))
    delivery = cur.fetchone()
    if not delivery:
        conn.rollback()
        cur.close(); conn.close()
        raise HTTPException(status_code=404, detail="Поставка не найдена")
    if delivery.get('project'):
        try:
            require_project_or_warehouse_access(_current_user, delivery.get('project') or "")
        except Exception:
            conn.rollback()
            cur.close(); conn.close()
            raise
    if _current_user.get("role") in PACKAGE_LIMIT_ROLES and not has_package_access(_current_user, delivery.get("work_package") or "Основная"):
        conn.rollback()
        cur.close(); conn.close()
        raise HTTPException(status_code=403, detail="Нет доступа к пакету поставки")
    if delivery['status'] in ('Принято', 'Проблема') or delivery.get('received_at'):
        try:
            _create_delivery_quality_records(cur, delivery)
        except Exception as e:
            print("DELIVERY QUALITY RECOVERY ERROR:", str(e))
        try:
            _create_supply_delivery_history(cur, delivery)
        except Exception as e:
            print("DELIVERY HISTORY RECOVERY ERROR:", str(e))
        try:
            invoice_id = _ensure_supply_delivery_invoice(
                cur, delivery,
                delivery.get('received_quantity'),
                delivery.get('received_at'),
                delivery.get('received_by') or ''
            )
        except Exception as e:
            print("DELIVERY INVOICE RECOVERY ERROR:", str(e))
            invoice_id = None
        try:
            cur.execute(DELIVERY_SELECT + " WHERE d.id=%s", (id,))
            row = cur.fetchone()
        except Exception as e:
            print("DELIVERY RECOVERY SELECT ERROR:", str(e))
            row = None
        conn.commit()
        cur.close(); conn.close()
        return {
            "ok": True,
            "delivery": dict(row) if row else {"id": id},
            "claimId": delivery.get('claim_id'),
            "invoiceId": invoice_id,
            "alreadyReceived": True
        }
    received_qty = _float_or_zero(data.get('receivedQuantity'))
    planned_qty = _float_or_zero(delivery['planned_quantity'])
    shipped_qty = _float_or_zero(delivery['shipped_quantity']) or planned_qty
    quality_status = data.get('qualityStatus') or 'Принято'
    if received_qty < 0:
        conn.rollback()
        cur.close(); conn.close()
        raise HTTPException(status_code=400, detail="Принятое количество не может быть отрицательным")
    if shipped_qty > 0 and received_qty > shipped_qty + 0.000001:
        conn.rollback()
        cur.close(); conn.close()
        raise HTTPException(
            status_code=400,
            detail=f"Нельзя принять больше отгруженного: отгружено {shipped_qty:g} {delivery['unit']}, принимается {received_qty:g} {delivery['unit']}",
        )
    shortage = max(0.0, shipped_qty - received_qty)
    problem = shortage > 0 or quality_status in ('Брак', 'Несоответствие', 'Недостача', 'Частично')
    status = 'Проблема' if problem else 'Принято'
    received_at = datetime.now()
    cur.execute("""UPDATE supply_deliveries SET received_quantity=%s, received_at=%s,
                   received_by=%s, quality_status=%s, quality_notes=%s,
                   shortage_quantity=%s, photo_url=COALESCE(NULLIF(%s,''), photo_url),
                   status=%s WHERE id=%s""",
                (received_qty, received_at, data.get('receivedBy') or '',
                 quality_status, data.get('qualityNotes') or '',
                 shortage, data.get('photoUrl') or '', status, id))
    claim_id = None
    cur.execute("SELECT * FROM supply_deliveries WHERE id=%s", (id,))
    updated = cur.fetchone()
    _create_delivery_quality_records(cur, updated)
    if problem:
        claim_type = 'Недостача' if shortage > 0 else quality_status
        description = data.get('claimDescription') or (
            f"По поставке «{delivery['material_name']}» ожидалось {shipped_qty:g} {delivery['unit']}, "
            f"принято {received_qty:g} {delivery['unit']}. "
            f"Статус качества: {quality_status}. {data.get('qualityNotes') or ''}"
        )
        cur.execute("""INSERT INTO supply_claims
                       (delivery_id, request_id, offer_id, supplier_id, project, material_name,
                        work_package, claim_type, description, expected_quantity, received_quantity,
                        shortage_quantity, photo_url, created_by)
                       VALUES (%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s) RETURNING id""",
                    (id, delivery['request_id'], delivery['offer_id'], delivery['supplier_id'],
                     delivery['project'], delivery['material_name'], delivery.get('work_package') or delivery.get('workPackage') or '',
                     claim_type, description,
                     shipped_qty, received_qty, shortage, data.get('photoUrl') or '',
                     data.get('receivedBy') or ''))
        claim_id = cur.fetchone()['id']
        cur.execute("UPDATE supply_deliveries SET claim_id=%s WHERE id=%s", (claim_id, id))
    _create_supply_delivery_history(cur, updated, status, received_qty, data.get('receivedBy') or '')
    invoice_id = _ensure_supply_delivery_invoice(cur, updated, received_qty, received_at, data.get('receivedBy') or '')
    if received_qty > 0 and quality_status not in ('Брак',):
        _add_project_material(cur, delivery['material_name'], delivery['unit'], received_qty,
                              _float_or_zero(delivery['price_per_unit']), delivery['project'],
                              delivery.get('work_package') or delivery.get('workPackage') or "")
    _update_supply_flow_status_after_delivery(cur, delivery['request_id'], delivery['offer_id'])
    cur.execute(DELIVERY_SELECT + " WHERE d.id=%s", (id,))
    row = cur.fetchone()
    conn.commit()
    cur.close(); conn.close()
    _run_project_ai_control_safely(delivery['project'], "supply_delivery:receive")
    return {"ok": True, "delivery": dict(row), "claimId": claim_id, "invoiceId": invoice_id}

@app.post("/supply-deliveries/{id}/ai-check")
def ai_check_supply_delivery(id: int, data: dict, _current_user: dict = Depends(require_roles(*WAREHOUSE_ROLES))):
    conn = get_db()
    cur = conn.cursor(cursor_factory=psycopg2.extras.RealDictCursor)
    cur.execute("SELECT * FROM supply_deliveries WHERE id=%s", (id,))
    d = cur.fetchone()
    if not d:
        cur.close(); conn.close()
        raise HTTPException(status_code=404, detail="Поставка не найдена")
    if d.get("project"):
        require_project_or_warehouse_access(_current_user, d.get("project") or "")
    if _current_user.get("role") in PACKAGE_LIMIT_ROLES and not has_package_access(_current_user, d.get("work_package") or "Основная"):
        cur.close(); conn.close()
        raise HTTPException(status_code=403, detail="Нет доступа к пакету поставки")
    parsed_items = data.get('parsedItems') or []
    doc_text = data.get('documentText') or ''
    expected = {
        "material": d['material_name'],
        "quantity": _float_or_zero(d['planned_quantity']),
        "unit": d['unit'] or '',
        "supplier": d['supplier_name'] or '',
        "project": d['project'] or '',
    }
    result_text = ""
    try:
        if parsed_items:
            best = None
            exp_name = (expected['material'] or '').lower()
            for it in parsed_items:
                nm = (it.get('name') or it.get('materialName') or '').lower()
                if nm and (nm in exp_name or exp_name in nm or any(w in nm for w in exp_name.split()[:2])):
                    best = it
                    break
            if best:
                qty = _float_or_zero(best.get('quantity'))
                diff = expected['quantity'] - qty
                result_text = (
                    f"В документе найдена похожая позиция: {best.get('name') or best.get('materialName')} "
                    f"{qty:g} {best.get('unit') or expected['unit']}. "
                    + ("Количество совпадает." if abs(diff) < 0.0001 else f"Расхождение: {diff:g} {expected['unit']}.")
                )
            else:
                result_text = "В распознанном документе не нашёл позицию, похожую на заявку. Проверьте накладную вручную."
        elif doc_text:
            import openai as oa
            prompt = (
                "Сверь поставку с текстом накладной. Ожидалось: "
                f"{expected['material']} — {expected['quantity']} {expected['unit']}, "
                f"поставщик {expected['supplier']}, объект {expected['project']}.\n"
                "Текст/заметки документа:\n" + doc_text[:4000] +
                "\nОтветь коротко: совпадает ли материал и количество, есть ли риск недопоставки или пересорта."
            )
            client = oa.OpenAI(api_key=YANDEX_API_KEY, base_url="https://ai.api.cloud.yandex.net/v1", project=YANDEX_FOLDER_ID)
            r = client.responses.create(
                model="gpt://"+YANDEX_FOLDER_ID+"/yandexgpt-5.1/latest",
                temperature=0.1,
                instructions="Ты помощник кладовщика на стройке. Проверяешь накладную перед приёмкой.",
                input=prompt,
                max_output_tokens=500,
            )
            result_text = (r.output_text or '').strip()
        else:
            result_text = "Загрузите фото накладной или вставьте текст/позиции документа для AI-сверки."
    except Exception as e:
        print("DELIVERY AI CHECK ERROR:", e)
        result_text = "AI-сверка не сработала, проверьте поставку вручную."
    cur.execute("UPDATE supply_deliveries SET ai_check_result=%s WHERE id=%s", (result_text, id))
    cur.close(); conn.close()
    return {"ok": True, "result": result_text, "expected": expected}

@app.put("/supply-claims/{id}")
def update_supply_claim(id: int, data: dict, _current_user: dict = Depends(require_roles(*SUPPLY_ROLES))):
    conn = get_db()
    cur = conn.cursor(cursor_factory=psycopg2.extras.RealDictCursor)
    cur.execute("SELECT id, supplier_id, project, COALESCE(work_package,'') as work_package FROM supply_claims WHERE id=%s", (id,))
    claim = cur.fetchone()
    if not claim:
        cur.close(); conn.close()
        raise HTTPException(status_code=404, detail="Претензия не найдена")
    role = _current_user.get("role")
    if role == "поставщик":
        supplier_id = current_supplier_id(cur, _current_user)
        if not supplier_id or supplier_id != claim.get("supplier_id"):
            cur.close(); conn.close()
            raise HTTPException(status_code=403, detail="Нет доступа к претензии")
        protected_keys = {"status", "resolvedAt"}
        if protected_keys.intersection(data.keys()):
            cur.close(); conn.close()
            raise HTTPException(status_code=403, detail="Закрытие претензии доступно только внутренним ролям")
    else:
        if role not in SUPPLY_INTERNAL_ROLES:
            cur.close(); conn.close()
            raise HTTPException(status_code=403, detail="Недостаточно прав для изменения претензии")
        if claim.get("project"):
            require_project_or_warehouse_access(_current_user, claim.get("project") or "")
        if role in PACKAGE_LIMIT_ROLES and not has_package_access(_current_user, claim.get("work_package") or "Основная"):
            cur.close(); conn.close()
            raise HTTPException(status_code=403, detail="Нет доступа к разделу сметы претензии")
    fields_map = [('status','status'),('resolution','resolution'),('resolvedAt','resolved_at')]
    sets, vals = [], []
    for js_key, db_col in fields_map:
        if js_key in data:
            sets.append(db_col + "=%s")
            vals.append(data[js_key] or None if js_key == 'resolvedAt' else data[js_key])
    if data.get('status') in ('Закрыта', 'Решена') and 'resolvedAt' not in data:
        sets.append("resolved_at=NOW()")
    if not sets:
        cur.close(); conn.close()
        return {"ok": True}
    vals.append(id)
    cur.execute("UPDATE supply_claims SET " + ", ".join(sets) + " WHERE id=%s", vals)
    cur.close(); conn.close()
    return {"ok": True}

@app.get("/supply-history")
def get_supply_history(limit: Optional[int] = None, offset: int = 0, current_user: dict = Depends(get_current_user)):
    conn = get_db()
    cur = conn.cursor(cursor_factory=psycopg2.extras.RealDictCursor)
    _ensure_supply_runtime_columns(cur)
    conn.commit()
    role = current_user.get("role")
    page_sql, page_params = limit_offset_sql(limit, offset)
    select_sql = ("SELECT id,supplier_id as \"supplierId\",material_name as \"materialName\",quantity,unit,"
                  "price_per_unit as \"pricePerUnit\",total_price as \"totalPrice\",project,date,status,"
                  "confirmed_by as \"confirmedBy\",COALESCE(work_package,'') as \"workPackage\" "
                  "FROM supply_history")
    if can_see_all_company_data(current_user):
        cur.execute(select_sql + " ORDER BY id DESC" + page_sql, page_params)
    elif role in ("снабженец", "кладовщик"):
        project_sql, project_params = scoped_project_where(current_user, "project")
        cur.execute(select_sql + project_sql + " ORDER BY id DESC" + page_sql, project_params + page_params)
    elif role == "поставщик":
        supplier_id = current_supplier_id(cur, current_user)
        if not supplier_id:
            cur.close(); conn.close()
            return []
        cur.execute(select_sql + " WHERE supplier_id=%s ORDER BY id DESC" + page_sql, [supplier_id] + page_params)
    elif role == "прораб":
        projects = user_project_names(current_user)
        if not projects:
            cur.close(); conn.close()
            return []
        package_sql, package_params = package_access_filter(current_user)
        cur.execute(select_sql + " WHERE project = ANY(%s)" + package_sql + " ORDER BY id DESC" + page_sql, [projects] + package_params + page_params)
    elif role in WORKER_EXECUTION_ROLES:
        cur.close(); conn.close()
        return []
    else:
        cur.close(); conn.close()
        return []
    rows = cur.fetchall()
    conn.close()
    return [dict(r) for r in rows]

@app.post("/supply-history")
def create_supply_history(d: SupplyHistoryModel, _current_user: dict = Depends(require_roles("директор", "зам_директора", "снабженец", "кладовщик"))):
    conn = get_db()
    cur = conn.cursor(cursor_factory=psycopg2.extras.RealDictCursor)
    _ensure_supply_runtime_columns(cur)
    conn.commit()
    if d.project:
        require_project_or_warehouse_access(_current_user, d.project)
    if not has_package_access(_current_user, d.workPackage or ""):
        cur.close(); conn.close()
        raise HTTPException(status_code=403, detail="Нет доступа к этому пакету работ")
    cur.execute("""INSERT INTO supply_history
                   (supplier_id,material_name,quantity,unit,price_per_unit,total_price,project,date,status,work_package)
                   VALUES (%s,%s,%s,%s,%s,%s,%s,%s,%s,%s) RETURNING *""",
                (d.supplierId,d.materialName,d.quantity,d.unit,d.pricePerUnit,d.totalPrice,d.project,d.date,d.status,d.workPackage or ""))
    row = cur.fetchone()
    conn.commit()
    conn.close()
    return dict(row)

@app.put("/supply-history/{id}")
def update_supply_history(id: int, data: dict, _current_user: dict = Depends(require_roles("директор", "зам_директора", "снабженец", "кладовщик"))):
    conn = get_db()
    cur = conn.cursor(cursor_factory=psycopg2.extras.RealDictCursor)
    _ensure_supply_runtime_columns(cur)
    conn.commit()
    cur.execute("SELECT project, COALESCE(NULLIF(work_package,''),'Основная') AS work_package FROM supply_history WHERE id=%s", (id,))
    row = cur.fetchone()
    if not row:
        cur.close(); conn.close()
        raise HTTPException(status_code=404, detail="Запись истории поставок не найдена")
    if row.get("project"):
        require_project_or_warehouse_access(_current_user, row.get("project") or "")
    if not has_package_access(_current_user, row.get("work_package") or "Основная"):
        cur.close(); conn.close()
        raise HTTPException(status_code=403, detail="Нет доступа к пакету поставки")
    status = data.get('status','')
    confirmed_by = data.get('confirmedBy','')
    cur.execute("UPDATE supply_history SET status=%s,confirmed_by=%s WHERE id=%s", (status,confirmed_by,id))
    conn.commit()
    conn.close()
    return {"ok": True}

@app.get("/work-journal")
def get_work_journal(
    limit: Optional[int] = None,
    offset: int = 0,
    project_name: str = "",
    search: str = "",
    date_from: str = "",
    date_to: str = "",
    current_user: dict = Depends(get_current_user),
):
    conn = get_db()
    cur = conn.cursor(cursor_factory=psycopg2.extras.RealDictCursor)
    select_sql = """SELECT id,master_id as "masterId",master_name as "masterName",project,description,unit,quantity,
                          price_per_unit as "pricePerUnit",total,date,status,comment,
                          customer_price_per_unit as "customerPricePerUnit",
                          customer_total as "customerTotal",
                          execution_price_per_unit as "executionPricePerUnit",
                          execution_total as "executionTotal",
                          execution_price_mode as "executionPriceMode",
                          photo_url as "photoUrl",confirmed_by as "confirmedBy",confirmed_at as "confirmedAt",
                          materials_used as "materialsUsed",
                          estimate_id as "estimateId", section_name as "sectionName",
                          responsible_itr as "responsibleItr", weather,
                          time_start as "timeStart", time_end as "timeEnd",
                          hidden_work as "hiddenWork", quality_status as "qualityStatus",
                          normatives, project_docs as "projectDocs",
                          ai_filled as "aiFilled",
                          unexpected_work_id as "unexpectedWorkId",
                          work_package as "workPackage",
                          room_id as "roomId",
                          room_name as "roomName",
                          surface,
                          estimate_item_name as "estimateItemName",
                          estimate_item_key as "estimateItemKey"
                   FROM work_journal"""
    role = current_user.get("role")
    page_sql, page_params = limit_offset_sql(limit, offset)
    package_names = user_package_names(current_user) if role in PACKAGE_LIMIT_ROLES and role != "прораб" else []
    scoped_journal_roles = ("прораб", "стройконтроль", "технадзор")
    project_filter = (project_name or "").strip()
    search_filter = (search or "").strip()
    if project_filter:
        require_project_access(current_user, project_filter)

    def add_runtime_filters(conditions, params):
        if project_filter:
            conditions.append("project=%s")
            params.append(project_filter)
        if search_filter:
            conditions.append("""(
                COALESCE(description, '') ILIKE %s OR
                COALESCE(master_name, '') ILIKE %s OR
                COALESCE(project, '') ILIKE %s OR
                COALESCE(comment, '') ILIKE %s OR
                COALESCE(room_name, '') ILIKE %s OR
                COALESCE(section_name, '') ILIKE %s OR
                COALESCE(work_package, '') ILIKE %s OR
                COALESCE(status, '') ILIKE %s
            )""")
            params.extend([f"%{search_filter}%"] * 8)
        if date_from:
            conditions.append("date >= %s")
            params.append(date_from)
        if date_to:
            conditions.append("date <= %s")
            params.append(date_to)

    if role in PACKAGE_LIMIT_ROLES and role != "прораб" and not package_names:
        cur.close(); conn.close()
        return []
    if can_see_all_company_data(current_user) or role in scoped_journal_roles:
        projects = user_project_names(current_user)
        conditions = []
        params = []
        if role in scoped_journal_roles and not projects:
            cur.close(); conn.close()
            return []
        if role in scoped_journal_roles and projects:
            conditions.append("project = ANY(%s)")
            params.append(projects)
        if role in PACKAGE_LIMIT_ROLES and package_names:
            conditions.append("COALESCE(NULLIF(work_package,''),'Основная') = ANY(%s)")
            params.append(package_names)
        add_runtime_filters(conditions, params)
        if conditions:
            cur.execute(select_sql + " WHERE " + " AND ".join(conditions) + " ORDER BY id DESC" + page_sql, params + page_params)
        else:
            cur.execute(select_sql + " ORDER BY id DESC" + page_sql, page_params)
    elif role in WORKER_EXECUTION_ROLES:
        if not package_names:
            cur.close(); conn.close()
            return []
        conditions = ["(COALESCE(master_id,0)=%s OR (COALESCE(master_id,0)=0 AND LOWER(TRIM(master_name))=LOWER(TRIM(%s))))"]
        params = [current_user.get("id"), current_user.get("name") or ""]
        conditions.append("COALESCE(NULLIF(work_package,''),'Основная') = ANY(%s)")
        params.append(package_names)
        add_runtime_filters(conditions, params)
        cur.execute(select_sql + " WHERE " + " AND ".join(conditions) + " ORDER BY id DESC" + page_sql, params + page_params)
    elif role == "заказчик":
        projects = user_project_names(current_user)
        if not projects:
            cur.close(); conn.close()
            return []
        conditions = ["project = ANY(%s)", "status='Подтверждено'"]
        params = [projects]
        add_runtime_filters(conditions, params)
        cur.execute(select_sql + " WHERE " + " AND ".join(conditions) + " ORDER BY id DESC" + page_sql, params + page_params)
    else:
        cur.close(); conn.close()
        return []
    rows = cur.fetchall()
    conn.close()
    out = [dict(r) for r in rows]
    if role in ("заказчик", "технадзор", "стройконтроль"):
        for row in out:
            row["pricePerUnit"] = 0
            row["total"] = 0
            row["executionPricePerUnit"] = 0
            row["executionTotal"] = 0
            row["customerPricePerUnit"] = 0
            row["customerTotal"] = 0
    elif role in WORKER_EXECUTION_ROLES:
        for row in out:
            row["customerPricePerUnit"] = 0
            row["customerTotal"] = 0
            row["pricePerUnit"] = row.get("executionPricePerUnit") or 0
            row["total"] = row.get("executionTotal") or 0
    return out

def _parse_materials_used(raw):
    import json as _json
    if not raw:
        return []
    if isinstance(raw, list):
        return raw
    try:
        parsed = _json.loads(raw)
        return parsed if isinstance(parsed, list) else []
    except Exception:
        return []

def _row_value(row, index: int, key: str, default=None):
    if isinstance(row, dict):
        return row.get(key, default)
    try:
        return row[index]
    except Exception:
        return default

def _stock_row_by_material_key(cur, *, project: str, material_name: str, unit: str = "", work_package: str = "", main_warehouse: bool = False):
    target_key = _material_control_key_resolved(cur, project, material_name, unit)
    unit_key = _norm_base_unit(unit or "").strip().lower()
    unit_filter = f" AND {_sql_norm_unit('unit')}=%s" if unit_key else ""
    def _row_matches(row):
        row_name = _row_value(row, 1, "name", "")
        row_unit = _row_value(row, 3, "unit", unit)
        if _material_control_key_resolved(cur, project, row_name, row_unit) == target_key:
            return True
        return _material_units_compatible(unit, row_unit) and _material_name_match_score(material_name, row_name) >= 0.55
    if main_warehouse:
        cur.execute(f"""SELECT id, name, quantity, unit
                        FROM warehouse_main
                        WHERE TRUE {unit_filter}
                        ORDER BY id DESC
                        FOR UPDATE""", tuple([unit_key] if unit_key else []))
        for row in cur.fetchall() or []:
            if _row_matches(row):
                return row
    else:
        package_name = (work_package or "Основная").strip() or "Основная"
        cur.execute(f"""SELECT id, name, quantity, unit
                        FROM materials
                        WHERE project=%s
                          AND COALESCE(NULLIF(work_package,''),'Основная')=%s
                          {unit_filter}
                        ORDER BY id DESC
                        FOR UPDATE""", tuple([project, package_name] + ([unit_key] if unit_key else [])))
        for row in cur.fetchall() or []:
            if _row_matches(row):
                return row
        if package_name != "Основная":
            cur.execute(f"""SELECT id, name, quantity, unit
                            FROM materials
                            WHERE project=%s
                              {unit_filter}
                            ORDER BY CASE WHEN COALESCE(NULLIF(work_package,''),'Основная')='Основная' THEN 0 ELSE 1 END, id DESC
                            FOR UPDATE""", tuple([project] + ([unit_key] if unit_key else [])))
            for row in cur.fetchall() or []:
                if _row_matches(row):
                    return row
    return None

def _personal_material_balance(cur, project: str, person_id, person_name: str, material_name: str, work_package: str = "", unit: str = ""):
    if not (material_name or "").strip():
        return {"issued": 0, "used": 0, "available": 0}
    target_key = _material_control_key_resolved(cur, project, material_name, unit)
    unit_key = _norm_base_unit(unit or "").strip().lower()
    package_name = (work_package or "Основная").strip() or "Основная"
    package_filter = " AND COALESCE(NULLIF(work_package,''),'Основная')=%s"
    unit_filter = f" AND {_sql_norm_unit('unit')}=%s" if unit_key else ""
    if person_id:
        cur.execute("""SELECT material_name, quantity, unit
                       FROM material_transfers
                       WHERE project_name=%s
                         AND (to_user_id=%s OR (to_user_id IS NULL AND LOWER(TRIM(to_person))=LOWER(TRIM(%s))))
                         AND signed=TRUE
                         AND COALESCE(status,'Активна') <> 'Аннулирована'
                         """ + package_filter + unit_filter,
                    tuple([project, person_id, person_name or "", package_name] + ([unit_key] if unit_key else [])))
    else:
        cur.execute("""SELECT material_name, quantity, unit
                       FROM material_transfers
                       WHERE project_name=%s
                         AND LOWER(TRIM(to_person))=LOWER(TRIM(%s))
                         AND signed=TRUE
                         AND COALESCE(status,'Активна') <> 'Аннулирована'
                         """ + package_filter + unit_filter,
                    tuple([project, person_name or "", package_name] + ([unit_key] if unit_key else [])))
    issued = 0
    for row in cur.fetchall() or []:
        row_name = _row_value(row, 0, "material_name", "")
        row_unit = _row_value(row, 2, "unit", unit)
        if _material_control_key_resolved(cur, project, row_name, row_unit) == target_key:
            issued += float(_row_value(row, 1, "quantity", 0) or 0)
    package_journal_filter = " AND COALESCE(NULLIF(work_package,''),'Основная')=%s"
    if person_id:
        cur.execute("""SELECT materials_used FROM work_journal
                       WHERE project=%s
                         AND COALESCE(status,'') NOT IN ('Отклонено','Аннулировано')
                         AND (COALESCE(master_id,0)=%s OR (COALESCE(master_id,0)=0 AND master_name=%s))""" + package_journal_filter,
                    (project, person_id, person_name or "", package_name))
    else:
        cur.execute("""SELECT materials_used FROM work_journal
                       WHERE project=%s
                         AND COALESCE(status,'') NOT IN ('Отклонено','Аннулировано')
                         AND master_name=%s""" + package_journal_filter,
                    (project, person_name or "", package_name))
    used = 0
    for row in cur.fetchall() or []:
        raw = row.get("materials_used") if isinstance(row, dict) else row[0]
        for m in _parse_materials_used(raw):
            material_unit = _norm_base_unit(m.get("unit") or "").strip().lower()
            material_name_key = _material_control_key_resolved(cur, project, m.get("name") or "", material_unit or unit)
            if material_name_key == target_key and (not unit_key or material_unit == unit_key):
                try:
                    used += float(m.get("quantity") or 0)
                except Exception:
                    pass
    cur.execute("""SELECT material, quantity, unit
                   FROM warehouse_history
                   WHERE project=%s
                     AND issued_by=%s
                     AND type=%s
                     """ + package_filter + unit_filter,
                tuple([project, person_name or "", "возврат от мастера", package_name] + ([unit_key] if unit_key else [])))
    returned = 0
    for row in cur.fetchall() or []:
        row_name = _row_value(row, 0, "material", "")
        row_unit = _row_value(row, 2, "unit", unit)
        if _material_control_key_resolved(cur, project, row_name, row_unit) == target_key:
            returned += float(_row_value(row, 1, "quantity", 0) or 0)
    return {"issued": issued, "used": used, "returned": returned, "available": issued - used - returned}

def _apply_material_work_writeoff(cur, project: str, material: dict, actor: dict, date_value: str, fallback_master_name: str = ""):
    name = material.get("name") or ""
    qty = float(material.get("quantity") or 0)
    unit = _norm_base_unit(material.get("unit") or "шт") or "шт"
    work_package = (material.get("workPackage") or material.get("work_package") or "Основная").strip() or "Основная"
    role = actor.get("role") or ""
    actor_id = actor.get("id")
    actor_name = actor.get("name") or fallback_master_name or ""
    if not name or qty <= 0:
        return
    if role not in WORKER_EXECUTION_ROLES:
        raise HTTPException(status_code=400, detail="Списание материалов через ЖПР выполняет мастер, субподрядчик или бригадир после выдачи материала. Прораб/директор подтверждают работу, но не списывают материал напрямую со склада объекта.")
    balance = _personal_material_balance(cur, project, actor_id, actor_name, name, work_package, unit)
    package_part = (" по пакету «" + work_package + "»") if work_package else ""
    if balance["issued"] <= 0:
        raise HTTPException(status_code=400, detail="Материал «"+name+"» не выдан мастеру «"+actor_name+"»"+package_part+" или получение не подтверждено")
    if balance["available"] < qty:
        raise HTTPException(status_code=400, detail="У мастера «"+actor_name+"»"+package_part+" доступно "+str(round(balance["available"], 3))+" "+unit+" «"+name+"», запрошено "+str(qty)+". Лишний материал нужно выдать или вернуть/уточнить списание")
    cur.execute("INSERT INTO warehouse_history (material,type,quantity,unit,date,project,issued_to,issued_by,work_package,date_time) VALUES (%s,%s,%s,%s,%s,%s,%s,%s,%s,%s)",
        (name, "расход (работа мастера)", qty, unit, date_value or None, project, actor_name, actor_name, work_package, __import__("datetime").datetime.now().strftime("%d.%m.%Y, %H:%M")))

def _work_material_items(raw, fallback_package: str = ""):
    items = []
    for material in _parse_materials_used(raw):
        if not isinstance(material, dict):
            continue
        name = (material.get("name") or "").strip()
        qty = _float_or_zero(material.get("quantity"))
        if not name or qty <= 0:
            continue
        work_package = (material.get("workPackage") or material.get("work_package") or fallback_package or "Основная").strip() or "Основная"
        items.append({
            **material,
            "name": name,
            "quantity": qty,
            "unit": _norm_base_unit(material.get("unit") or "шт") or "шт",
            "workPackage": work_package,
        })
    return items

def _server_work_material_norm(cur, material: dict, *, project: str = "", estimate_id=None,
                               work_name: str = "", section_name: str = "",
                               work_qty=0, work_unit: str = ""):
    name = (material.get("name") or "").strip()
    if not name:
        return None
    unit_factor, normalized_work_unit = _estimate_scaled_unit(work_unit or "")
    qty = _float_or_zero(work_qty) * (unit_factor if unit_factor > 1 else 1)
    if qty <= 0:
        return None
    material_unit = material.get("unit") or material.get("materialUnit") or "шт"
    try:
        rules = _load_active_norm_rules(cur, project, estimate_id)
    except Exception as e:
        print("SERVER MATERIAL NORM LOAD ERROR:", str(e))
        return None
    resolved_name = ""
    try:
        resolved_key = _material_control_key_resolved(cur, project, name, material_unit)
        resolved_name = resolved_key[0] if isinstance(resolved_key, tuple) else ""
    except Exception:
        resolved_name = ""
    material_name_variants = [name]
    if resolved_name and _norm_key_text(resolved_name) != _norm_key_text(name):
        material_name_variants.append(resolved_name)
    matches = [
        rule for rule in rules
        if any(
            _norm_rule_matches(rule, work_name, section_name, variant, normalized_work_unit or work_unit, material_unit)
            for variant in material_name_variants
        )
    ]
    if not matches:
        return None
    rule = matches[0]
    qty_per_unit = _safe_float(rule.get("qty_per_unit"))
    if qty_per_unit <= 0:
        return None
    norm_qty = qty * qty_per_unit
    label = rule.get("label") or rule.get("name") or rule.get("rule_key") or "Норма расхода"
    thickness_base = _safe_float(rule.get("thickness_base_mm"))
    if thickness_base > 0:
        thickness = (
            _safe_float(material.get("normThicknessMm"))
            or _safe_float(material.get("thicknessMm"))
            or _safe_float(material.get("thickness_mm"))
            or _safe_float(rule.get("default_thickness_mm"))
            or thickness_base
        )
        norm_qty *= thickness / thickness_base
        label += f" · слой {thickness:g} мм"
    rule_unit = _norm_base_unit(rule.get("material_unit") or material_unit)
    target_unit = _norm_base_unit(material_unit or rule_unit)
    if rule_unit and target_unit and rule_unit != target_unit:
        converted = _convert_norm_material_qty(name, norm_qty, rule_unit, target_unit)
        if not converted:
            return None
        norm_qty, note = converted
        label += " · " + note
    norm_qty = _round_norm_qty(norm_qty)
    return {
        "normQuantity": norm_qty,
        "normSource": label,
        "normRuleId": rule.get("override_id") or rule.get("id"),
        "normThicknessMm": material.get("normThicknessMm") or material.get("thicknessMm") or material.get("thickness_mm") or "",
        "autoNorm": True,
    }

def _validate_work_material_norm_reasons(items, cur=None, *, project: str = "", estimate_id=None,
                                         work_name: str = "", section_name: str = "",
                                         work_qty=0, work_unit: str = "", actor_role: str = ""):
    for material in items or []:
        name = (material.get("name") or "").strip()
        qty = _float_or_zero(material.get("quantity"))
        server_norm = None
        if cur is not None:
            server_norm = _server_work_material_norm(
                cur,
                material,
                project=project,
                estimate_id=estimate_id,
                work_name=work_name,
                section_name=section_name,
                work_qty=work_qty,
                work_unit=work_unit,
            )
        if server_norm:
            material.update(server_norm)
        elif _float_or_zero(material.get("normQuantity") or material.get("norm_quantity")) > 0:
            raise HTTPException(
                status_code=400,
                detail=(
                    "Норма материала «" + name + "» не подтверждена сервером. "
                    "Сохраните правило нормы в справочнике или оформите материал без нормы как отдельную проверяемую позицию."
                ),
            )
        norm_qty = _float_or_zero(material.get("normQuantity") or material.get("norm_quantity"))
        if not name or qty <= 0 or norm_qty <= 0:
            continue
        tolerance = max(0.001, norm_qty * 0.10)
        if qty <= norm_qty + tolerance:
            continue
        over_qty = round(qty - norm_qty, 3)
        unit = material.get("unit") or "шт"
        if actor_role in WORKER_EXECUTION_ROLES:
            raise HTTPException(
                status_code=400,
                detail=(
                    "Списание материала «" + name + "» выше нормы на "
                    + str(over_qty) + " " + unit
                    + ". Исполнитель не может списывать перерасход напрямую: оформите запрос на перерасход для прораба/директора"
                ),
            )
        reason = (material.get("overNormReason") or material.get("over_norm_reason") or "").strip()
        if not reason:
            raise HTTPException(
                status_code=400,
                detail=(
                    "Списание материала «" + name + "» выше нормы на "
                    + str(over_qty) + " " + unit
                    + ". Укажите причину перерасхода перед сохранением ЖПР"
                ),
            )

def _force_work_material_package(items, work_package: str):
    target_package = (work_package or "Основная").strip() or "Основная"
    for material in items or []:
        current_package = (material.get("workPackage") or material.get("work_package") or "").strip()
        if current_package and current_package != target_package:
            raise HTTPException(
                status_code=400,
                detail=(
                    "Материал «" + ((material.get("name") or "").strip() or "(без названия)")
                    + "» относится к пакету «" + current_package
                    + "», а работа закрывается по пакету «" + (target_package or "Без пакета") + "»"
                ),
            )
        material["workPackage"] = target_package
        material.pop("work_package", None)
    return items

def _worker_execution_price_from_estimate(cur, estimate_id, estimate_item_key: str = "", description: str = ""):
    if not estimate_id:
        return 0, "no_estimate"
    cur.execute("SELECT sections_json FROM estimates WHERE id=%s", (estimate_id,))
    row = cur.fetchone()
    if not row:
        return 0, "estimate_not_found"
    raw_sections = row.get("sections_json") if isinstance(row, dict) else row[0]
    try:
        sections = json.loads(raw_sections) if isinstance(raw_sections, str) else (raw_sections or [])
    except Exception:
        sections = []
    target_key = str(estimate_item_key or "").strip().lower()
    target_name = (description or "").strip().lower()
    for section in sections or []:
        for item in (section.get("items") or []):
            if not isinstance(item, dict):
                continue
            item_type = str(item.get("type") or item.get("itemType") or "work").lower()
            if any(t in item_type for t in ("material", "материал", "equipment", "оборуд", "delivery", "доставка")):
                continue
            item_name = (item.get("name") or item.get("description") or "").strip().lower()
            item_keys = [
                item.get("id"),
                item.get("key"),
                item.get("itemKey"),
                item.get("estimateItemKey"),
                item.get("code"),
            ]
            key_match = target_key and any(str(k or "").strip().lower() == target_key for k in item_keys)
            name_match = target_name and item_name == target_name
            if not key_match and not name_match:
                continue
            for field in ("executionPricePerUnit", "priceBrigade", "masterPricePerUnit", "internalPricePerUnit"):
                price = _float_or_zero(item.get(field))
                if price > 0:
                    return price, "estimate:" + field
            return 0, "estimate_no_execution_price"
    return 0, "estimate_item_not_found"

def _worker_contract_item_for_work(
    cur,
    user: dict,
    project: str,
    description: str,
    unit: str = "",
    contract_item_id=None,
    work_package: str = "",
    estimate_item_key: str = "",
    estimate_section: str = "",
):
    """Find the exact assigned contract line for a worker-submitted estimate work."""
    if user.get("role") not in WORKER_EXECUTION_ROLES:
        return None
    project = (project or "").strip()
    description = (description or "").strip()
    unit = (unit or "").strip()
    work_package = (work_package or "").strip() or "Основная"
    user_id = user.get("id")
    user_name = (user.get("name") or "").strip().lower()
    if not project or not description:
        raise HTTPException(status_code=400, detail="Для закрытия сметной работы нужен объект и наименование работы")

    base_sql = """SELECT bci.id, bci.contract_id, bci.description, bci.unit, bci.quantity,
                         bci.price_brigade, bci.done_quantity, bc.project_name, bc.brigade_name,
                         COALESCE(bci.work_package,'')
                  FROM brigade_contract_items bci
                  JOIN brigade_contracts bc ON bc.id=bci.contract_id
                  WHERE bc.project_name=%s
                    AND COALESCE(NULLIF(bci.work_package,''),'Основная')=%s
                    AND COALESCE(bc.status,'') NOT IN ('Аннулирован','Удалён','Удален')
                    AND (COALESCE(bc.contractor_id,0)=%s OR (COALESCE(bc.contractor_id,0)=0 AND LOWER(TRIM(COALESCE(bc.brigade_name,'')))=%s))"""
    params = [project, work_package, user_id, user_name]
    if contract_item_id:
        base_sql += " AND bci.id=%s"
        params.append(contract_item_id)
    elif (estimate_item_key or "").strip():
        base_sql += " AND COALESCE(bci.estimate_item_key,'')=%s"
        params.append((estimate_item_key or "").strip())
    else:
        base_sql += " AND LOWER(TRIM(COALESCE(bci.description,'')))=LOWER(TRIM(%s))"
        params.append(description)
        if (estimate_section or "").strip():
            base_sql += " AND LOWER(TRIM(COALESCE(bci.estimate_section,'')))=LOWER(TRIM(%s))"
            params.append((estimate_section or "").strip())
        if unit:
            base_sql += " ORDER BY CASE WHEN LOWER(TRIM(COALESCE(bci.unit,'')))=LOWER(TRIM(%s)) THEN 0 ELSE 1 END, bci.id LIMIT 1"
            params.append(unit)
        else:
            base_sql += " ORDER BY bci.id LIMIT 1"
    cur.execute(base_sql, tuple(params))
    row = cur.fetchone()
    if not row:
        raise HTTPException(
            status_code=403,
            detail="Эта работа не назначена исполнителю в договорных позициях. Назначьте работу через договор/распределение перед закрытием ЖПР.",
        )
    return dict(row) if isinstance(row, dict) else {
        "id": row[0],
        "contract_id": row[1],
        "description": row[2],
        "unit": row[3],
        "quantity": row[4],
        "price_brigade": row[5],
        "done_quantity": row[6],
        "project_name": row[7],
        "brigade_name": row[8],
        "work_package": row[9],
    }

def _validate_contract_item_capacity(contract_item: dict, requested_qty: float, current_qty: float = 0):
    plan_qty = _float_or_zero(contract_item.get("quantity"))
    done_qty = _float_or_zero(contract_item.get("done_quantity"))
    requested_qty = _float_or_zero(requested_qty)
    current_qty = _float_or_zero(current_qty)
    if plan_qty <= 0:
        raise HTTPException(status_code=400, detail="В договорной позиции нет планового объёма. Сначала исправьте договорную позицию.")
    available = max(0, plan_qty - done_qty + current_qty)
    if requested_qty > available + 0.000001:
        raise HTTPException(
            status_code=400,
            detail=f"Нельзя закрыть больше назначенного объёма: доступно {available:g}, отправлено {requested_qty:g}",
        )

def _sync_contract_item_done(cur, contract_item_id, delta_qty: float):
    if not contract_item_id or abs(_float_or_zero(delta_qty)) < 0.000001:
        return
    cur.execute("""UPDATE brigade_contract_items
                   SET done_quantity = GREATEST(0, LEAST(COALESCE(quantity,0), COALESCE(done_quantity,0)+%s))
                   WHERE id=%s""", (_float_or_zero(delta_qty), contract_item_id))

def _work_material_key(material: dict, cur=None, project: str = ""):
    name = (material.get("name") or "").strip()
    unit = (material.get("unit") or "").strip()
    package = (material.get("workPackage") or material.get("work_package") or "").strip().lower()
    if cur is not None and project:
        return (
            _material_control_key_resolved(cur, project, name, unit),
            package,
        )
    return (
        name.lower(),
        unit.lower(),
        package,
    )

def _work_material_map(items, cur=None, project: str = ""):
    mapped = {}
    for material in items or []:
        key = _work_material_key(material, cur, project)
        if not key[0]:
            continue
        current = mapped.get(key)
        if current:
            current["quantity"] = _float_or_zero(current.get("quantity")) + _float_or_zero(material.get("quantity"))
        else:
            mapped[key] = {**material, "quantity": _float_or_zero(material.get("quantity"))}
    return mapped

def _scale_work_materials(items, ratio: float):
    scaled = []
    for material in items or []:
        qty = _float_or_zero(material.get("quantity"))
        if qty <= 0:
            continue
        scaled.append({**material, "quantity": round(qty * ratio, 6)})
    return scaled

def _restore_material_work_writeoff(cur, project: str, material: dict, work_row: dict, date_value: str, actor_name: str = ""):
    name = material.get("name") or ""
    qty = _float_or_zero(material.get("quantity"))
    unit = material.get("unit") or "шт"
    work_package = (material.get("workPackage") or material.get("work_package") or work_row.get("work_package") or "").strip()
    master_name = work_row.get("master_name") or ""
    master_id = work_row.get("master_id")
    if not name or qty <= 0:
        return
    personal_balance = _personal_material_balance(cur, project, master_id, master_name, name, work_package, unit)
    if personal_balance["issued"] > 0:
        cur.execute("INSERT INTO warehouse_history (material,type,quantity,unit,date,project,issued_to,issued_by,work_package,date_time) VALUES (%s,%s,%s,%s,%s,%s,%s,%s,%s,%s)",
                    (name, "корректировка списания мастера", qty, unit, date_value or None, project, master_name, actor_name or master_name, work_package, __import__("datetime").datetime.now().strftime("%d.%m.%Y, %H:%M")))
        return
    mat = _stock_row_by_material_key(
        cur,
        project=project,
        material_name=name,
        unit=unit,
        work_package=work_package,
    )
    if mat:
        mat_id = mat.get("id") if isinstance(mat, dict) else mat[0]
        cur.execute("UPDATE materials SET quantity=COALESCE(quantity,0)+%s, unit=COALESCE(NULLIF(unit,''),%s) WHERE id=%s", (qty, unit, mat_id))
    else:
        cur.execute("INSERT INTO materials (name, unit, quantity, price, min_quantity, project, category, work_package) VALUES (%s,%s,%s,%s,%s,%s,%s,%s)",
                    (name, unit, qty, 0, 0, project, "Возврат", work_package))
    cur.execute("INSERT INTO warehouse_history (material,type,quantity,unit,date,project,issued_by,work_package,date_time) VALUES (%s,%s,%s,%s,%s,%s,%s,%s,%s)",
                (name, "возврат (корректировка работы)", qty, unit, date_value or None, project, actor_name or master_name, work_package, __import__("datetime").datetime.now().strftime("%d.%m.%Y, %H:%M")))

def _apply_work_material_delta(cur, work_row: dict, old_items, new_items, current_user: dict, date_value: str):
    project = work_row.get("project") or ""
    if not project:
        return
    old_map = _work_material_map(old_items, cur, project)
    new_map = _work_material_map(new_items, cur, project)
    changes = []
    for key in set(old_map.keys()) | set(new_map.keys()):
        old_material = old_map.get(key) or {}
        new_material = new_map.get(key) or {}
        delta = round(_float_or_zero(new_material.get("quantity")) - _float_or_zero(old_material.get("quantity")), 6)
        if abs(delta) < 0.000001:
            continue
        changes.append((delta, new_material or old_material))
    if not changes:
        return
    is_worker = (current_user.get("role") or "") in WORKER_EXECUTION_ROLES
    for delta, base in changes:
        material = {**base, "quantity": abs(delta)}
        if delta > 0:
            if not is_worker:
                raise HTTPException(
                    status_code=403,
                    detail="Увеличивать списание материалов в ЖПР может только исполнитель: мастер, субподрядчик или бригадир.",
                )
            master_name = work_row.get("master_name") or ""
            master_id = work_row.get("master_id")
            work_package = material.get("workPackage") or material.get("work_package") or work_row.get("work_package") or ""
            if master_id and str(master_id) != str(current_user.get("id") or ""):
                raise HTTPException(status_code=403, detail="Нельзя списывать материалы за другого исполнителя")
            if master_name and master_name != (current_user.get("name") or ""):
                raise HTTPException(status_code=403, detail="Нельзя списывать материалы за другого исполнителя")
            _apply_material_work_writeoff(cur, project, material, current_user, date_value, master_name)
        else:
            _restore_material_work_writeoff(cur, project, material, work_row, date_value, current_user.get("name") or "")

def _work_journal_duplicate(cur, project, room_id=None, room_name="", estimate_item_key="", description="", work_package="", exclude_id=None):
    project = (project or "").strip()
    room_name = (room_name or "").strip()
    estimate_item_key = (estimate_item_key or "").strip()
    description = (description or "").strip()
    work_package = (work_package or "").strip()
    if not project or (not room_id and not room_name) or (not estimate_item_key and not description):
        return None

    exclude_sql = " AND id<>%s" if exclude_id else ""
    exclude_params = [exclude_id] if exclude_id else []
    package_sql = " AND COALESCE(work_package,'')=%s" if work_package else ""
    package_params = [work_package] if work_package else []

    target_sql = "COALESCE(estimate_item_key,'')=%s" if estimate_item_key else "LOWER(TRIM(description))=LOWER(TRIM(%s))"
    target_value = estimate_item_key if estimate_item_key else description

    if room_id:
        cur.execute(f"""SELECT id, master_name, status, room_name, work_package FROM work_journal
                       WHERE project=%s AND room_id=%s AND {target_sql}
                         AND COALESCE(status,'') NOT IN ('Отклонено','Аннулировано'){package_sql}{exclude_sql}
                       LIMIT 1""", [project, room_id, target_value] + package_params + exclude_params)
        duplicate = cur.fetchone()
        if duplicate:
            return duplicate

    if room_name:
        cur.execute(f"""SELECT id, master_name, status, room_name, work_package FROM work_journal
                       WHERE project=%s AND LOWER(TRIM(COALESCE(room_name,'')))=LOWER(TRIM(%s)) AND {target_sql}
                         AND COALESCE(status,'') NOT IN ('Отклонено','Аннулировано'){package_sql}{exclude_sql}
                       LIMIT 1""", [project, room_name, target_value] + package_params + exclude_params)
        duplicate = cur.fetchone()
        if duplicate:
            return duplicate

    return None

def _raise_work_journal_duplicate(duplicate):
    if not duplicate:
        return
    row_id = duplicate.get("id") if isinstance(duplicate, dict) else duplicate[0]
    master_name = duplicate.get("master_name") if isinstance(duplicate, dict) else duplicate[1]
    room_name = duplicate.get("room_name") if isinstance(duplicate, dict) and duplicate.get("room_name") else ""
    room_part = (" в помещении «" + str(room_name) + "»") if room_name else " по выбранному помещению"
    raise HTTPException(
        status_code=409,
        detail="Эта работа уже заведена" + room_part + ". Запись ЖПР №" + str(row_id) + " (" + str(master_name or "исполнитель") + ")"
    )

def _room_work_duplicate(cur, project, room_id=None, room_name="", estimate_item_key="", description="", work_package="", exclude_work_journal_id=None):
    project = (project or "").strip()
    room_name = (room_name or "").strip()
    estimate_item_key = (estimate_item_key or "").strip()
    description = (description or "").strip()
    work_package = (work_package or "").strip()
    if not project or (not room_id and not room_name) or (not estimate_item_key and not description):
        return None

    target_sql = "COALESCE(estimate_item_key,'')=%s" if estimate_item_key else "LOWER(TRIM(description))=LOWER(TRIM(%s))"
    target_value = estimate_item_key if estimate_item_key else description
    package_sql = " AND COALESCE(work_package,'')=%s" if work_package else ""
    package_params = [work_package] if work_package else []
    exclude_sql = " AND COALESCE(work_journal_id,0)<>%s" if exclude_work_journal_id else ""
    exclude_params = [exclude_work_journal_id] if exclude_work_journal_id else []

    if room_id:
        cur.execute(f"""SELECT id, master_name, status, room_name, work_package FROM room_works
                        WHERE project=%s AND room_id=%s AND {target_sql}
                          AND COALESCE(status,'') NOT IN ('Отклонено','Аннулировано'){package_sql}{exclude_sql}
                        LIMIT 1""", [project, room_id, target_value] + package_params + exclude_params)
        duplicate = cur.fetchone()
        if duplicate:
            return duplicate

    if room_name:
        cur.execute(f"""SELECT id, master_name, status, room_name, work_package FROM room_works
                        WHERE project=%s AND LOWER(TRIM(COALESCE(room_name,'')))=LOWER(TRIM(%s)) AND {target_sql}
                          AND COALESCE(status,'') NOT IN ('Отклонено','Аннулировано'){package_sql}{exclude_sql}
                        LIMIT 1""", [project, room_name, target_value] + package_params + exclude_params)
        duplicate = cur.fetchone()
        if duplicate:
            return duplicate
    return None

def _sync_room_work_from_journal(cur, work_row: dict):
    if not work_row:
        return
    work_journal_id = work_row.get("id")
    room_id = work_row.get("room_id")
    room_name = (work_row.get("room_name") or "").strip()
    project = (work_row.get("project") or "").strip()
    description = (work_row.get("description") or "").strip()
    estimate_item_key = (work_row.get("estimate_item_key") or "").strip()
    work_package = (work_row.get("work_package") or "").strip()

    if not room_id and not room_name:
        if work_journal_id:
            cur.execute("DELETE FROM room_works WHERE work_journal_id=%s", (work_journal_id,))
        return

    duplicate = _room_work_duplicate(
        cur,
        project,
        room_id=room_id,
        room_name=room_name,
        estimate_item_key=estimate_item_key,
        description=description,
        work_package=work_package,
        exclude_work_journal_id=work_journal_id,
    )
    if duplicate:
        _raise_work_journal_duplicate(duplicate)

    cur.execute("SELECT id FROM room_works WHERE work_journal_id=%s", (work_journal_id,))
    existing = cur.fetchone()
    payload = (
        room_id,
        project,
        room_name,
        work_row.get("master_id"),
        work_row.get("master_name"),
        description,
        work_row.get("surface") or "",
        work_row.get("unit") or "",
        work_row.get("quantity") or 0,
        work_row.get("price_per_unit") or 0,
        work_row.get("total") or 0,
        work_row.get("date") or "",
        work_row.get("status") or "На проверке",
        work_row.get("photo_url") or "",
        work_row.get("confirmed_by") or "",
        work_journal_id,
        work_package,
        estimate_item_key,
    )
    if existing:
        cur.execute("""UPDATE room_works
                       SET room_id=%s, project=%s, room_name=%s, master_id=%s, master_name=%s,
                           description=%s, surface=%s, unit=%s, quantity=%s, price_per_unit=%s,
                           total=%s, date=%s, status=%s, photo_url=%s, confirmed_by=%s,
                           work_journal_id=%s, work_package=%s, estimate_item_key=%s
                       WHERE work_journal_id=%s""", payload + (work_journal_id,))
    else:
        cur.execute("""INSERT INTO room_works
                       (room_id,project,room_name,master_id,master_name,description,surface,unit,quantity,price_per_unit,total,date,status,photo_url,confirmed_by,work_journal_id,work_package,estimate_item_key)
                       VALUES (%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s)""", payload)

def _work_journal_sync_row(cur, work_journal_id: int):
    if not work_journal_id:
        return None
    cur.execute("""SELECT id, master_id, master_name, project, description, surface, unit, quantity,
                          price_per_unit, total, date, status, photo_url, confirmed_by,
                          room_id, room_name, work_package, estimate_item_key, contract_item_id, estimate_id,
                          section_name, hidden_work, materials_used, project_docs,
                          customer_price_per_unit, customer_total
                   FROM work_journal WHERE id=%s""", (work_journal_id,))
    row = cur.fetchone()
    if not row:
        return None
    if isinstance(row, dict):
        return dict(row)
    cols = [d[0] for d in cur.description]
    return dict(zip(cols, row))

def _sync_hidden_work_act_from_journal(cur, work_row: dict):
    if not work_row or not work_row.get("hidden_work"):
        return 0
    work_journal_id = work_row.get("id")
    project_name = (work_row.get("project") or "").strip()
    work_name = (work_row.get("description") or "").strip()
    if not project_name or not work_name:
        return 0

    existing = None
    if work_journal_id:
        cur.execute("SELECT id, COALESCE(status,'Черновик') FROM hidden_works_acts WHERE work_journal_id=%s LIMIT 1", (work_journal_id,))
        existing = cur.fetchone()
    if not existing and work_row.get("estimate_id"):
        cur.execute("""SELECT id, COALESCE(status,'Черновик') FROM hidden_works_acts
                       WHERE estimate_id=%s AND work_name=%s LIMIT 1""", (work_row.get("estimate_id"), work_name))
        existing = cur.fetchone()
    if not existing:
        cur.execute("""SELECT id, COALESCE(status,'Черновик') FROM hidden_works_acts
                       WHERE project_name=%s AND work_name=%s AND COALESCE(brigade,'')=%s
                         AND work_date IS NOT DISTINCT FROM %s LIMIT 1""",
                    (project_name, work_name, work_row.get("master_name") or "", work_row.get("date") or None))
        existing = cur.fetchone()
    quantity = work_row.get("quantity") or 0
    unit = work_row.get("unit") or ""
    price_per_unit = work_row.get("customer_price_per_unit") or work_row.get("price_per_unit") or 0
    total = work_row.get("customer_total") or work_row.get("total") or 0
    work_date = work_row.get("date") or None
    section_name = work_row.get("section_name") or work_row.get("work_package") or ""
    work_package = (work_row.get("work_package") or "Основная").strip() or "Основная"
    brigade = work_row.get("master_name") or ""
    materials_used = work_row.get("materials_used") or ""
    project_docs = work_row.get("project_docs") or ""
    estimate_id = work_row.get("estimate_id")

    if existing:
        act_id = existing.get("id") if isinstance(existing, dict) else existing[0]
        status = existing.get("status") if isinstance(existing, dict) else existing[1]
        if status not in ("Подписан", "Аннулирован"):
            cur.execute("""UPDATE hidden_works_acts
                           SET project_name=%s, estimate_id=%s, work_name=%s, section_name=%s, work_package=%s,
                               brigade=%s, quantity=%s, unit=%s, price_per_unit=%s, total=%s,
                               work_date=%s, materials_used=%s, project_docs=%s, work_journal_id=%s
                           WHERE id=%s""",
                        (project_name, estimate_id, work_name, section_name, work_package, brigade, quantity, unit,
                         price_per_unit, total, work_date, materials_used, project_docs, work_journal_id, act_id))
        return 0

    cur.execute("SELECT COUNT(*) AS count FROM hidden_works_acts WHERE project_name=%s", (project_name,))
    count_row = cur.fetchone()
    existing_count = count_row.get("count") if isinstance(count_row, dict) else count_row[0]
    next_num = (existing_count or 0) + 1
    act_number = "АОСР-" + str(next_num) + (("/" + str(estimate_id)) if estimate_id else "")
    cur.execute("""INSERT INTO hidden_works_acts
                   (project_name, estimate_id, act_number, work_name, section_name, brigade,
                    work_package, quantity, unit, price_per_unit, total, work_date, materials_used, project_docs,
                    status, work_journal_id)
                   VALUES (%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s)""",
                (project_name, estimate_id, act_number, work_name, section_name, brigade,
                 work_package, quantity, unit, price_per_unit, total, work_date, materials_used, project_docs,
                 "Черновик", work_journal_id))
    return 1

def _mark_room_work_rejected(cur, work_journal_id: int, confirmed_by: str = ""):
    if not work_journal_id:
        return
    cur.execute("UPDATE room_works SET status='Отклонено', confirmed_by=%s WHERE work_journal_id=%s", (confirmed_by or "", work_journal_id))

@app.post("/work-journal")
def create_work_journal(w: WorkJournalModel, _current_user: dict = Depends(require_roles(*JOURNAL_WRITE_ROLES))):
    require_project_access(_current_user, w.project)
    user_role = _current_user.get("role")
    work_package = (w.workPackage or "Основная").strip() or "Основная"
    if user_role in PACKAGE_LIMIT_ROLES and not has_work_execution_package_access(_current_user, w.project, work_package):
        raise HTTPException(status_code=403, detail="Нет доступа к пакету работ")
    if user_role in WORKER_EXECUTION_ROLES:
        if str(w.masterId or "") != str(_current_user.get("id") or "") and (w.masterName or "").strip().lower() != (_current_user.get("name") or "").strip().lower():
            raise HTTPException(status_code=403, detail="Мастер может создавать ЖПР только от своего имени")
        if not w.roomId and not (w.roomName or "").strip():
            raise HTTPException(status_code=400, detail="Для закрытия работ исполнителем укажите помещение. Это нужно для контроля обмеров и защиты от дублей.")
    used = [m for m in (w.materialsUsed or []) if m.get("name") and float(m.get("quantity") or 0) > 0]

    conn = get_db()
    conn.autocommit = False
    cur = conn.cursor(cursor_factory=psycopg2.extras.RealDictCursor)
    try:
        estimate_work_item = None
        journal_estimate_id = w.estimateId
        journal_section_name = w.sectionName
        journal_description = w.description
        journal_unit = w.unit
        journal_work_package = work_package
        journal_estimate_item_key = w.estimateItemKey
        if str(journal_estimate_item_key or "").startswith("pricelist:"):
            journal_estimate_item_key = ""
        if journal_estimate_id:
            require_estimate_access(cur, journal_estimate_id, _current_user)
            estimate_work_item = _load_estimate_work_item(
                cur,
                journal_estimate_id,
                project_name=w.project,
                work_package=work_package,
                estimate_item_key=journal_estimate_item_key,
                section_name=w.sectionName,
                item_name=w.description,
            )
            journal_section_name = estimate_work_item.get("sectionName") or journal_section_name
            journal_description = estimate_work_item.get("name") or journal_description
            journal_unit = estimate_work_item.get("unit") or journal_unit
            journal_work_package = estimate_work_item.get("workPackage") or journal_work_package
            journal_estimate_item_key = estimate_work_item.get("estimateItemKey") or journal_estimate_item_key
        elif journal_estimate_item_key:
            raise HTTPException(status_code=400, detail="Для сметной строки ЖПР нужен estimateId")

        _raise_work_journal_duplicate(_work_journal_duplicate(
            cur,
            w.project,
            room_id=w.roomId,
            room_name=w.roomName,
            estimate_item_key=journal_estimate_item_key,
            description=journal_description,
            work_package=journal_work_package,
        ))
        used = _force_work_material_package(used, journal_work_package)
        _validate_work_material_norm_reasons(
            used,
            cur,
            project=w.project,
            estimate_id=journal_estimate_id,
            work_name=journal_description,
            section_name=journal_section_name,
            work_qty=w.quantity,
            work_unit=journal_unit,
            actor_role=user_role,
        )
        for m in used:
            _apply_material_work_writeoff(cur, w.project, m, _current_user, w.date, w.masterName)

        import json as _json
        materials_json = _json.dumps(used, ensure_ascii=False) if used else None
        contract_item_id = w.contractItemId
        if user_role in WORKER_EXECUTION_ROLES:
            assigned_item = _worker_contract_item_for_work(
                cur,
                _current_user,
                w.project,
                journal_description,
                journal_unit,
                contract_item_id,
                journal_work_package,
                journal_estimate_item_key,
                journal_section_name,
            )
            _validate_contract_item_capacity(assigned_item, w.quantity)
            contract_item_id = assigned_item.get("id")
            execution_price = _float_or_zero(assigned_item.get("price_brigade"))
            if execution_price <= 0:
                raise HTTPException(status_code=400, detail="Для работы не задана цена исполнителя в договорной позиции")
            execution_mode = "brigade_contract"
            execution_total = float(w.quantity or 0) * execution_price
            customer_price = 0
            customer_total = 0
        else:
            if user_role in FINANCE_ROLES:
                execution_price = float(w.executionPricePerUnit or 0)
                execution_total = float(w.executionTotal or (float(w.quantity or 0) * execution_price))
                customer_price = float(w.customerPricePerUnit or w.pricePerUnit or 0)
                customer_total = float(w.customerTotal or w.total or (float(w.quantity or 0) * customer_price))
                execution_mode = w.executionPriceMode or ("fixed" if w.executionPricePerUnit else "not_set")
            else:
                execution_price = 0
                execution_total = 0
                customer_price = estimate_work_item.get("pricePerUnit") if estimate_work_item else 0
                customer_total = float(w.quantity or 0) * float(customer_price or 0)
                execution_mode = "not_set"
        cur.execute("""INSERT INTO work_journal
                       (master_id,master_name,project,description,unit,quantity,price_per_unit,total,date,
                        comment,photo_url,materials_used,
                        estimate_id,section_name,responsible_itr,weather,time_start,time_end,
                        hidden_work,quality_status,normatives,project_docs,
                        work_package,room_id,room_name,surface,estimate_item_name,estimate_item_key,
                        contract_item_id,customer_price_per_unit,customer_total,execution_price_per_unit,execution_total,execution_price_mode)
                       VALUES (%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s) RETURNING *""",
                    (w.masterId,w.masterName,w.project,journal_description,journal_unit,w.quantity,execution_price,execution_total,w.date,
                     w.comment,w.photoUrl,materials_json,
                     journal_estimate_id,journal_section_name,w.responsibleItr,w.weather,w.timeStart,w.timeEnd,
                     w.hiddenWork,w.qualityStatus,w.normatives,w.projectDocs,
                     journal_work_package,w.roomId,w.roomName,w.surface,w.estimateItemName or journal_description,journal_estimate_item_key,
                     contract_item_id,customer_price,customer_total,execution_price,execution_total,execution_mode))
        row = cur.fetchone()
        _sync_contract_item_done(cur, contract_item_id, w.quantity)
        _sync_room_work_from_journal(cur, row)
        _sync_hidden_work_act_from_journal(cur, row)
        conn.commit()
        log_audit(
            _current_user.get("name", ""),
            _current_user.get("role", ""),
            "create",
            "work_journal",
            row.get("id"),
            ("ЖПР: " + str(row.get("description") or journal_description or "") + "; объем " + str(row.get("quantity") or w.quantity or "") + " " + str(row.get("unit") or journal_unit or ""))[:250],
            w.project,
        )
        _run_project_ai_control_safely(w.project, "work_journal:create")
        return dict(row)
    except HTTPException:
        conn.rollback()
        raise
    except Exception as e:
        conn.rollback()
        raise HTTPException(status_code=500, detail=str(e))
    finally:
        cur.close()
        conn.close()

@app.put("/work-journal/{id}")
def update_work_journal(id: int, data: dict, _current_user: dict = Depends(require_roles(*JOURNAL_WRITE_ROLES))):
    import json as _json
    conn = get_db()
    conn.autocommit = False
    cur = conn.cursor(cursor_factory=psycopg2.extras.RealDictCursor)
    require_row_project_access(cur, "work_journal", id, _current_user, "project")
    cur.execute("""SELECT project, master_id, master_name, room_id, room_name, description,
                          estimate_item_key, work_package, status, quantity, unit, date, materials_used,
                          contract_item_id, estimate_id, section_name
		                   FROM work_journal WHERE id=%s FOR UPDATE""", (id,))
    project_row = cur.fetchone()
    project_name = project_row.get("project") if project_row else ""
    role = _current_user.get("role")
    current_work_package = project_row.get("work_package") or "Основная" if project_row else "Основная"
    requested_work_package = (data.get("workPackage", current_work_package) or "Основная").strip() or "Основная"
    if role in PACKAGE_LIMIT_ROLES and (
        not has_work_execution_package_access(_current_user, project_name, current_work_package)
        or not has_work_execution_package_access(_current_user, project_name, requested_work_package)
    ):
        cur.close(); conn.close()
        raise HTTPException(status_code=403, detail="Нет доступа к пакету работ")
    if role in WORKER_EXECUTION_ROLES:
        master_id = project_row.get("master_id") if project_row else None
        master_name = project_row.get("master_name") if project_row else ""
        if str(master_id or "") != str(_current_user.get("id") or "") and (master_name or "").strip().lower() != (_current_user.get("name") or "").strip().lower():
            cur.close(); conn.close()
            raise HTTPException(status_code=403, detail="Мастер может менять только свои записи ЖПР")
        allowed_worker_keys = {"quantity", "comment", "photoUrl", "materialsUsed", "timeStart", "timeEnd"}
        forbidden_worker_keys = set(data.keys()) - allowed_worker_keys
        if forbidden_worker_keys:
            cur.close(); conn.close()
            raise HTTPException(
                status_code=403,
                detail="Рабочая роль может менять только объем, комментарий, фото, время и списанные материалы ЖПР"
            )
    financial_keys = {
        "pricePerUnit", "total", "customerPricePerUnit", "customerTotal",
        "executionPricePerUnit", "executionTotal", "executionPriceMode",
    }
    if role not in FINANCE_ROLES and any(k in data for k in financial_keys):
        cur.close(); conn.close()
        raise HTTPException(status_code=403, detail="Денежные поля ЖПР меняет только директор, замдиректора или бухгалтер. Для исполнителей сумма берётся из договорной позиции.")
    target_status = str(data.get("status", project_row.get("status") if project_row else "") or "").strip()
    target_room_id = data.get("roomId", project_row.get("room_id") if project_row else None)
    target_room_name = data.get("roomName", project_row.get("room_name") if project_row else "")
    confirm_roles = set(LEADERSHIP_ROLES) | {"прораб", "главный_инженер"}
    if (
        str(data.get("status") or "").strip() == "Подтверждено"
        or "confirmedBy" in data
        or "confirmedAt" in data
    ) and role not in confirm_roles:
        cur.close(); conn.close()
        raise HTTPException(status_code=403, detail="Подтверждать ЖПР может директор, замдиректора, прораб или главный инженер")
    if target_status != "Отклонено" and (target_status == "Подтверждено" or (project_row and project_row.get("estimate_item_key"))) and not target_room_id and not str(target_room_name or "").strip():
        cur.close(); conn.close()
        raise HTTPException(status_code=400, detail="Нельзя подтвердить или сохранить сметную работу без помещения")
    if str(data.get("status") or "").strip() == "Отклонено":
        current_status = str(project_row.get("status") or "").strip() if project_row else ""
        if current_status == "Отклонено":
            conn.rollback()
            cur.close(); conn.close()
            return {"ok": True, "alreadyRejected": True}
        if role not in set(LEADERSHIP_ROLES) | {"прораб", "главный_инженер"}:
            conn.rollback()
            cur.close(); conn.close()
            raise HTTPException(status_code=403, detail="Отклонять ЖПР может директор, зам, прораб или главный инженер")
        conn.rollback()
        cur.close(); conn.close()
        return delete_work_journal(id, _current_user)
    # Динамически обновляем только переданные поля. Старая логика (status/confirmedBy/...) продолжает работать.
    fields_map = [
        ('status', 'status'),
        ('quantity', 'quantity'),
        ('pricePerUnit', 'price_per_unit'),
        ('total', 'total'),
        ('customerPricePerUnit', 'customer_price_per_unit'),
        ('customerTotal', 'customer_total'),
        ('executionPricePerUnit', 'execution_price_per_unit'),
        ('executionTotal', 'execution_total'),
        ('executionPriceMode', 'execution_price_mode'),
        ('confirmedBy', 'confirmed_by'),
        ('confirmedAt', 'confirmed_at'),
        ('comment', 'comment'),
        ('photoUrl', 'photo_url'),
        ('responsibleItr', 'responsible_itr'),
        ('weather', 'weather'),
        ('timeStart', 'time_start'),
        ('timeEnd', 'time_end'),
        ('qualityStatus', 'quality_status'),
        ('normatives', 'normatives'),
        ('projectDocs', 'project_docs'),
        ('sectionName', 'section_name'),
        ('hiddenWork', 'hidden_work'),
        ('workPackage', 'work_package'),
        ('roomId', 'room_id'),
        ('roomName', 'room_name'),
        ('surface', 'surface'),
        ('estimateItemName', 'estimate_item_name'),
        ('estimateItemKey', 'estimate_item_key'),
    ]
    sets, vals = [], []
    ai_resetting_fields = {'responsibleItr','weather','timeStart','timeEnd','qualityStatus','normatives','projectDocs'}
    reset_ai = False
    for js_key, db_col in fields_map:
        if js_key in data:
            sets.append(db_col + "=%s")
            vals.append(data[js_key])
            if js_key in ai_resetting_fields:
                reset_ai = True
    if reset_ai:
        sets.append("ai_filled=FALSE")
    old_materials = _work_material_items(project_row.get("materials_used"), project_row.get("work_package") or "") if project_row else []
    new_materials = None
    old_qty = _float_or_zero(project_row.get("quantity") if project_row else 0)
    new_qty = _float_or_zero(data.get("quantity")) if "quantity" in data else old_qty
    contract_item_id = project_row.get("contract_item_id") if project_row else None
    contract_item = None
    if contract_item_id and "quantity" in data:
        cur.execute("""SELECT id, quantity, done_quantity, price_brigade
                       FROM brigade_contract_items
                       WHERE id=%s FOR UPDATE""", (contract_item_id,))
        contract_item = cur.fetchone()
        if contract_item:
            _validate_contract_item_capacity(contract_item, new_qty, old_qty)
    package_changed = "workPackage" in data and (data.get("workPackage") or "") != (project_row.get("work_package") or "")
    if "materialsUsed" in data:
        new_materials = _work_material_items(data.get("materialsUsed"), data.get("workPackage", project_row.get("work_package") if project_row else ""))
    elif old_materials and ("quantity" in data or package_changed):
        new_materials = _scale_work_materials(old_materials, max(0, new_qty) / old_qty) if "quantity" in data and old_qty > 0 else list(old_materials)
        if package_changed:
            target_package = data.get("workPackage") or ""
            new_materials = [{**m, "workPackage": target_package} for m in new_materials]
    if new_materials is not None:
        target_material_package = data.get("workPackage", project_row.get("work_package") if project_row else "")
        new_materials = _force_work_material_package(new_materials, target_material_package or "")
        _validate_work_material_norm_reasons(
            new_materials,
            cur,
            project=project_name,
            estimate_id=data.get("estimateId") or (project_row.get("estimate_id") if project_row else None),
            work_name=data.get("description") or (project_row.get("description") if project_row else ""),
            section_name=data.get("sectionName") or (project_row.get("section_name") if project_row else ""),
            work_qty=new_qty,
            work_unit=data.get("unit") or (project_row.get("unit") if project_row else ""),
            actor_role=_current_user.get("role") or "",
        )
    if contract_item_id and contract_item and "quantity" in data:
        contract_price = _float_or_zero(contract_item.get("price_brigade") if isinstance(contract_item, dict) else contract_item[3])
        contract_total = round(new_qty * contract_price, 2)
        if "pricePerUnit" not in data:
            sets.append("price_per_unit=%s")
            vals.append(contract_price)
        if "total" not in data:
            sets.append("total=%s")
            vals.append(contract_total)
        if "executionPricePerUnit" not in data:
            sets.append("execution_price_per_unit=%s")
            vals.append(contract_price)
        if "executionTotal" not in data:
            sets.append("execution_total=%s")
            vals.append(contract_total)
        if "executionPriceMode" not in data:
            sets.append("execution_price_mode=%s")
            vals.append("brigade_contract")
    if any(k in data for k in ("roomId", "roomName", "estimateItemKey", "description")):
        _raise_work_journal_duplicate(_work_journal_duplicate(
            cur,
            project_name,
            room_id=data.get("roomId", project_row.get("room_id") if project_row else None),
            room_name=data.get("roomName", project_row.get("room_name") if project_row else ""),
            estimate_item_key=data.get("estimateItemKey", project_row.get("estimate_item_key") if project_row else ""),
            description=data.get("description", project_row.get("description") if project_row else ""),
            work_package=data.get("workPackage", project_row.get("work_package") if project_row else ""),
            exclude_id=id,
        ))
    try:
        if new_materials is not None:
            _apply_work_material_delta(cur, project_row, old_materials, new_materials, _current_user, project_row.get("date") or "")
            sets.append("materials_used=%s")
            vals.append(_json.dumps(new_materials, ensure_ascii=False) if new_materials else None)
        if not sets:
            conn.rollback()
            return {"ok": True}
        vals.append(id)
        cur.execute("UPDATE work_journal SET " + ", ".join(sets) + " WHERE id=%s", vals)
        if contract_item_id and "quantity" in data:
            _sync_contract_item_done(cur, contract_item_id, new_qty - old_qty)
        updated_row = _work_journal_sync_row(cur, id)
        _sync_room_work_from_journal(cur, updated_row)
        _sync_hidden_work_act_from_journal(cur, updated_row)
        conn.commit()
        audit_action = str(data.get("status") or "update").strip() or "update"
        log_audit(
            _current_user.get("name", ""),
            _current_user.get("role", ""),
            audit_action,
            "work_journal",
            id,
            ("ЖПР обновлен: " + str(updated_row.get("description") or "") + "; статус " + str(updated_row.get("status") or ""))[:250],
            project_name,
        )
        _run_project_ai_control_safely(project_name, "work_journal:update")
        return {"ok": True}
    except HTTPException:
        conn.rollback()
        raise
    except Exception as e:
        conn.rollback()
        raise HTTPException(status_code=500, detail=str(e))
    finally:
        cur.close()
        conn.close()

@app.delete("/work-journal/{id}")
def delete_work_journal(id: int, _current_user: dict = Depends(require_roles(*LEADERSHIP_ROLES, "прораб", "главный_инженер"))):
    import json as _json
    from datetime import datetime
    conn = get_db()
    conn.autocommit = False
    cur = conn.cursor(cursor_factory=psycopg2.extras.RealDictCursor)
    try:
        require_row_project_access(cur, "work_journal", id, _current_user, "project")
        cur.execute("SELECT project, master_id, master_name, date, status, comment, materials_used, work_package, quantity, contract_item_id, description FROM work_journal WHERE id=%s FOR UPDATE", (id,))
        work = cur.fetchone()
        if not work:
            conn.rollback()
            raise HTTPException(status_code=404, detail="Запись журнала не найдена")
        if _current_user.get("role") in PACKAGE_LIMIT_ROLES and not has_package_access(_current_user, work.get("work_package") or "Основная"):
            conn.rollback()
            raise HTTPException(status_code=403, detail="Нет доступа к пакету работ")
        cancellation_marker = "Аннулировано без физического удаления"
        if cancellation_marker in (work.get("comment") or ""):
            conn.rollback()
            return {"ok": True, "cancelled": True, "alreadyCancelled": True, "materialsRestored": 0}
        used = []
        raw_used = work.get("materials_used")
        if raw_used:
            try:
                parsed = _json.loads(raw_used) if isinstance(raw_used, str) else raw_used
                if isinstance(parsed, list):
                    used = [m for m in parsed if isinstance(m, dict) and m.get("name") and float(m.get("quantity") or 0) > 0]
            except Exception:
                used = []
        for m in used:
            name = m.get("name") or ""
            qty = float(m.get("quantity") or 0)
            unit = m.get("unit") or "шт"
            project_name = work.get("project") or ""
            master_name = work.get("master_name") or ""
            master_id = work.get("master_id")
            work_package = m.get("workPackage") or m.get("work_package") or work.get("work_package") or ""
            personal_balance = _personal_material_balance(cur, project_name, master_id, master_name, name, work_package, unit)
            if personal_balance["issued"] > 0:
                cur.execute("INSERT INTO warehouse_history (material,type,quantity,unit,date,project,issued_to,issued_by,work_package,date_time) VALUES (%s,%s,%s,%s,%s,%s,%s,%s,%s,%s)",
                            (name, "отмена списания мастера", qty, unit, str(work.get("date") or ""), project_name, master_name, _current_user.get("name") or "", work_package, datetime.now().strftime("%d.%m.%Y, %H:%M")))
                continue
            cur.execute(f"""SELECT id FROM materials
                           WHERE name=%s AND project=%s AND COALESCE(work_package,'')=%s
                             AND {_sql_norm_unit('unit')}=%s
                           ORDER BY id LIMIT 1 FOR UPDATE""", (name, project_name, work_package, unit))
            mat = cur.fetchone()
            if mat:
                cur.execute("UPDATE materials SET quantity=COALESCE(quantity,0)+%s, unit=COALESCE(NULLIF(unit,''),%s) WHERE id=%s", (qty, unit, mat["id"]))
            else:
                cur.execute("INSERT INTO materials (name, unit, quantity, price, min_quantity, project, category, work_package) VALUES (%s,%s,%s,%s,%s,%s,%s,%s)",
                            (name, unit, qty, 0, 0, project_name, "Возврат", work_package))
            cur.execute("INSERT INTO warehouse_history (material,type,quantity,unit,date,project,issued_by,work_package,date_time) VALUES (%s,%s,%s,%s,%s,%s,%s,%s,%s)",
                        (name, "возврат (удаление работы)", qty, unit, str(work.get("date") or ""), project_name, master_name, work_package, datetime.now().strftime("%d.%m.%Y, %H:%M")))
        cur.execute("SELECT COUNT(*) AS cnt FROM piecework WHERE work_journal_id=%s", (id,))
        piecework_row = cur.fetchone()
        piecework_count = int((piecework_row.get("cnt") if isinstance(piecework_row, dict) else piecework_row[0]) or 0)
        actor_name = _current_user.get("name") or ""
        cancelled_at = datetime.now().strftime("%d.%m.%Y, %H:%M")
        old_comment = work.get("comment") or ""
        cancel_note = cancellation_marker + " " + cancelled_at
        if actor_name:
            cancel_note += " (" + actor_name + ")"
        new_comment = (old_comment + "\n" + cancel_note).strip() if old_comment else cancel_note
        cur.execute("UPDATE work_journal SET status=%s, comment=%s WHERE id=%s", ("Отклонено", new_comment, id))
        _sync_contract_item_done(cur, work.get("contract_item_id"), -_float_or_zero(work.get("quantity")))
        _mark_room_work_rejected(cur, id, actor_name)
        conn.commit()
        log_audit(
            _current_user.get("name", ""),
            _current_user.get("role", ""),
            "cancel",
            "work_journal",
            id,
            ("ЖПР отменен: " + str(work.get("description") or "") + "; мастер " + str(work.get("master_name") or ""))[:250],
            work.get("project") or "",
        )
        return {"ok": True, "cancelled": True, "materialsRestored": len(used), "pieceworkPreserved": piecework_count}
    except HTTPException:
        conn.rollback()
        raise
    except Exception as e:
        conn.rollback()
        raise HTTPException(status_code=500, detail=str(e))
    finally:
        cur.close()
        conn.close()

@app.post("/work-journal/{id}/ai-prefill")
def ai_prefill_work_journal(id: int, _current_user: dict = Depends(require_roles(*JOURNAL_WRITE_ROLES))):
    import openai as oa, json as j, re
    conn = get_db()
    cur = conn.cursor()
    require_work_journal_actor_access(cur, id, _current_user)
    cur.execute("""SELECT description, section_name, unit, quantity, materials_used, project, hidden_work
                   FROM work_journal WHERE id=%s""", (id,))
    row = cur.fetchone()
    if not row:
        cur.close(); conn.close()
        raise HTTPException(status_code=404, detail="запись не найдена")
    description, section_name, unit, quantity, materials_used, project, hidden_work = row
    cur.close()

    user_text = (
        "Описание работы: " + (description or "—") + "\n"
        "Раздел сметы: " + (section_name or "—") + "\n"
        "Объект: " + (project or "—") + "\n"
        "Объём: " + str(quantity or 0) + " " + (unit or "") + "\n"
        "Скрытые работы: " + ("да" if hidden_work else "нет") + "\n"
        "Использованные материалы: " + (materials_used or "—") + "\n\n"
        "Верни СТРОГО JSON с тремя полями (без markdown, без тройных кавычек):\n"
        '{"normatives": "...", "projectDocs": "...", "qualityNote": "..."}\n'
        "Где:\n"
        "- normatives: перечень применимых СНиП/СП/ГОСТ через запятую (только реально применимые к виду работ)\n"
        "- projectDocs: типовые проектные документы (разделы рабочего проекта, листы)\n"
        "- qualityNote: краткая формулировка о соответствии работ нормативной/проектной документации, "
        "официальный канцелярский русский, 1-2 предложения."
    )
    instructions = "Ты отвечаешь СТРОГО валидным JSON. Никакого markdown, никаких тройных кавычек, никакого текста до или после JSON. Только сам JSON."
    client = oa.OpenAI(api_key=YANDEX_API_KEY, base_url="https://ai.api.cloud.yandex.net/v1", project=YANDEX_FOLDER_ID)

    def _call(model_id):
        try:
            r = client.responses.create(
                model="gpt://" + YANDEX_FOLDER_ID + "/" + model_id,
                temperature=0.1, instructions=instructions, input=user_text, max_output_tokens=2000,
            )
            return (r.output_text or ""), None
        except Exception as e:
            return "", str(e)

    answer, err = _call("qwen3.6-35b-a3b/latest")
    if not (answer or "").strip():
        print("AI-PREFILL work_journal primary empty, fallback. err=" + str(err))
        answer, err = _call("yandexgpt-5.1/latest")
    if not (answer or "").strip():
        conn.close()
        raise HTTPException(status_code=502, detail="AI вернул пустой ответ: " + str(err))

    text = answer.strip()
    m = re.search(r"\{.*\}", text, re.DOTALL)
    if m:
        text = m.group(0)
    try:
        parsed = j.loads(text)
    except Exception as e:
        conn.close()
        raise HTTPException(status_code=502, detail="AI вернул невалидный JSON: " + str(e)[:200])

    normatives = (parsed.get("normatives") or "").strip()
    project_docs = (parsed.get("projectDocs") or "").strip()
    quality_note = (parsed.get("qualityNote") or "").strip()

    cur = conn.cursor()
    # qualityNote дописываем в comment (если comment пустой), нормативы и проектные доки — в свои поля
    cur.execute("""UPDATE work_journal
                   SET normatives=%s, project_docs=%s,
                       comment = CASE WHEN COALESCE(comment,'')='' THEN %s ELSE comment END,
                       ai_filled=TRUE
                   WHERE id=%s""",
                (normatives, project_docs, quality_note, id))
    conn.commit()
    cur.close(); conn.close()
    return {"ok": True, "normatives": normatives, "projectDocs": project_docs, "qualityNote": quality_note, "aiFilled": True}

# Ключевые слова скрытых работ (резерв, если ИИ недоступен) — СНиП 12-01-2004
HIDDEN_WORK_KEYWORDS = [
    "арматур","армиров","бетонир","фундамент","основани","гидроизол","пароизол","теплоизол",
    "утеплен","стяжк","засыпк","обратн","грунт","свая","сваи","ростверк","монолит","опалубк",
    "закладн","заземлен","молниезащит","кабел","проводк","электропроводк","трубопровод","разводк",
    "канализац","водопровод","дренаж","вентиляц","воздуховод","штроб","закрыт","скрыт",
    "мембран","рулонн","праймер","битум","сеткa","сетк","каркас","анкер","дюбел","примыкан",
]

def _detect_hidden_by_keywords(name):
    n = (name or "").lower()
    return any(k in n for k in HIDDEN_WORK_KEYWORDS)

@app.post("/estimates/{id}/ai-detect-hidden")
def ai_detect_hidden_works(id: int, _current_user: dict = Depends(require_roles(*ESTIMATE_WRITE_ROLES))):
    import openai as oa, json as j, re
    conn = get_db()
    cur = conn.cursor()
    require_estimate_access(cur, id, _current_user)
    cur.execute("SELECT sections_json FROM estimates WHERE id=%s", (id,))
    row = cur.fetchone()
    if not row:
        cur.close(); conn.close()
        raise HTTPException(status_code=404, detail="смета не найдена")
    try:
        sections = j.loads(row[0]) if row[0] else []
    except Exception:
        sections = []
    if not isinstance(sections, list):
        sections = []
    # Собираем уникальные названия работ
    names = []
    for sec in sections:
        section_name = sec.get("name") or ""
        for it in (sec.get("items") or []):
            if _estimate_item_type_backend(it, section_name) != "work":
                continue
            nm = (it.get("name") or "").strip()
            if nm and nm not in names:
                names.append(nm)
    if not names:
        cur.close(); conn.close()
        return {"ok": True, "count": 0, "sections": sections, "method": "empty"}

    hidden_set = set()
    method = "keywords"
    # Пытаемся через ИИ; при любой ошибке — откат на ключевые слова
    if YANDEX_API_KEY and YANDEX_FOLDER_ID:
        user_text = (
            "Ниже список наименований строительных работ из сметы. Определи, какие из них являются "
            "СКРЫТЫМИ работами, требующими оформления Акта освидетельствования скрытых работ (АОСР) по "
            "СНиП 12-01-2004 — это работы, скрываемые последующими конструкциями (земляные, фундаменты, "
            "армирование, бетонирование, гидро-/паро-/теплоизоляция, стяжки, скрытые инженерные сети — "
            "кабели/трубопроводы в стенах и полах, заземление, закладные и т.п.). Отделочные и монтажные "
            "видимые работы НЕ являются скрытыми.\n\n"
            "Список работ (JSON-массив):\n" + j.dumps(names, ensure_ascii=False) + "\n\n"
            'Верни СТРОГО JSON без markdown: {"hidden": ["точное название работы из списка", ...]}'
        )
        instructions = "Ты отвечаешь СТРОГО валидным JSON без markdown и пояснений. Только JSON."
        try:
            client = oa.OpenAI(api_key=YANDEX_API_KEY, base_url="https://ai.api.cloud.yandex.net/v1", project=YANDEX_FOLDER_ID)
            r = client.responses.create(
                model="gpt://" + YANDEX_FOLDER_ID + "/yandexgpt-5.1/latest",
                temperature=0.1, instructions=instructions, input=user_text, max_output_tokens=2000,
            )
            text = (r.output_text or "").strip()
            m = re.search(r"\{.*\}", text, re.DOTALL)
            if m:
                parsed = j.loads(m.group(0))
                arr = parsed.get("hidden") or []
                if isinstance(arr, list):
                    hidden_set = set((s or "").strip() for s in arr if isinstance(s, str))
                    method = "ai"
        except Exception as e:
            print("AI-DETECT-HIDDEN error, fallback to keywords:", str(e))

    if not hidden_set:
        hidden_set = set(nm for nm in names if _detect_hidden_by_keywords(nm))
        method = "keywords"

    # Проставляем hiddenWork=true найденным (ручные отметки не снимаем)
    count = 0
    for sec in sections:
        section_name = sec.get("name") or ""
        for it in (sec.get("items") or []):
            if _estimate_item_type_backend(it, section_name) != "work":
                continue
            nm = (it.get("name") or "").strip()
            if nm in hidden_set and not it.get("hiddenWork"):
                it["hiddenWork"] = True
                count += 1
    cur.execute("UPDATE estimates SET sections_json=%s WHERE id=%s", (j.dumps(sections, ensure_ascii=False), id))
    conn.commit()
    cur.close(); conn.close()
    return {"ok": True, "count": count, "detected": len(hidden_set), "sections": sections, "method": method}

@app.get("/master-profiles")
def get_master_profiles(current_user: dict = Depends(get_current_user)):
    conn = get_db()
    cur = conn.cursor(cursor_factory=psycopg2.extras.RealDictCursor)
    def _public_master_profile(row):
        data = dict(row)
        for key in ("passport", "inn", "bankAccount", "bankName", "ogrnip"):
            data.pop(key, None)
        return data
    if current_user.get("role") in FINANCE_ROLES:
        cur.execute("SELECT id,user_id as \"userId\",full_name as \"fullName\",passport,inn,contract_type as \"contractType\",bank_account as \"bankAccount\",bank_name as \"bankName\",phone,specialization,ogrnip,profile_completed as \"profileCompleted\" FROM master_profiles")
    elif current_user.get("role") in ("прораб", "главный_инженер"):
        allowed_projects = user_project_names(current_user)
        if not allowed_projects:
            cur.close(); conn.close()
            return []
        cur.execute("""
            SELECT mp.id,mp.user_id as "userId",mp.full_name as "fullName",mp.passport,mp.inn,
                   mp.contract_type as "contractType",mp.bank_account as "bankAccount",
                   mp.bank_name as "bankName",mp.phone,mp.specialization,mp.ogrnip,
                   mp.profile_completed as "profileCompleted"
            FROM master_profiles mp
            JOIN users u ON u.id=mp.user_id
            WHERE COALESCE(u.project_name,'') = ANY(%s)
               OR EXISTS (
                   SELECT 1 FROM jsonb_array_elements_text(COALESCE(u.assigned_projects,'[]'::jsonb)) ap(project_name)
                   WHERE ap.project_name = ANY(%s)
               )
            ORDER BY mp.id DESC
        """, (allowed_projects, allowed_projects))
    elif current_user.get("role") in WORKER_EXECUTION_ROLES:
        cur.execute("SELECT id,user_id as \"userId\",full_name as \"fullName\",passport,inn,contract_type as \"contractType\",bank_account as \"bankAccount\",bank_name as \"bankName\",phone,specialization,ogrnip,profile_completed as \"profileCompleted\" FROM master_profiles WHERE user_id=%s", (current_user.get("id"),))
    else:
        cur.close(); conn.close()
        return []
    rows = cur.fetchall()
    conn.close()
    if current_user.get("role") in ("прораб", "главный_инженер"):
        return [_public_master_profile(r) for r in rows]
    return [dict(r) for r in rows]

