@app.post("/parse-smeta")
async def parse_smeta(file: UploadFile = File(...)):
    import tempfile, os, re
    try:
        import openpyxl
    except ImportError:
        return {"error": "openpyxl not installed"}
    
    contents = await file.read()
    with tempfile.NamedTemporaryFile(delete=False, suffix=".xlsx") as tmp:
        tmp.write(contents)
        tmp_path = tmp.name
    
    try:
        wb = openpyxl.load_workbook(tmp_path, data_only=True)
        ws = wb.active
        results = []
        current_section = "Без раздела"
        data_start_row = 1
        file_type = "unknown"
        header_rows = list(ws.iter_rows(max_row=80, values_only=True))
        lsr_header_row_idx = None
        
        for i, row in enumerate(header_rows[:60]):
            vals = [str(v).strip() for v in row if v is not None]
            row_text = " ".join(vals).lower()
            is_lsr_table_header = (
                "обоснование" in row_text
                and "наименование" in row_text
                and ("работ" in row_text or "затрат" in row_text)
                and ("единица" in row_text or "измерения" in row_text)
                and "количество" in row_text
            )
            is_lsr_number_header = (
                "№" in row_text
                and "обоснование" in row_text
                and "наименование" in row_text
                and ("единица" in row_text or "количество" in row_text)
            )
            if "номер сметы" in row_text and "стоимость всего" in row_text and ("цена на единицу" in row_text or "цена на" in row_text):
                data_start_row = i + 2
                file_type = "contract"
                break
            elif is_lsr_table_header or is_lsr_number_header:
                data_start_row = i + 2
                file_type = "lsr"
                lsr_header_row_idx = i
                break
            elif "наименование" in row_text and ("работ" in row_text or "затрат" in row_text) and ("единица" in row_text or "количество" in row_text) and ("сметн" in row_text or "стоим" in row_text):
                data_start_row = i + 2
                file_type = "lsr"
                lsr_header_row_idx = i
                break
            elif "наименование" in row_text and "ед" in row_text and "кол" in row_text and "обоснование" not in row_text:
                data_start_row = i + 2
                file_type = "defect"
                break
            elif "обоснование" in row_text and "наименование" in row_text and "общее" in row_text:
                data_start_row = i + 2
                file_type = "vedomost"
                break
        
        work_prefixes = ["ГЭСНм", "ФЕРм", "ТЕРм", "ГЭСНи", "ФЕРи", "ГЭСНр", "ФЕРр", "ТЕРр", "ГЭСН", "ФЕР", "ТЕР"]
        material_prefixes = ["ФСБЦ", "ФССЦ", "ТССЦ", "ТССЦпг", "ТЦ_", "ТЦ-", "КАЦ", "МАТ"]
        work_words = ("монтаж", "демонтаж", "установка", "устройство", "прокладка", "разбор", "разборка", "сборка", "замена", "подключение", "снятие", "очистка", "ремонт", "отбивка", "облицов", "окраск", "шпатлев", "шпаклев", "грунтов", "стяжк", "укладка")
        material_words = ("материал", "труба", "кабель", "провод", "смесь", "раствор", "ротбанд", "кнауф", "штукатурка", "штукатурк", "шпатлевка", "шпатлевк", "шпаклевка", "шпаклевк", "клей", "краска", "акрил", "грунтовка", "цемент", "бетон", "кирпич", "блок", "лист", "профиль", "саморез", "шуруп", "анкер", "болт", "гайк", "шайб", "плитка", "плитк", "керамическ", "керамогранит", "гранит", "livorno", "ливорно", "axima", "аксима", "линолеум", "арматур", "битум", "бризол", "лак", "мастик", "утеплитель", "рубероид", "пвх", "уголок", "уголк", "угол", "подвес", "маяк", "рейк", "лента", "серпян", "панель", "плинтус", "наличник", "дюбел", "втулк", "скреп", "крепеж", "металлочереп", "черепиц", "монтеррей", "кровл", "кроншт", "направл", "фитинг", "муфт", "клапан", "американ", "воздухоотвод", "радиатор", "светиль", "ламп", "розет", "выключ", "доска", "брус", "фанер", "осп", "osb", "гвозд", "шпил", "перфолента")
        lsr_service_tokens = (
            "итого", "всего", "в том числе", "объем=", "объём=",
            "фот", "средства на оплату труда", "нормативные затраты труда",
            "накладные расходы", "сметная прибыль", "индекс", "индексы",
            "коэффициент к итогам", "коэффициенты к итогам",
            "заготовительно-складские", "заготовительно складские",
            "справочно", "начисление", "начисления",
            "вспомогательные ненормируемые"
        )

        def _lsr_text_key(value):
            return str(value or "").lower().replace("ё", "е").replace("\xa0", " ").strip()

        def _detect_lsr_columns(rows, header_idx):
            columns = {
                "num": 0,
                "obosn": 1,
                "name": 2,
                "unit": 3,
                "quantity_base": 4,
                "quantity_coeff": 5,
                "quantity_final": 6,
            }
            if header_idx is None:
                return columns

            start = max(0, header_idx - 2)
            end = min(len(rows), header_idx + 6)
            scan_rows = rows[start:end]

            for row in scan_rows:
                for idx, value in enumerate(row):
                    key = _lsr_text_key(value).replace("\n", " ")
                    if "обоснование" in key:
                        columns["obosn"] = idx
                    if "наименование" in key and ("работ" in key or "затрат" in key):
                        columns["name"] = idx
                    if "единица" in key and "измер" in key:
                        columns["unit"] = idx

            unit_idx = columns.get("unit")
            if unit_idx is not None:
                columns.setdefault("quantity_base", unit_idx + 1)
                columns.setdefault("quantity_coeff", unit_idx + 2)
                columns.setdefault("quantity_final", unit_idx + 3)
                columns["quantity_base"] = unit_idx + 1
                columns["quantity_coeff"] = unit_idx + 2
                columns["quantity_final"] = unit_idx + 3

            for row in scan_rows:
                seen_cost_unit = False
                for idx, value in enumerate(row):
                    key = _lsr_text_key(value).replace("\n", " ")
                    compact = re.sub(r"\s+", " ", key)
                    if "на единицу" in compact:
                        if idx <= columns.get("quantity_final", 6):
                            columns["quantity_base"] = idx
                        elif not seen_cost_unit:
                            columns["cost_unit"] = idx
                            seen_cost_unit = True
                    elif "всего" in compact:
                        if "учет" in compact and "коэффициент" in compact:
                            columns["quantity_final"] = idx
                        elif idx > columns.get("quantity_final", 6) and "cost_total" not in columns:
                            columns["cost_total"] = idx
                    elif "коэффициент" in compact and "сметн" not in compact:
                        if idx < columns.get("quantity_final", 6):
                            columns["quantity_coeff"] = idx
                        elif "cost_coeff" not in columns:
                            columns["cost_coeff"] = idx
                    elif "индекс" in compact:
                        columns["cost_index"] = idx

            qf = columns.get("quantity_final", 6)
            if "cost_unit" not in columns:
                columns["cost_unit"] = qf + 1
            if "cost_coeff" not in columns:
                columns["cost_coeff"] = columns["cost_unit"] + 1
            if "cost_total" not in columns:
                columns["cost_total"] = columns["cost_coeff"] + 1
            if "cost_index" not in columns:
                columns["cost_index"] = columns["cost_total"] + 1
            if "cost_current_total" not in columns:
                columns["cost_current_total"] = columns["cost_index"] + 1
            return columns

        lsr_columns = _detect_lsr_columns(header_rows, lsr_header_row_idx) if file_type == "lsr" else {}

        def _is_lsr_service_row(name_value, obosn_value=""):
            name_key = _lsr_text_key(name_value)
            code_key = _lsr_text_key(obosn_value)
            if not name_key:
                return True
            if "пр/" in code_key or "648/" in code_key:
                return True
            if any(token in name_key for token in lsr_service_tokens):
                return True
            return False

        def _lsr_item_type(obosn_value, name_value):
            code = str(obosn_value or "").strip()
            name_key = _lsr_text_key(name_value)
            if any(code.startswith(x) for x in work_prefixes):
                return "work"
            if any(code.startswith(x) for x in material_prefixes):
                return "material"
            if re.match(r"^\d{2,}[-/]\d+", code) or re.match(r"^\d{3,}$", code):
                return "material"
            if any(word in name_key for word in work_words):
                return "work"
            if any(word in name_key for word in material_words):
                return "material"
            return "material"

        def _lsr_name_looks_resource(name_value):
            name_key = _lsr_text_key(name_value)
            if not name_key:
                return False
            work_starts = (
                "монтаж", "демонтаж", "устройство", "установка", "разбор",
                "разборка", "снятие", "очистка", "отбивка", "облицовка",
                "окраска", "грунтование", "штукатурка поверхностей", "стяжка",
                "смена", "прокладка", "подключение", "ремонт"
            )
            if any(name_key.startswith(prefix) for prefix in work_starts):
                return False
            return any(word in name_key for word in material_words)

        def _lsr_code_is_resource(obosn_value):
            code = str(obosn_value or "").strip()
            return (
                any(code.startswith(x) for x in material_prefixes)
                or re.match(r"^\d{2,}[-/]\d+", code)
                or re.match(r"^\d{3,}$", code)
            )

        def _infer_lsr_unit(unit_value, name_value, item_type):
            raw = str(unit_value or "").strip()
            compact = raw.lower().replace(" ", "")
            if raw and compact not in ("1", "ед", "ед.", "единица"):
                return _normalize_lsr_unit_text(raw)
            name_key = _lsr_text_key(name_value)
            if item_type == "material":
                if any(w in name_key for w in ("смесь", "штукатурная", "шпатлевка", "шпатлевк", "шпаклевка", "шпаклевк", "клей", "затирка", "цемент", "пескобетон", "сухая смесь")):
                    return "кг"
                if any(w in name_key for w in ("краска", "грунтовка", "эмаль", "лак", "акрил")):
                    return "кг"
                if any(w in name_key for w in ("уголок", "уголк", "угол", "плинтус", "наличник", "кабель", "провод", "труба", "трубопровод", "лоток", "короб", "профиль", "маяк", "подоконник")):
                    return "м"
                if any(w in name_key for w in ("плитк", "керамогранит", "гранит", "линолеум", "покрытие пола", "обои", "лист гипсокартон", "листы гипсокартон", "гкл", "панель", "плита")):
                    return "м2"
                if any(w in name_key for w in ("кирпич", "блок", "саморез", "дюбель", "гвозд", "светильник", "розетка", "выключатель", "прибор", "радиатор", "решетк")):
                    return "шт"
            if any(w in name_key for w in ("розет", "выключател", "светильник", "табло", "прибор", "радиатор", "решетк", "унитаз", "раковин", "смесител", "коробка", "шкаф", "стол")):
                return "шт"
            if any(w in name_key for w in ("уголок", "уголк", "угол", "плинтус", "наличник", "кабель", "провод", "труба", "трубопровод", "лоток", "короб", "профиль", "маяк", "подоконник")):
                return "м"
            if any(w in name_key for w in ("бетон", "брус", "каркас из брус")):
                return "м3"
            if item_type == "work" and any(w in name_key for w in ("поверхност", "фасад", "стен", "перегород", "потол", "обои", "облицов", "окраск", "штукатур", "шпатлев", "шпаклев", "грунтов", "плитк", "керамогранит", "гранит", "линолеум", "покрытие пола", "гкл", "гипсокартон", "сетка")):
                return "100 м2"
            return "шт"

        def _row_float(value):
            if value is None:
                return None
            if isinstance(value, (int, float)):
                return float(value)
            text = str(value).strip().replace("\xa0", " ")
            if not text:
                return None
            compact = text.replace(" ", "").replace(",", ".")
            if re.match(r"^\([+-]?\d+(?:\.\d+)?\)$", compact):
                compact = "-" + compact.strip("()").lstrip("+")
            if not re.match(r"^[+-]?\d+(?:\.\d+)?$", compact):
                return None
            try:
                return float(compact)
            except Exception:
                return None

        def _money_candidates_from_text(value):
            text = str(value or "").replace("\xa0", " ")
            candidates = []
            for match in re.finditer(r"(?<!\d)(?:\d[\d\s]{3,}\d)(?:[,.]\d{1,2})?(?!\d)", text):
                raw = match.group(0).replace(" ", "").replace(",", ".")
                try:
                    amount = abs(float(raw))
                except Exception:
                    continue
                if 1000 <= amount < 1000000000000:
                    candidates.append(amount)
            for match in re.finditer(r"(?<![\w-])(?:\d{1,3}(?:\s+\d{3})+|\d{5,})(?:[,.]\d{1,2})?(?![\w-])", text):
                raw = match.group(0).replace(" ", "").replace(",", ".")
                try:
                    amount = abs(float(raw))
                except Exception:
                    continue
                if 1000 <= amount < 1000000000000:
                    candidates.append(amount)
            return candidates

        def _extract_declared_estimate_total():
            file_candidates = _money_candidates_from_text(file.filename or "")
            if file_candidates:
                return round(max(file_candidates), 2), "filename"
            summary_candidates = []
            summary_tokens = ("сметн", "итого", "всего", "стоимость", "стоимост", "руб")
            for row in ws.iter_rows(values_only=True):
                row_text = " ".join(str(v) for v in row if v is not None).lower().replace("ё", "е")
                if not any(token in row_text for token in summary_tokens):
                    continue
                for value in row:
                    if isinstance(value, (int, float)) and 1000 <= abs(float(value)) < 1000000000000:
                        summary_candidates.append(abs(float(value)))
                    elif isinstance(value, str):
                        summary_candidates.extend(_money_candidates_from_text(value))
            if summary_candidates:
                return round(max(summary_candidates), 2), "workbook"
            return 0, ""

        def _lsr_items_total(items):
            return round(sum(float(item.get("total") or 0) for item in items if item.get("type") in ("work", "material", "equipment", "transport", "overhead", "adjustment")), 2)

        def _declared_total_diagnostics(items, declared_total, declared_source):
            parsed_total = _lsr_items_total(items)
            factor = (declared_total / parsed_total) if declared_total and parsed_total > 0 else 1
            difference = (declared_total - parsed_total) if declared_total and parsed_total > 0 else 0
            mismatch = bool(declared_total and parsed_total > 0 and abs(difference) > max(1000, declared_total * 0.01))
            meta = {
                "declaredTotal": declared_total,
                "declaredTotalSource": declared_source,
                "parsedTotal": parsed_total,
                "difference": round(difference, 2),
                "diagnosticFactor": round(factor, 8),
                "totalMismatch": mismatch,
                "scaleApplied": False,
            }
            return meta

        def _normalize_lsr_unit_text(value):
            text = str(value or "").strip().replace("\xa0", " ")
            text = re.sub(r"\s+", " ", text)
            text = text.replace("м²", "м2").replace("М²", "м2").replace("м³", "м3").replace("М³", "м3")
            compact = text.lower().replace(" ", "").replace(".", "")
            single_unit = re.match(r"^1\s*(шт\.?|м2|м3|м|кг|т|л)$", text.lower())
            if single_unit:
                return _normalize_lsr_unit_text(single_unit.group(1))
            if not re.match(r"^\d", compact):
                if compact.startswith("маш"):
                    return "маш-ч"
                if compact.startswith("чел"):
                    return "чел-ч"
                if compact.startswith("м2"):
                    return "м2"
                if compact.startswith("м3"):
                    return "м3"
                if compact.startswith(("мп", "пм", "м/п", "м")):
                    return "м"
                if compact.startswith("шт"):
                    return "шт"
                if compact.startswith("кг"):
                    return "кг"
                if compact.startswith("т"):
                    return "т"
                if compact.startswith("л"):
                    return "л"
            return text

        def _looks_lsr_unit(value):
            text = _normalize_lsr_unit_text(value).lower().replace(" ", "")
            if not text or text in ("1", "ед", "ед.", "единица"):
                return False
            units = ("шт", "м", "м2", "м3", "кг", "т", "л", "рулон", "лист", "упак", "компл", "маш-ч", "чел-ч")
            if text in units:
                return True
            return bool(re.match(r"^\d+(м2|м3|маш-ч|чел-ч|шт|кг|рулон|лист|упак|компл|м|т|л)", text))

        def _normalize_lsr_measure(qty, unit):
            raw_unit = _normalize_lsr_unit_text(unit)
            raw_qty = qty if qty is not None else 0
            m = re.match(r"^(\d{2,})\s*(.+)$", raw_unit)
            if not m:
                return float(raw_qty or 0), raw_unit, 1
            factor = int(m.group(1) or 1)
            if factor < 10:
                return float(raw_qty or 0), _normalize_lsr_unit_text(m.group(2)), 1
            return float(raw_qty or 0) * factor, _normalize_lsr_unit_text(m.group(2)), factor

        def _pick_lsr_unit_and_quantity(row, fallback_unit, fallback_qty, preferred_unit_idx=None,
                                        quantity_base_idx=None, quantity_coeff_idx=None, quantity_final_idx=None):
            found_unit = None
            found_idx = None
            quantity_base = None
            quantity_coeff = None
            quantity_final = None
            if preferred_unit_idx is not None and len(row) > preferred_unit_idx and _looks_lsr_unit(row[preferred_unit_idx]):
                found_unit = _normalize_lsr_unit_text(row[preferred_unit_idx])
                found_idx = preferred_unit_idx
            elif preferred_unit_idx is None:
                # Если колонка единицы не определена, ищем только в начале строки ЛСР.
                # В хвосте строки встречаются единицы ресурсов/труда ("т", "чел-ч"),
                # их нельзя принимать за единицу самой работы.
                for idx, value in enumerate(row[:10]):
                    if _looks_lsr_unit(value):
                        found_unit = _normalize_lsr_unit_text(value)
                        found_idx = idx
                        break
            unit = found_unit or fallback_unit
            qty = fallback_qty

            def _num_at(idx):
                if idx is None or idx < 0 or len(row) <= idx:
                    return None
                return _row_float(row[idx])

            quantity_base = _num_at(quantity_base_idx)
            quantity_coeff = _num_at(quantity_coeff_idx)
            quantity_final = _num_at(quantity_final_idx)
            if quantity_final is not None:
                qty = quantity_final
            elif quantity_base is not None:
                qty = quantity_base

            if quantity_base is None and quantity_final is None and found_idx is not None:
                nums = []
                for idx in range(found_idx + 1, min(len(row), found_idx + 6)):
                    n = _row_float(row[idx])
                    if n is not None:
                        nums.append(n)
                quantity_base = nums[0] if len(nums) >= 1 else None
                quantity_coeff = nums[1] if len(nums) >= 2 else None
                quantity_final = nums[2] if len(nums) >= 3 else None
                if len(nums) >= 3 and abs(nums[2]) > 0.0001:
                    qty = nums[2]
                elif nums:
                    qty = nums[0]
            normalized_qty, normalized_unit, factor = _normalize_lsr_measure(qty, unit)
            return normalized_unit, normalized_qty, unit, qty, factor, found_idx, quantity_base, quantity_coeff, quantity_final

        def _pick_lsr_sum(row, preferred_indexes=(), unit_idx=None):
            max_line_total = 1000000000000
            if unit_idx is not None:
                after_unit = []
                for idx in range(unit_idx + 1, len(row)):
                    n = _row_float(row[idx])
                    if n is not None and 0.0001 < abs(n) < max_line_total:
                        after_unit.append((idx, n))
                # В ЛСР после единицы обычно идут: объем на единицу, коэффициент,
                # итоговый объем, затем денежная часть. Первые 3 числа не считаем суммой.
                money_candidates = [item for item in after_unit[3:] if abs(item[1]) >= 1]
                if money_candidates:
                    return round(max(money_candidates, key=lambda item: abs(item[1]))[1], 2)
            for idx in preferred_indexes:
                if len(row) > idx:
                    n = _row_float(row[idx])
                    if n is not None and 0.0001 < abs(n) < max_line_total:
                        return round(n, 2)
            candidates = []
            start_idx = max(6, (unit_idx + 4) if unit_idx is not None else 6)
            for idx, value in enumerate(row):
                if idx < start_idx:
                    continue
                n = _row_float(value)
                if n is not None and 0.0001 < abs(n) < max_line_total:
                    candidates.append((idx, n))
            if not candidates:
                return 0
            money_candidates = [item for item in candidates if abs(item[1]) >= 1]
            if money_candidates:
                return round(max(money_candidates, key=lambda item: abs(item[1]))[1], 2)
            return round(candidates[-1][1], 2)

        def _cell_float(row, idx):
            if idx is None or idx < 0 or len(row) <= idx:
                return None
            return _row_float(row[idx])

        def _valid_lsr_money(value):
            return value is not None and 0.0001 < abs(float(value)) < 1000000000000

        def _pick_lsr_money(row, columns, unit_idx=None):
            base_unit_price = _cell_float(row, columns.get("cost_unit"))
            cost_coeff = _cell_float(row, columns.get("cost_coeff"))
            base_total = _cell_float(row, columns.get("cost_total"))
            cost_index = _cell_float(row, columns.get("cost_index"))
            current_total = _cell_float(row, columns.get("cost_current_total"))
            quantity_final = _cell_float(row, columns.get("quantity_final"))

            result = {
                "baseUnitPrice": round(float(base_unit_price), 6) if base_unit_price is not None else None,
                "costCoefficient": round(float(cost_coeff), 6) if cost_coeff is not None else None,
                "baseTotal": round(float(base_total), 2) if base_total is not None else None,
                "costIndex": round(float(cost_index), 6) if cost_index is not None else None,
                "currentTotal": round(float(current_total), 2) if current_total is not None else None,
                "lineTotalSource": "",
                "lineTotal": 0,
            }

            if _valid_lsr_money(current_total):
                if _valid_lsr_money(base_total) and cost_index not in (None, 0):
                    expected = float(base_total) * float(cost_index)
                    if abs(float(current_total) - expected) <= max(1, abs(expected) * 0.03):
                        result["lineTotal"] = round(float(current_total), 2)
                        result["lineTotalSource"] = "current_total"
                        return result
                elif not _valid_lsr_money(base_total) or abs(float(current_total)) >= abs(float(base_total)):
                    result["lineTotal"] = round(float(current_total), 2)
                    result["lineTotalSource"] = "current_total"
                    return result

            if _valid_lsr_money(base_total) and cost_index not in (None, 0) and 0.0001 < abs(float(cost_index)) < 1000:
                result["lineTotal"] = round(float(base_total) * float(cost_index), 2)
                result["lineTotalSource"] = "base_total_x_index"
                return result

            if _valid_lsr_money(base_total):
                result["lineTotal"] = round(float(base_total), 2)
                result["lineTotalSource"] = "base_total"
                return result

            if base_unit_price is not None and quantity_final is not None:
                coeff = float(cost_coeff) if cost_coeff not in (None, 0) else 1
                result["lineTotal"] = round(float(base_unit_price) * coeff * float(quantity_final), 2)
                result["lineTotalSource"] = "unit_price_x_quantity"
                return result

            fallback = _pick_lsr_sum(row, (), unit_idx)
            result["lineTotal"] = fallback
            result["lineTotalSource"] = "fallback_scan" if fallback else ""
            return result

        def _lsr_summary_indexes(columns):
            idx_col = columns.get("cost_index", 12)
            name_idx = columns.get("name", 2)
            indexes = {}
            for row in ws.iter_rows(min_row=max(1, ws.max_row - 260), values_only=True):
                name = _lsr_text_key(row[name_idx] if len(row) > name_idx else "")
                idx_value = _row_float(row[idx_col]) if idx_col is not None and len(row) > idx_col else None
                if idx_value is None or idx_value <= 1:
                    continue
                if "материал" in name:
                    indexes["material"] = float(idx_value)
                elif "эксплуатация машин" in name or "машин" in name or "механизм" in name:
                    indexes["machine"] = float(idx_value)
                    indexes.setdefault("transport", float(idx_value))
                elif "оборудован" in name:
                    indexes["equipment"] = float(idx_value)
                elif "перевоз" in name or "транспорт" in name:
                    indexes["transport"] = float(idx_value)
            return indexes

        lsr_indexes = _lsr_summary_indexes(lsr_columns) if file_type == "lsr" else {}

        def _lsr_cost_kind(name_value):
            key = _lsr_text_key(name_value)
            compact = key.replace(" ", "")
            if compact in ("от",):
                return "labor"
            if compact in ("эм",):
                return "machine"
            if compact == "м":
                return "material_total"
            if key.startswith("нр "):
                return "overhead"
            if key.startswith("сп "):
                return "profit"
            if compact in ("зт", "зтм", "фот") or key.startswith("в т.ч.") or key.startswith("в том числе") or "итого по расценке" in key:
                return "skip"
            return ""

        def _lsr_index_for_kind(kind, name_value="", code_value=""):
            text = _lsr_text_key(str(name_value or "") + " " + str(code_value or ""))
            if kind in ("machine",):
                return lsr_indexes.get("machine") or lsr_indexes.get("transport") or 1
            if kind in ("equipment",):
                return lsr_indexes.get("equipment") or lsr_indexes.get("material") or 1
            if kind in ("transport",):
                return lsr_indexes.get("transport") or lsr_indexes.get("machine") or 1
            if kind in ("material", "material_total"):
                return lsr_indexes.get("material") or 1
            if "эксплуатация машин" in text or "машин" in text or "механизм" in text:
                return lsr_indexes.get("machine") or 1
            if "материал" in text:
                return lsr_indexes.get("material") or 1
            return 1

        def _lsr_money_with_index(row, columns, unit_idx=None, kind="material", name_value="", code_value=""):
            money = _pick_lsr_money(row, columns, unit_idx)
            line = float(money.get("lineTotal") or 0)
            source = money.get("lineTotalSource") or ""
            base_total = money.get("baseTotal")
            if (not line or source in ("base_total", "fallback_scan", "")) and _valid_lsr_money(base_total):
                idx = money.get("costIndex") or _lsr_index_for_kind(kind, name_value, code_value)
                if idx and abs(float(idx)) > 1.0001:
                    money["lineTotal"] = round(float(base_total) * float(idx), 2)
                    money["currentTotal"] = money["lineTotal"]
                    money["costIndex"] = round(float(idx), 6)
                    money["lineTotalSource"] = "base_total_x_summary_index"
                else:
                    money["lineTotal"] = round(float(base_total), 2)
                    money["lineTotalSource"] = source or "base_total"
            return money

        def _add_imported_work_amount(item_idx, amount, component_key):
            if item_idx is None or item_idx < 0 or item_idx >= len(results):
                return
            amount = float(amount or 0)
            item = results[item_idx]
            item["totalWork"] = round(float(item.get("totalWork") or 0) + amount, 2)
            item["total"] = round(float(item.get("total") or 0) + amount, 2)
            item["lineTotal"] = round(float(item.get("lineTotal") or 0) + amount, 2)
            components = item.setdefault("costComponents", {})
            components[component_key] = round(float(components.get(component_key) or 0) + amount, 2)

        def _lsr_work_key(section, code, name, row_index):
            raw = "|".join([
                str(section or ""),
                str(code or ""),
                str(name or ""),
                str(row_index or ""),
            ]).lower().replace("ё", "е")
            return re.sub(r"[^a-zа-я0-9]+", "-", raw).strip("-")[:160]
        
        last_work_result_idx = None
        current_work_ref = None
        for i, row in enumerate(ws.iter_rows(min_row=data_start_row, values_only=True)):
            try:
                num_idx = lsr_columns.get("num", 0) if file_type == "lsr" else 0
                obosn_idx = lsr_columns.get("obosn", 1) if file_type == "lsr" else 1
                name_idx = lsr_columns.get("name", 2) if file_type == "lsr" else 2
                first_val = str(row[0]).strip() if row[0] is not None else ""
                name_col = str(row[name_idx]).strip() if len(row) > name_idx and row[name_idx] else ""
                obosn = str(row[obosn_idx]).strip() if len(row) > obosn_idx and row[obosn_idx] else ""
                
                if "Раздел" in first_val or "РАЗДЕЛ" in first_val:
                    current_section = first_val
                    continue
                
                if file_type == "lsr":
                    num = row[num_idx] if len(row) > num_idx else None
                    num_is_main = False
                    if num not in (None, ""):
                        try:
                            float(str(num).strip())
                            num_is_main = True
                        except:
                            num_is_main = bool(re.match(r"^\s*\d+", str(num)))

                    if "Всего по позиции" in name_col:
                        if last_work_result_idx is not None and 0 <= last_work_result_idx < len(results):
                            try:
                                v = _pick_lsr_sum(row, (13, 14, 15, 16, 17))
                                if v:
                                    results[last_work_result_idx]["positionBaseTotal"] = round(float(v), 2)
                            except:
                                pass
                        continue

                    cost_kind = _lsr_cost_kind(name_col)
                    if not num_is_main and current_work_ref and cost_kind:
                        if cost_kind == "skip":
                            continue
                        money = _lsr_money_with_index(row, lsr_columns, None, cost_kind, name_col, obosn)
                        line_money = float(money.get("lineTotal") or 0)
                        if cost_kind == "material_total":
                            if int(current_work_ref.get("resourceCount") or 0) == 0 and abs(line_money) > 0.0001:
                                agg_item = {
                                    "section": current_section,
                                    "name": "Материалы по позиции: " + current_work_ref.get("workName", ""),
                                    "unit": "компл",
                                    "quantity": 1,
                                    "rawUnit": "компл",
                                    "rawQuantity": 1,
                                    "unitFactor": 1,
                                    "baseUnitPrice": money.get("baseUnitPrice"),
                                    "costCoefficient": money.get("costCoefficient"),
                                    "baseTotal": money.get("baseTotal"),
                                    "costIndex": money.get("costIndex"),
                                    "currentTotal": money.get("currentTotal"),
                                    "lineTotalSource": money.get("lineTotalSource"),
                                    "lineTotal": line_money,
                                    "total": line_money,
                                    "totalWork": 0,
                                    "totalMaterial": line_money,
                                    "type": "material",
                                    "sourceCode": obosn,
                                    "parentWorkKey": current_work_ref.get("workKey"),
                                    "parentWorkName": current_work_ref.get("workName"),
                                    "parentWorkSourceCode": current_work_ref.get("workSourceCode"),
                                    "resourceRole": "material",
                                    "importKind": "aggregate_material",
                                }
                                results.append(agg_item)
                                current_work_ref["resourceCount"] = int(current_work_ref.get("resourceCount") or 0) + 1
                            continue
                        if abs(line_money) > 0.0001:
                            _add_imported_work_amount(last_work_result_idx, line_money, cost_kind)
                        continue

                    if not name_col:
                        continue

                    if not num_is_main:
                        # Дочерние ресурсные строки внутри позиции: материалы, оборудование, перевозка.
                        if not current_work_ref or _is_lsr_service_row(name_col, obosn) or not _lsr_code_is_resource(obosn):
                            continue
                        item_type = _lsr_item_type(obosn, name_col)
                        if item_type == "work":
                            if _lsr_name_looks_resource(name_col):
                                item_type = "material"
                            else:
                                continue
                    else:
                        if len(name_col) < 5 or _is_lsr_service_row(name_col, obosn):
                            continue
                        item_type = _lsr_item_type(obosn, name_col)

                    unit_idx_hint = lsr_columns.get("unit")
                    qty_base_idx = lsr_columns.get("quantity_base")
                    qty_coeff_idx = lsr_columns.get("quantity_coeff")
                    qty_final_idx = lsr_columns.get("quantity_final")
                    unit_raw = str(row[unit_idx_hint]).strip() if unit_idx_hint is not None and len(row) > unit_idx_hint and row[unit_idx_hint] else "шт"
                    inferred_unit = _infer_lsr_unit(unit_raw, name_col, item_type)
                    raw_qty = _row_float(row[qty_final_idx]) if qty_final_idx is not None and len(row) > qty_final_idx else None
                    if raw_qty is None and qty_base_idx is not None and len(row) > qty_base_idx:
                        raw_qty = _row_float(row[qty_base_idx])
                    raw_qty = raw_qty if raw_qty is not None else 0
                    unit, qty, raw_unit, raw_qty, unit_factor, unit_idx, quantity_base, quantity_coeff, quantity_final = _pick_lsr_unit_and_quantity(
                        row,
                        inferred_unit,
                        raw_qty,
                        unit_idx_hint,
                        qty_base_idx,
                        qty_coeff_idx,
                        qty_final_idx,
                    )

                    money = _lsr_money_with_index(row, lsr_columns, unit_idx, item_type, name_col, obosn)
                    line_money = float(money.get("lineTotal") or 0)
                    resource_item_type = item_type
                    is_negative_line = float(qty or 0) < -0.0001 or line_money < 0
                    is_resource_adjustment = is_negative_line and (
                        item_type in ("material", "equipment", "transport")
                        or (item_type == "work" and _lsr_name_looks_resource(name_col))
                    )
                    if is_resource_adjustment and item_type == "work":
                        resource_item_type = "material"
                    if is_resource_adjustment:
                        item_type = "adjustment"
                    work_total = line_money if item_type == "work" else 0
                    mat_total = line_money if item_type in ("material", "equipment", "transport") else 0
                    line_total = line_money if is_resource_adjustment else (mat_total if item_type in ("material", "equipment", "transport") else work_total)
                    if resource_item_type in ("material", "equipment", "transport") and not is_resource_adjustment and abs(float(qty or 0)) <= 0.0001 and abs(line_total) <= 0.0001:
                        continue

                    item = {
                        "section": current_section,
                        "name": name_col,
                        "unit": unit,
                        "quantity": round(qty, 4),
                        "rawUnit": raw_unit,
                        "rawQuantity": round(float(raw_qty or 0), 4),
                        "unitFactor": unit_factor,
                        "quantityBase": round(float(quantity_base), 4) if quantity_base is not None else None,
                        "quantityCoefficient": round(float(quantity_coeff), 6) if quantity_coeff is not None else None,
                        "quantityFinal": round(float(quantity_final), 4) if quantity_final is not None else None,
                        "baseUnitPrice": money.get("baseUnitPrice"),
                        "costCoefficient": money.get("costCoefficient"),
                        "baseTotal": money.get("baseTotal"),
                        "costIndex": money.get("costIndex"),
                        "currentTotal": money.get("currentTotal"),
                        "lineTotalSource": money.get("lineTotalSource"),
                        "lineTotal": line_total,
                        "total": line_total,
                        "totalWork": work_total if item_type == "work" else 0,
                        "totalMaterial": mat_total if item_type in ("material", "equipment", "transport") else 0,
                        "type": item_type,
                        "sourceCode": obosn
                    }
                    if item_type == "work":
                        work_key = _lsr_work_key(current_section, obosn, name_col, i)
                        current_work_ref = {
                            "workKey": work_key,
                            "workName": name_col,
                            "workSourceCode": obosn,
                            "resourceCount": 0,
                        }
                        item.update(current_work_ref)
                    elif resource_item_type in ("material", "equipment", "transport") and current_work_ref:
                        item.update({
                            "parentWorkKey": current_work_ref.get("workKey"),
                            "parentWorkName": current_work_ref.get("workName"),
                            "parentWorkSourceCode": current_work_ref.get("workSourceCode"),
                            "resourceRole": resource_item_type,
                            "importKind": "resource_adjustment" if is_resource_adjustment else "resource",
                        })
                        current_work_ref["resourceCount"] = int(current_work_ref.get("resourceCount") or 0) + 1
                    results.append(item)
                    if item_type == "work":
                        last_work_result_idx = len(results) - 1

                elif file_type == "contract":
                    num = row[0] if len(row) > 0 else None
                    first_val = str(num or "").strip()
                    num_is_main = False
                    if num not in (None, ""):
                        try:
                            float(str(num).strip())
                            num_is_main = True
                        except:
                            num_is_main = bool(re.match(r"^\s*\d+", str(num)))

                    if not num_is_main:
                        label = first_val
                        if label and label not in ("1", "2", "3", "4", "5", "6", "7", "8") and "№" not in label and "наименование" not in label.lower():
                            current_section = label
                        continue

                    name = str((row[4] if len(row) > 4 and row[4] else (row[2] if len(row) > 2 else "")) or "").strip()
                    if not name or len(name) < 5:
                        continue
                    source_code = str(row[1]).strip() if len(row) > 1 and row[1] else ""
                    raw_unit = str((row[7] if len(row) > 7 and row[7] else (row[3] if len(row) > 3 else "шт")) or "шт").strip()
                    raw_qty = _row_float(row[8]) if len(row) > 8 and row[8] is not None else (_row_float(row[4]) if len(row) > 4 else 0)
                    unit_qty, unit, unit_factor = _normalize_lsr_measure(raw_qty or 0, raw_unit)
                    unit_price = _row_float(row[9]) if len(row) > 9 and row[9] is not None else (_row_float(row[5]) if len(row) > 5 else None)
                    total = _row_float(row[10]) if len(row) > 10 and row[10] is not None else (_row_float(row[6]) if len(row) > 6 else None)
                    if total is None and unit_price is not None:
                        total = float(unit_price) * float(raw_qty or 0)
                    total = round(float(total or 0), 2)
                    item_type = "material" if _lsr_name_looks_resource(name) else "work"
                    is_resource_adjustment = item_type == "material" and (
                        float(unit_qty or 0) < -0.0001 or total < 0
                    )
                    if is_resource_adjustment:
                        item_type = "adjustment"
                    results.append({
                        "section": current_section,
                        "name": name,
                        "unit": unit,
                        "quantity": round(float(unit_qty or 0), 4),
                        "rawUnit": raw_unit,
                        "rawQuantity": round(float(raw_qty or 0), 4),
                        "unitFactor": unit_factor,
                        "quantityBase": round(float(raw_qty or 0), 4),
                        "quantityCoefficient": 1,
                        "quantityFinal": round(float(raw_qty or 0), 4),
                        "baseUnitPrice": round(float(unit_price), 6) if unit_price is not None else None,
                        "costCoefficient": None,
                        "baseTotal": total,
                        "costIndex": None,
                        "currentTotal": total,
                        "lineTotalSource": "contract_total",
                        "lineTotal": total,
                        "total": total,
                        "totalWork": total if item_type == "work" else 0,
                        "totalMaterial": total if item_type == "material" else 0,
                        "type": item_type,
                        "sourceCode": source_code,
                        "importKind": "resource_adjustment" if is_resource_adjustment else "contract_smeta",
                    })
                
                elif file_type == "defect":
                    if all(v is None or (isinstance(v, (int,float)) and v < 10) for v in row[:5]):
                        continue
                    name = str(row[1]).strip() if len(row) > 1 and row[1] else ""
                    unit = str(row[2]).strip() if len(row) > 2 and row[2] else "шт"
                    try:
                        qty = float(row[3]) if len(row) > 3 and row[3] and isinstance(row[3], (int,float)) else 0
                    except:
                        qty = 0
                    if name and len(name) > 5 and name not in ["Наименование", "2"] and not all(c.isdigit() or c == " " for c in name):
                        results.append({"section": current_section, "name": name, "unit": unit, "quantity": qty, "total": 0, "type": "work"})
                
                elif file_type == "vedomost":
                    name = str(row[2]).strip() if len(row) > 2 and row[2] else ""
                    unit = str(row[3]).strip() if len(row) > 3 and row[3] else "шт"
                    try:
                        qty = float(row[4]) if len(row) > 4 and row[4] and isinstance(row[4], (int,float)) else 0
                        total = float(row[6]) if len(row) > 6 and row[6] and isinstance(row[6], (int,float)) else 0
                    except:
                        qty = total = 0
                    if name and len(name) > 5 and name not in ["Наименование", "3"]:
                        results.append({"section": current_section, "name": name, "unit": unit, "quantity": round(qty,4), "total": round(total,2), "type": "material"})
            except:
                continue
        
        declared_total, declared_source = _extract_declared_estimate_total() if file_type in ("lsr", "contract") else (0, "")
        if file_type in ("lsr", "contract") and declared_total:
            parsed_before_reconciliation = _lsr_items_total(results)
            reconciliation_delta = round(float(declared_total) - float(parsed_before_reconciliation), 2)
            if abs(reconciliation_delta) > 1 and abs(reconciliation_delta) <= max(1000, float(declared_total) * 0.01):
                results.append({
                    "section": "Итоговая сверка ЛСР",
                    "name": "Корректировка округлений и итоговых строк до ВСЕГО по смете",
                    "unit": "компл",
                    "quantity": 1,
                    "rawUnit": "компл",
                    "rawQuantity": 1,
                    "unitFactor": 1,
                    "baseUnitPrice": None,
                    "costCoefficient": None,
                    "baseTotal": None,
                    "costIndex": None,
                    "currentTotal": reconciliation_delta,
                    "lineTotalSource": "reconciliation_to_declared_total",
                    "lineTotal": reconciliation_delta,
                    "total": reconciliation_delta,
                    "totalWork": 0,
                    "totalMaterial": 0,
                    "type": "overhead",
                    "sourceCode": "ВСЕГО по смете",
                    "importKind": "reconciliation",
                })
        meta = _declared_total_diagnostics(results, declared_total, declared_source) if file_type in ("lsr", "contract") else {}
        if file_type in ("lsr", "contract"):
            meta.update({
                "parserVersion": "grand-contract-v1" if file_type == "contract" else "grand-lsr-v2",
                "fileType": file_type,
                "dataStartRow": data_start_row,
                "lsrColumns": lsr_columns,
                "lsrIndexes": lsr_indexes,
            })
        os.unlink(tmp_path)
        return {"items": results, "count": len(results), "meta": meta}
    except Exception as e:
        try:
            os.unlink(tmp_path)
        except:
            pass
        return {"error": str(e)}


def _worker_estimate_item_kind_for_sanitize(item):
    kind = str((item or {}).get("itemType") or (item or {}).get("type") or "").strip().lower()
    if kind:
        return kind
    try:
        price_work = float((item or {}).get("priceWork") or 0)
        price_material = float((item or {}).get("priceMaterial") or 0)
    except (TypeError, ValueError):
        price_work = 0
        price_material = 0
    if price_material > 0 and price_work <= 0:
        return "material"
    return "work"


def _sanitize_worker_estimate_sections(sections, allowed_items=None):
    money_keys = (
        "priceWork", "priceMaterial", "totalWork", "totalMaterial", "lineTotal",
        "currentTotal", "total", "sum", "amount", "totalSum", "workTotal",
        "materialTotal", "workSum", "materialSum", "currentWork", "currentMaterial",
        "customerPricePerUnit", "customerTotal", "baseUnitPrice", "baseTotal",
        "baseWork", "baseMaterial", "basePrice", "baseSum", "baseAmount",
        "costCoefficient", "coefficient", "index", "indexValue", "currentIndex",
        "priceBase", "estimatedCost", "resourceCost", "executionPricePerUnit",
        "internalPricePerUnit", "masterPricePerUnit", "contractorPricePerUnit",
        "executorPricePerUnit", "executionPriceMode", "executionCoefficient",
        "masterCoefficient", "contractorCoefficient",
    )
    allowed_by_key = set()
    allowed_by_name = set()
    if allowed_items is not None:
        for row in allowed_items or []:
            item_key = str(row.get("estimate_item_key") or row.get("estimateItemKey") or "").strip()
            if item_key:
                allowed_by_key.add(item_key)
            section_name = str(row.get("estimate_section") or row.get("section") or "").strip().lower()
            description = str(row.get("description") or row.get("name") or "").strip().lower()
            if description:
                allowed_by_name.add((section_name, description))
    sanitized_sections = []
    for section in sections or []:
        if not isinstance(section, dict):
            continue
        items = []
        section_name = str(section.get("name") or "").strip()
        for item in section.get("items") or []:
            if not isinstance(item, dict):
                continue
            if _worker_estimate_item_kind_for_sanitize(item) in ("material", "equipment", "transport", "note", "adjustment"):
                continue
            if allowed_items is not None:
                item_key = str(item.get("estimateItemKey") or item.get("estimate_item_key") or "").strip()
                name_key = (section_name.lower(), str(item.get("name") or "").strip().lower())
                if (item_key and item_key not in allowed_by_key) and name_key not in allowed_by_name:
                    continue
                if not item_key and name_key not in allowed_by_name:
                    continue
            cleaned = dict(item)
            for key in money_keys:
                if key in cleaned:
                    cleaned[key] = 0
            items.append(cleaned)
        if items:
            cleaned_section = dict(section)
            cleaned_section["items"] = items
            sanitized_sections.append(cleaned_section)
    return sanitized_sections


def _worker_allowed_estimate_items_for_scopes(cur, user: dict, scopes: list[tuple[str, str]]):
    if user.get("role") not in WORKER_EXECUTION_ROLES or not scopes:
        return {}
    unique_scopes = []
    seen = set()
    for project_scope, package_scope in scopes:
        key = ((project_scope or "").strip(), (package_scope or "Основная").strip() or "Основная")
        if key[0] and key not in seen:
            seen.add(key)
            unique_scopes.append(key)
    if not unique_scopes:
        return {}
    conditions = []
    params = [user.get("id"), user.get("name") or ""]
    for project_scope, package_scope in unique_scopes:
        conditions.append("(bc.project_name=%s AND COALESCE(NULLIF(bci.work_package,''),'Основная')=%s)")
        params.extend([project_scope, package_scope])
    cur.execute(f"""SELECT bc.project_name,
                           COALESCE(NULLIF(bci.work_package,''),'Основная') AS work_package,
                           COALESCE(bci.estimate_section,'') AS estimate_section,
                           COALESCE(bci.description,'') AS description,
                           COALESCE(bci.estimate_item_key,'') AS estimate_item_key
                    FROM brigade_contract_items bci
                    JOIN brigade_contracts bc ON bc.id=bci.contract_id
                    WHERE COALESCE(bc.status,'') <> 'Аннулирован'
                      AND (COALESCE(bc.contractor_id,0)=%s OR (COALESCE(bc.contractor_id,0)=0 AND LOWER(COALESCE(bc.brigade_name,''))=LOWER(%s)))
                      AND ({" OR ".join(conditions)})""", tuple(params))
    allowed = {}
    for row in cur.fetchall() or []:
        project_scope = row[0] if not isinstance(row, dict) else row.get("project_name")
        package_scope = row[1] if not isinstance(row, dict) else row.get("work_package")
        estimate_section = row[2] if not isinstance(row, dict) else row.get("estimate_section")
        description = row[3] if not isinstance(row, dict) else row.get("description")
        estimate_item_key = row[4] if not isinstance(row, dict) else row.get("estimate_item_key")
        allowed.setdefault((project_scope or "", package_scope or "Основная"), []).append({
            "estimate_section": estimate_section or "",
            "description": description or "",
            "estimate_item_key": estimate_item_key or "",
        })
    return allowed


def _sanitize_worker_estimate_total(user: dict, total):
    return 0 if user.get("role") in WORKER_EXECUTION_ROLES else float(total or 0)


def _estimate_item_total_for_summary(item: dict) -> float:
    item = item or {}
    qty = _safe_float(item.get("quantity"))
    if item.get("isImported"):
        work_total = _safe_float(item.get("totalWork") or item.get("workTotal") or item.get("workSum"))
        material_total = _safe_float(item.get("totalMaterial") or item.get("materialTotal") or item.get("materialSum"))
        if work_total or material_total:
            return work_total + material_total
        for field in ("lineTotal", "currentTotal", "total", "amount", "sum", "totalSum", "estimatedCost"):
            total = _safe_float(item.get(field))
            if total:
                return total
    return qty * (_safe_float(item.get("priceWork")) + _safe_float(item.get("priceMaterial")))


def _estimate_sections_total_for_summary(sections) -> float:
    total = 0.0
    for sec in sections or []:
        for item in (sec or {}).get("items", []) or []:
            total += _estimate_item_total_for_summary(item)
    return round(total, 2)


def _estimate_response_payload_from_row(r, sections, *, sections_loaded: bool, total_override=None):
    summary_total = (
        _estimate_sections_total_for_summary(sections)
        if total_override is None
        else round(_safe_float(total_override), 2)
    )
    return {
        "id": r[0],
        "projectId": r[1],
        "projectName": r[2],
        "name": r[3],
        "version": r[4],
        "sections": sections if sections_loaded else [],
        "sectionsLoaded": bool(sections_loaded),
        "summaryTotal": summary_total,
        "total": summary_total,
        "smetaType": r[6] or "Заказчик",
        "workPackage": r[7] or "Основная",
        "isTemplate": bool(r[8]),
        "status": r[9] or "Черновик",
        "createdAt": str(r[10]) if r[10] else "",
        "versionCount": int(r[11] or 0),
        "latestVersionAt": str(r[12]) if r[12] else "",
    }


@app.get("/estimates")
def get_estimates(summary: bool = False, current_user: dict = Depends(get_current_user)):
    conn = get_db()
    cur = conn.cursor()
    allowed_projects = visible_project_names(current_user)
    role = current_user.get("role")
    package_names = user_package_names(current_user) if role in PACKAGE_LIMIT_ROLES else []
    restrict_packages = bool(package_names)
    deny_without_packages = role in PACKAGE_LIMIT_ROLES and role != "прораб" and not package_names
    base_cols = """e.id,e.project_id,e.project_name,e.name,e.version,e.sections_json,
                   COALESCE(e.smeta_type,'Заказчик'),COALESCE(e.work_package,'Основная'),COALESCE(e.is_template,FALSE),e.status,e.created_at,
                   (SELECT COUNT(*) FROM estimate_versions ev WHERE ev.estimate_id=e.id) as version_count,
                   (SELECT MAX(ev.created_at) FROM estimate_versions ev WHERE ev.estimate_id=e.id) as latest_version_at"""
    if role == "заказчик":
        if not allowed_projects:
            cur.execute(f"SELECT {base_cols} FROM estimates e WHERE FALSE")
        else:
            cur.execute(f"""SELECT {base_cols} FROM estimates e
                            WHERE e.project_name = ANY(%s)
                              AND e.status='Активная'
                              AND COALESCE(e.smeta_type,'Заказчик')='Заказчик'
                            ORDER BY e.id DESC""", (allowed_projects,))
    elif allowed_projects is not None and not allowed_projects:
        if role in WORKER_EXECUTION_ROLES:
            cur.execute(f"SELECT {base_cols} FROM estimates e WHERE FALSE")
        else:
            cur.execute(f"""SELECT {base_cols} FROM estimates e
                            WHERE COALESCE(e.is_template,FALSE)=TRUE
                              AND COALESCE(e.project_name,'')=''
                            ORDER BY e.id DESC""")
    elif deny_without_packages:
        cur.execute(f"SELECT {base_cols} FROM estimates e WHERE FALSE")
    elif allowed_projects is None:
        cur.execute(f"SELECT {base_cols} FROM estimates e ORDER BY e.id DESC")
    else:
        query = f"""SELECT {base_cols} FROM estimates e
                    WHERE (e.project_name = ANY(%s)"""
        params = [allowed_projects]
        if restrict_packages:
            query += " AND COALESCE(NULLIF(e.work_package,''),'Основная') = ANY(%s)"
            params.append(package_names)
        query += ") OR (COALESCE(e.is_template,FALSE)=TRUE AND COALESCE(e.project_name,'')=''"
        if restrict_packages:
            query += " AND COALESCE(NULLIF(e.work_package,''),'Основная') = ANY(%s)"
            params.append(package_names)
        query += ")"
        query += " ORDER BY e.id DESC"
        cur.execute(query, tuple(params))
    rows = cur.fetchall()
    if role in WORKER_EXECUTION_ROLES or role == "прораб":
        rows = [r for r in rows if (r[9] or "") == "Активная"]
    worker_allowed_items_by_scope = {}
    if role in WORKER_EXECUTION_ROLES and rows:
        worker_allowed_items_by_scope = _worker_allowed_estimate_items_for_scopes(
            cur,
            current_user,
            [((r[2] or ""), (r[7] or "Основная")) for r in rows],
        )
    cur.close(); conn.close()
    import json as j
    result = []
    for r in rows:
        try:
            sections = j.loads(r[5]) if r[5] else []
        except:
            sections = []
        sections, _ = _normalize_estimate_adjustment_rows(sections)
        if role in WORKER_EXECUTION_ROLES:
            # Исполнитель получает доступ через объект + пакет работ. Старые
            # contract-items могут дополнительно сузить список строк, но их
            # отсутствие не должно скрывать весь пакет: новая логика работает
            # без обязательного ручного наряда.
            allowed_items = worker_allowed_items_by_scope.get((r[2] or "", r[7] or "Основная"))
            sections = _sanitize_worker_estimate_sections(sections, allowed_items if allowed_items else None)
        summary_total = _estimate_sections_total_for_summary(sections)
        if role == "бухгалтер":
            sections = []
            summary_total = 0
        sections_loaded = not summary and role != "бухгалтер"
        result.append(_estimate_response_payload_from_row(
            r,
            sections,
            sections_loaded=sections_loaded,
            total_override=summary_total,
        ))
    return result


@app.get("/estimates-summary")
def get_estimates_summary(current_user: dict = Depends(get_current_user)):
    return get_estimates(summary=True, current_user=current_user)


@app.get("/estimates/{id}")
def get_estimate_detail(id: int, current_user: dict = Depends(get_current_user)):
    conn = get_db()
    cur = conn.cursor()
    require_estimate_access(cur, id, current_user)
    base_cols = """e.id,e.project_id,e.project_name,e.name,e.version,e.sections_json,
                   COALESCE(e.smeta_type,'Заказчик'),COALESCE(e.work_package,'Основная'),COALESCE(e.is_template,FALSE),e.status,e.created_at,
                   (SELECT COUNT(*) FROM estimate_versions ev WHERE ev.estimate_id=e.id) as version_count,
                   (SELECT MAX(ev.created_at) FROM estimate_versions ev WHERE ev.estimate_id=e.id) as latest_version_at"""
    cur.execute(f"SELECT {base_cols} FROM estimates e WHERE e.id=%s", (id,))
    r = cur.fetchone()
    if not r:
        cur.close(); conn.close()
        raise HTTPException(status_code=404, detail="Смета не найдена")

    role = current_user.get("role")
    status = r[9] or "Черновик"
    smeta_type = r[6] or "Заказчик"
    if role == "заказчик" and (status != "Активная" or smeta_type != "Заказчик"):
        cur.close(); conn.close()
        raise HTTPException(status_code=403, detail="Нет доступа к смете")
    if (role in WORKER_EXECUTION_ROLES or role == "прораб") and status != "Активная":
        cur.close(); conn.close()
        raise HTTPException(status_code=403, detail="Нет доступа к неактивной смете")

    import json as j
    try:
        sections = j.loads(r[5]) if r[5] else []
    except:
        sections = []
    sections, _ = _normalize_estimate_adjustment_rows(sections)
    if role in WORKER_EXECUTION_ROLES:
        allowed_by_scope = _worker_allowed_estimate_items_for_scopes(
            cur,
            current_user,
            [((r[2] or ""), (r[7] or "Основная"))],
        )
        allowed_items = allowed_by_scope.get((r[2] or "", r[7] or "Основная"))
        sections = _sanitize_worker_estimate_sections(sections, allowed_items if allowed_items else None)
    summary_total = _estimate_sections_total_for_summary(sections)
    if role == "бухгалтер":
        sections = []
        summary_total = 0
    cur.close(); conn.close()
    return _estimate_response_payload_from_row(
        r,
        sections,
        sections_loaded=role != "бухгалтер",
        total_override=summary_total,
    )


def _estimate_reconciliation_text_key(value):
    return re.sub(r"[^a-zа-я0-9]+", " ", str(value or "").lower().replace("ё", "е")).strip()


def _estimate_reconciliation_item_sums(item, section_name=""):
    item = item or {}
    qty = _safe_float(item.get("quantity"))
    try:
        item_type = _estimate_item_type_backend(item, section_name)
    except Exception:
        item_type = str(item.get("itemType") or item.get("type") or "").strip().lower() or "work"
    if item_type in ("adjustment", "note"):
        return 0.0, 0.0, 0.0
    if item.get("isImported"):
        work_total = _safe_float(item.get("totalWork") or item.get("workTotal") or item.get("workSum"))
        material_total = _safe_float(item.get("totalMaterial") or item.get("materialTotal") or item.get("materialSum"))
        if work_total or material_total:
            return work_total, material_total, work_total + material_total
        line_total = _safe_float(
            item.get("lineTotal")
            or item.get("currentTotal")
            or item.get("total")
            or item.get("sum")
            or item.get("amount")
            or item.get("totalSum")
            or item.get("estimatedCost")
        )
        if line_total:
            if item_type in ("material", "equipment", "transport"):
                return 0.0, line_total, line_total
            return line_total, 0.0, line_total
    work = qty * _safe_float(item.get("priceWork"))
    material = qty * _safe_float(item.get("priceMaterial"))
    return work, material, work + material


def _estimate_reconciliation_rows(estimate_id, sections):
    grouped = {}
    for section_idx, section in enumerate(sections or []):
        if not isinstance(section, dict):
            continue
        section_name = section.get("name") or "Без раздела"
        for item_idx, item in enumerate(section.get("items") or []):
            if not isinstance(item, dict):
                continue
            try:
                item_type = _estimate_item_type_backend(item, section_name)
            except Exception:
                item_type = str(item.get("itemType") or item.get("type") or "").strip().lower() or "work"
            if item_type in ("adjustment", "note"):
                continue
            qty = _safe_float(item.get("quantity"))
            work_sum, material_sum, total = _estimate_reconciliation_item_sums(item, section_name)
            unit = str(item.get("unit") or "").strip()
            name = str(item.get("name") or item.get("description") or "Без названия").strip()
            key = "|".join([
                _estimate_reconciliation_text_key(section_name),
                _estimate_reconciliation_text_key(name),
                _estimate_reconciliation_text_key(unit),
            ]) or "row:" + str(section_idx) + ":" + str(item_idx)
            row = {
                "key": key,
                "section": section_name,
                "name": name,
                "unit": unit,
                "qty": qty,
                "workSum": work_sum,
                "materialSum": material_sum,
                "sum": total,
                "unitPrice": (total / qty) if qty else 0,
            }
            if key not in grouped:
                grouped[key] = row
                continue
            prev = grouped[key]
            merged_qty = _safe_float(prev.get("qty")) + qty
            merged_sum = _safe_float(prev.get("sum")) + total
            grouped[key] = {
                **prev,
                "section": prev.get("section") if prev.get("section") == section_name else "Несколько разделов",
                "qty": merged_qty,
                "workSum": _safe_float(prev.get("workSum")) + work_sum,
                "materialSum": _safe_float(prev.get("materialSum")) + material_sum,
                "sum": merged_sum,
                "unitPrice": (merged_sum / merged_qty) if merged_qty else 0,
            }
    return list(grouped.values())


def _load_estimate_reconciliation_source(cur, estimate_id, current_user):
    require_estimate_access(cur, estimate_id, current_user)
    cur.execute("""SELECT id, project_id, project_name, name, version, sections_json,
                          COALESCE(smeta_type,'Заказчик'), COALESCE(NULLIF(work_package,''),'Основная'),
                          COALESCE(status,'Черновик'), created_at
                   FROM estimates WHERE id=%s""", (estimate_id,))
    row = cur.fetchone()
    if not row:
        raise HTTPException(status_code=404, detail="Смета не найдена")
    try:
        sections = json.loads(row[5]) if row[5] else []
    except Exception:
        sections = []
    sections, _ = _normalize_estimate_adjustment_rows(sections)
    total = _estimate_sections_total_for_summary(sections)
    return row, sections, total


def _build_estimate_reconciliation_diff(base_estimate_id, base_sections, base_total, next_estimate_id, next_sections, next_total):
    base_rows = _estimate_reconciliation_rows(base_estimate_id, base_sections)
    next_rows = _estimate_reconciliation_rows(next_estimate_id, next_sections)
    base_map = {r["key"]: r for r in base_rows}
    next_map = {r["key"]: r for r in next_rows}
    added, removed, changed = [], [], []
    for next_row in next_rows:
        base_row = base_map.get(next_row["key"])
        if not base_row:
            added.append({**next_row, "impact": _safe_float(next_row.get("sum"))})
            continue
        qty_changed = abs(_safe_float(next_row.get("qty")) - _safe_float(base_row.get("qty"))) > 0.0001
        price_changed = abs(_safe_float(next_row.get("unitPrice")) - _safe_float(base_row.get("unitPrice"))) > 0.01
        sum_changed = abs(_safe_float(next_row.get("sum")) - _safe_float(base_row.get("sum"))) > 0.5
        if qty_changed or price_changed or sum_changed:
            changed.append({
                "base": base_row,
                "next": next_row,
                "impact": _safe_float(next_row.get("sum")) - _safe_float(base_row.get("sum")),
            })
    for base_row in base_rows:
        if base_row["key"] not in next_map:
            removed.append({**base_row, "impact": -_safe_float(base_row.get("sum"))})
    sort_key = lambda row: abs(_safe_float(row.get("impact")))
    return {
        "added": sorted(added, key=sort_key, reverse=True),
        "removed": sorted(removed, key=sort_key, reverse=True),
        "changed": sorted(changed, key=sort_key, reverse=True),
        "baseTotal": round(_safe_float(base_total), 2),
        "nextTotal": round(_safe_float(next_total), 2),
        "impact": round(_safe_float(next_total) - _safe_float(base_total), 2),
        "nextRows": next_rows,
    }


def _estimate_reconciliation_name_score(left, right):
    a = _estimate_reconciliation_text_key(left)
    b = _estimate_reconciliation_text_key(right)
    if not a or not b:
        return 0
    if a == b:
        return 1
    if a in b or b in a:
        return 0.92
    aw = [w for w in a.split(" ") if len(w) > 3]
    bw = [w for w in b.split(" ") if len(w) > 3]
    if not aw or not bw:
        return 0
    return len([w for w in aw if w in bw]) / max(len(aw), len(bw))


def _estimate_reconciliation_find_candidate(change, rows):
    names = [str(change.get(k) or "").strip() for k in ("estimate_item_name", "description")]
    names = [n for idx, n in enumerate(names) if n and n not in names[:idx]]
    if not names:
        return None
    unit_key = _estimate_reconciliation_text_key(change.get("unit"))
    section_key = _estimate_reconciliation_text_key(change.get("section_name"))
    best = None
    for row in rows or []:
        row_unit_key = _estimate_reconciliation_text_key(row.get("unit"))
        if unit_key and row_unit_key and unit_key != row_unit_key:
            continue
        section_bonus = 0.08 if section_key and section_key == _estimate_reconciliation_text_key(row.get("section")) else 0
        score = min(0.99, max(_estimate_reconciliation_name_score(name, row.get("name")) for name in names) + section_bonus)
        if score >= 0.72 and (not best or score > best["score"]):
            best = {"row": row, "score": score}
    return best


def _estimate_reconciliation_change_required(change):
    change_type = change.get("change_type") or "Работа вне сметы"
    base = _safe_float(change.get("base_quantity"))
    delta = _safe_float(change.get("delta_quantity") or change.get("quantity"))
    raw = _safe_float(change.get("new_required_quantity"))
    if raw <= 0 and (base > 0 or delta > 0):
        raw = max(0, base - delta) if change_type == "Исключение объёма" else base + delta
    return raw or delta


def _estimate_reconciliation_change_items(cur, reconciliation_id, project_name, work_package, base_estimate_id, next_estimate_id, diff):
    cols = """id, description, unit, quantity, price, total, change_type, estimate_id,
              section_name, estimate_item_name, base_quantity, new_required_quantity,
              delta_quantity, included_in_estimate_id, reason, status"""
    cur.execute(f"""SELECT {cols} FROM unexpected_works
                   WHERE project_name=%s
                     AND (status = ANY(%s) OR status='Включено в новую смету')
                     AND COALESCE(status,'') <> 'Аннулировано'
                   ORDER BY id""", (project_name, list(ESTIMATE_CHANGE_APPROVED_STATUSES)))
    changes = cur.fetchall() or []
    priority_rows = [
        *[{**r, "_kind": "Добавлена"} for r in diff.get("added", [])],
        *[{**x.get("next", {}), "_kind": "Изменена"} for x in diff.get("changed", [])],
        *[{**r, "_kind": "Найдена"} for r in diff.get("nextRows", [])],
    ]
    inserted = 0
    for r in changes:
        change = {
            "id": r[0],
            "description": r[1] or "",
            "unit": r[2] or "",
            "quantity": _safe_float(r[3]),
            "price": _safe_float(r[4]),
            "total": _safe_float(r[5]),
            "change_type": r[6] or "Работа вне сметы",
            "estimate_id": r[7],
            "section_name": r[8] or "",
            "estimate_item_name": r[9] or "",
            "base_quantity": _safe_float(r[10]),
            "new_required_quantity": _safe_float(r[11]),
            "delta_quantity": _safe_float(r[12]),
            "included_in_estimate_id": r[13],
            "reason": r[14] or "",
            "status": r[15] or "",
        }
        if change["estimate_id"] and int(change["estimate_id"]) not in (int(base_estimate_id), int(next_estimate_id)):
            continue
        change_scope = (change["section_name"] or "").strip()
        if not change["estimate_id"] and change_scope and work_package and change_scope not in (work_package, "Основная"):
            continue
        candidate = _estimate_reconciliation_find_candidate(change, priority_rows)
        required_qty = _estimate_reconciliation_change_required(change)
        signed_total = -abs(change["total"]) if change["change_type"] == "Исключение объёма" else change["total"]
        included = str(change.get("included_in_estimate_id") or "") == str(next_estimate_id)
        decision = "Остаётся отдельной допработой"
        confidence = 0
        if included:
            decision = "Включено в новую смету"
            confidence = 1
        elif candidate:
            confidence = _safe_float(candidate.get("score"))
            candidate_qty = _safe_float(candidate["row"].get("qty"))
            if change["change_type"] == "Исключение объёма":
                decision = "Проверить исключение объёма в новой смете"
            elif not required_qty or candidate_qty >= required_qty * 0.95:
                decision = "Проверить включение в новую смету"
            else:
                decision = "Проверить частичное включение в новую смету"
        target_row = candidate["row"] if candidate else None
        cur.execute("""INSERT INTO estimate_reconciliation_items
                       (reconciliation_id, item_type, section_name, item_name, unit,
                        base_quantity, next_quantity, base_unit_price, next_unit_price,
                        base_total, next_total, impact, decision, confidence, notes,
                        old_row_json, new_row_json, unexpected_work_id)
                       VALUES (%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s)""",
                    (reconciliation_id, "estimate_change", change["section_name"],
                     change["estimate_item_name"] or change["description"], change["unit"],
                     change["base_quantity"], _safe_float(target_row.get("qty")) if target_row else 0,
                     change["price"], _safe_float(target_row.get("unitPrice")) if target_row else 0,
                     change["base_quantity"] * change["price"], _safe_float(target_row.get("sum")) if target_row else 0,
                     signed_total, decision, confidence, change["reason"],
                     json.dumps(change, ensure_ascii=False),
                     json.dumps(target_row or {}, ensure_ascii=False),
                     change["id"]))
        inserted += 1
    return inserted


def _estimate_reconciliation_item_payload(r):
    return {
        "id": r[0],
        "reconciliationId": r[1],
        "itemType": r[2] or "",
        "sectionName": r[3] or "",
        "itemName": r[4] or "",
        "unit": r[5] or "",
        "baseQuantity": float(r[6] or 0),
        "nextQuantity": float(r[7] or 0),
        "baseUnitPrice": float(r[8] or 0),
        "nextUnitPrice": float(r[9] or 0),
        "baseTotal": float(r[10] or 0),
        "nextTotal": float(r[11] or 0),
        "impact": float(r[12] or 0),
        "decision": r[13] or "",
        "confidence": float(r[14] or 0),
        "notes": r[15] or "",
        "oldRow": json.loads(r[16]) if r[16] else {},
        "newRow": json.loads(r[17]) if r[17] else {},
        "unexpectedWorkId": r[18],
        "createdAt": str(r[19]) if r[19] else "",
    }


def _estimate_reconciliation_payload(r, items=None):
    payload = {
        "id": r[0],
        "projectName": r[1] or "",
        "workPackage": r[2] or "Основная",
        "smetaType": r[3] or "Заказчик",
        "baseEstimateId": r[4],
        "nextEstimateId": r[5],
        "baseEstimateName": r[6] or "",
        "nextEstimateName": r[7] or "",
        "baseVersion": r[8] or "",
        "nextVersion": r[9] or "",
        "baseTotal": float(r[10] or 0),
        "nextTotal": float(r[11] or 0),
        "impact": float(r[12] or 0),
        "changedCount": int(r[13] or 0),
        "addedCount": int(r[14] or 0),
        "removedCount": int(r[15] or 0),
        "status": r[16] or "Черновик",
        "notes": r[17] or "",
        "createdBy": r[18] or "",
        "approvedBy": r[19] or "",
        "approvedAt": str(r[20]) if r[20] else "",
        "createdAt": str(r[21]) if r[21] else "",
        "updatedAt": str(r[22]) if r[22] else "",
    }
    if len(r) > 23:
        payload["itemCount"] = int(r[23] or 0)
        payload["reviewCount"] = int(r[24] or 0)
    if items is not None:
        payload["items"] = items
    return payload


def _estimate_reconciliation_select_with_counts(where_sql="", params=()):
    return f"""SELECT r.id,r.project_name,r.work_package,r.smeta_type,r.base_estimate_id,r.next_estimate_id,
                      r.base_estimate_name,r.next_estimate_name,r.base_version,r.next_version,
                      r.base_total,r.next_total,r.impact,r.changed_count,r.added_count,r.removed_count,
                      r.status,r.notes,r.created_by,r.approved_by,r.approved_at,r.created_at,r.updated_at,
                      COUNT(i.id) AS item_count,
                      COALESCE(SUM(CASE WHEN COALESCE(i.decision,'') ILIKE 'Проверить%%' OR COALESCE(i.decision,'')='На проверке' THEN 1 ELSE 0 END),0) AS review_count
               FROM estimate_reconciliations r
               LEFT JOIN estimate_reconciliation_items i ON i.reconciliation_id=r.id
               {where_sql}
               GROUP BY r.id
               ORDER BY r.id DESC""", params


@app.get("/estimate-reconciliations")
def list_estimate_reconciliations(project_name: str = None, current_user: dict = Depends(require_roles(*PROJECT_DOCUMENT_ROLES))):
    conn = get_db()
    cur = conn.cursor()
    where, params = [], []
    allowed_projects = visible_project_names(current_user)
    if project_name:
        if allowed_projects is not None and project_name not in allowed_projects:
            cur.close(); conn.close()
            return []
        where.append("r.project_name=%s")
        params.append(project_name)
    elif allowed_projects is not None:
        if not allowed_projects:
            cur.close(); conn.close()
            return []
        where.append("r.project_name = ANY(%s)")
        params.append(allowed_projects)
    package_sql, package_params = package_access_filter(current_user, "r.work_package")
    if package_sql:
        where.append(package_sql[5:] if package_sql.startswith(" AND ") else package_sql)
        params.extend(package_params)
    if current_user.get("role") == "заказчик":
        where.append("r.status='Утверждена'")
    where_sql = "WHERE " + " AND ".join(where) if where else ""
    sql, _ = _estimate_reconciliation_select_with_counts(where_sql, tuple(params))
    cur.execute(sql, tuple(params))
    rows = cur.fetchall()
    cur.close(); conn.close()
    return [_estimate_reconciliation_payload(r) for r in rows]


@app.get("/estimate-reconciliations/{id}")
def get_estimate_reconciliation(id: int, current_user: dict = Depends(require_roles(*PROJECT_DOCUMENT_ROLES))):
    conn = get_db()
    cur = conn.cursor()
    where_sql = "WHERE r.id=%s"
    sql, _ = _estimate_reconciliation_select_with_counts(where_sql, (id,))
    cur.execute(sql, (id,))
    row = cur.fetchone()
    if not row:
        cur.close(); conn.close()
        raise HTTPException(status_code=404, detail="Сверка смет не найдена")
    require_project_access(current_user, row[1] or "")
    if current_user.get("role") in PACKAGE_LIMIT_ROLES and not has_package_access(current_user, row[2] or "Основная"):
        cur.close(); conn.close()
        raise HTTPException(status_code=403, detail="Нет доступа к пакету сверки")
    if current_user.get("role") == "заказчик" and (row[16] or "") != "Утверждена":
        cur.close(); conn.close()
        raise HTTPException(status_code=403, detail="Сверка ещё не утверждена")
    cur.execute("""SELECT id,reconciliation_id,item_type,section_name,item_name,unit,
                          base_quantity,next_quantity,base_unit_price,next_unit_price,
                          base_total,next_total,impact,decision,confidence,notes,
                          old_row_json,new_row_json,unexpected_work_id,created_at
                   FROM estimate_reconciliation_items
                   WHERE reconciliation_id=%s
                   ORDER BY CASE item_type
                              WHEN 'changed' THEN 1
                              WHEN 'added' THEN 2
                              WHEN 'removed' THEN 3
                              WHEN 'estimate_change' THEN 4
                              ELSE 5
                            END, ABS(COALESCE(impact,0)) DESC, id""", (id,))
    items = [_estimate_reconciliation_item_payload(r) for r in cur.fetchall() or []]
    cur.close(); conn.close()
    return _estimate_reconciliation_payload(row, items)


@app.post("/estimate-reconciliations")
def create_estimate_reconciliation(data: dict, current_user: dict = Depends(require_roles(*ESTIMATE_WRITE_ROLES))):
    base_id = int(data.get("baseEstimateId") or data.get("base_estimate_id") or 0)
    next_id = int(data.get("nextEstimateId") or data.get("next_estimate_id") or 0)
    if not base_id or not next_id or base_id == next_id:
        raise HTTPException(status_code=400, detail="Нужно выбрать две разные сметы")
    conn = get_db()
    cur = conn.cursor()
    base, base_sections, base_total = _load_estimate_reconciliation_source(cur, base_id, current_user)
    next_est, next_sections, next_total = _load_estimate_reconciliation_source(cur, next_id, current_user)
    project_name = next_est[2] or base[2] or ""
    if (base[2] or "") != (next_est[2] or ""):
        cur.close(); conn.close()
        raise HTTPException(status_code=400, detail="Сметы относятся к разным объектам")
    if (base[6] or "Заказчик") != (next_est[6] or "Заказчик") or (base[7] or "Основная") != (next_est[7] or "Основная"):
        cur.close(); conn.close()
        raise HTTPException(status_code=400, detail="Сравнивать можно сметы одного типа и пакета работ")
    diff = _build_estimate_reconciliation_diff(base_id, base_sections, base_total, next_id, next_sections, next_total)
    status = data.get("status") or "Черновик"
    if status not in ("Черновик", "На проверке", "Утверждена", "Отклонена"):
        status = "Черновик"
    cur.execute("""INSERT INTO estimate_reconciliations
                   (project_name, work_package, smeta_type, base_estimate_id, next_estimate_id,
                    base_estimate_name, next_estimate_name, base_version, next_version,
                    base_total, next_total, impact, changed_count, added_count, removed_count,
                    status, notes, created_by)
                   VALUES (%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s)
                   RETURNING id, created_at""",
                (project_name, next_est[7] or "Основная", next_est[6] or "Заказчик", base_id, next_id,
                 base[3] or "", next_est[3] or "", base[4] or "", next_est[4] or "",
                 diff["baseTotal"], diff["nextTotal"], diff["impact"],
                 len(diff["changed"]), len(diff["added"]), len(diff["removed"]),
                 status, data.get("notes") or "", current_user.get("name") or ""))
    reconciliation_id, created_at = cur.fetchone()

    def insert_item(item_type, row, base_row=None, next_row=None):
        old_row = base_row or row if item_type == "removed" else base_row
        new_row = next_row or row if item_type == "added" else next_row
        cur.execute("""INSERT INTO estimate_reconciliation_items
                       (reconciliation_id, item_type, section_name, item_name, unit,
                        base_quantity, next_quantity, base_unit_price, next_unit_price,
                        base_total, next_total, impact, decision, confidence,
                        old_row_json, new_row_json)
                       VALUES (%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s)""",
                    (reconciliation_id, item_type,
                     (next_row or row or base_row or {}).get("section") or "",
                     (next_row or row or base_row or {}).get("name") or "",
                     (next_row or row or base_row or {}).get("unit") or "",
                     _safe_float((base_row or {}).get("qty")),
                     _safe_float((next_row or {}).get("qty")),
                     _safe_float((base_row or {}).get("unitPrice")),
                     _safe_float((next_row or {}).get("unitPrice")),
                     _safe_float((base_row or {}).get("sum")),
                     _safe_float((next_row or {}).get("sum")),
                     _safe_float(row.get("impact")),
                     {
                         "changed": "Проверить изменение объёма/цены",
                         "added": "Проверить новую позицию",
                         "removed": "Проверить исключённую позицию",
                     }.get(item_type, "На проверке"),
                     1,
                     json.dumps(old_row or {}, ensure_ascii=False),
                     json.dumps(new_row or {}, ensure_ascii=False)))

    for row in diff["changed"]:
        insert_item("changed", row, row.get("base"), row.get("next"))
    for row in diff["added"]:
        insert_item("added", row, None, row)
    for row in diff["removed"]:
        insert_item("removed", row, row, None)
    _estimate_reconciliation_change_items(cur, reconciliation_id, project_name, next_est[7] or "Основная", base_id, next_id, diff)
    doc_number = "СС-" + str(reconciliation_id)
    cur.execute("""INSERT INTO project_documents
                   (project_name, side, doc_type, number, doc_date, counterparty, sign_status,
                    scan_url, amount, notes, uploaded_by)
                   VALUES (%s,%s,%s,%s,CURRENT_DATE,%s,%s,%s,%s,%s,%s)""",
                (project_name, "customer", "Сверка смет", doc_number, "",
                 "Подписан" if status == "Утверждена" else status,
                 "", diff["impact"],
                 "Автоматически создана по сверке смет #" + str(reconciliation_id) + ": " + (base[3] or "") + " -> " + (next_est[3] or ""),
                 current_user.get("name") or ""))
    conn.commit()
    cur.close(); conn.close()
    return {"ok": True, "id": reconciliation_id, "createdAt": str(created_at) if created_at else ""}


@app.put("/estimate-reconciliations/{id}")
def update_estimate_reconciliation(id: int, data: dict, current_user: dict = Depends(require_roles(*ESTIMATE_WRITE_ROLES))):
    status = data.get("status")
    if status and status not in ("Черновик", "На проверке", "Утверждена", "Отклонена"):
        raise HTTPException(status_code=400, detail="Недопустимый статус сверки")
    if status == "Утверждена" and current_user.get("role") not in (*LEADERSHIP_ROLES, "главный_инженер", "сметчик"):
        raise HTTPException(status_code=403, detail="Утвердить сверку может руководитель, главный инженер или сметчик")
    conn = get_db()
    cur = conn.cursor()
    cur.execute("SELECT project_name, work_package, status FROM estimate_reconciliations WHERE id=%s", (id,))
    row = cur.fetchone()
    if not row:
        cur.close(); conn.close()
        raise HTTPException(status_code=404, detail="Сверка смет не найдена")
    project_name, work_package, old_status = row[0] or "", row[1] or "Основная", row[2] or ""
    require_project_access(current_user, project_name)
    if current_user.get("role") in PACKAGE_LIMIT_ROLES and not has_package_access(current_user, work_package):
        cur.close(); conn.close()
        raise HTTPException(status_code=403, detail="Нет доступа к пакету сверки")
    updates, params = ["updated_at=NOW()"], []
    if status:
        updates.append("status=%s")
        params.append(status)
        if status == "Утверждена":
            updates.extend(["approved_by=%s", "approved_at=CURRENT_DATE"])
            params.append(current_user.get("name") or "")
    if "notes" in data:
        updates.append("notes=%s")
        params.append(data.get("notes") or "")
    params.append(id)
    cur.execute("UPDATE estimate_reconciliations SET " + ",".join(updates) + " WHERE id=%s", tuple(params))
    if status:
        doc_status = "Подписан" if status == "Утверждена" else status
        cur.execute("""UPDATE project_documents
                       SET sign_status=%s
                       WHERE project_name=%s AND doc_type='Сверка смет' AND number=%s""",
                    (doc_status, project_name, "СС-" + str(id)))
        if status != old_status:
            log_audit(user_name=current_user.get("name") or "", user_role=current_user.get("role") or "",
                      action="status_change", entity_type="estimate_reconciliation", entity_id=id,
                      description="Статус сверки смет: " + (old_status or "—") + " -> " + status,
                      project_name=project_name)
    conn.commit()
    cur.close(); conn.close()
    return {"ok": True}


