@app.post("/estimates")
def create_estimate(data: dict, _current_user: dict = Depends(require_roles(*ESTIMATE_WRITE_ROLES))):
    import json as j
    require_project_access(_current_user, data.get("projectName", ""))
    conn = get_db()
    cur = conn.cursor()
    status = data.get("status") or "Активная"
    smeta_type = data.get("smetaType") or "Заказчик"
    work_package = (data.get("workPackage") or data.get("work_package") or "Основная").strip() or "Основная"
    project_name = data.get("projectName","")
    if status not in ("Активная", "Черновик"):
        cur.close(); conn.close()
        raise HTTPException(status_code=400, detail="Недопустимый статус сметы")
    if _current_user.get("role") in PACKAGE_LIMIT_ROLES and not has_package_access(_current_user, work_package):
        cur.close(); conn.close()
        raise HTTPException(status_code=403, detail="Нет доступа к пакету сметы")
    if status not in ("Активная", "Черновик"):
        cur.close(); conn.close()
        raise HTTPException(status_code=400, detail="Недопустимый статус сметы")
    if status == "Активная" and _current_user.get("role") not in LEADERSHIP_ROLES:
        cur.close(); conn.close()
        raise HTTPException(status_code=403, detail="Активировать смету может только директор или замдиректора. Сохраните смету черновиком.")
    if status == "Активная":
        cur.execute("""UPDATE estimates
                       SET status='Черновик'
                       WHERE project_name=%s
                         AND COALESCE(smeta_type,'Заказчик')=%s
                         AND COALESCE(NULLIF(work_package,''),'Основная')=%s
                         AND status='Активная'""",
                    (project_name, smeta_type, work_package))
    sections, _ = _normalize_estimate_adjustment_rows(data.get("sections", []))
    cur.execute("INSERT INTO estimates (project_id,project_name,name,version,sections_json,smeta_type,work_package,status) VALUES (%s,%s,%s,%s,%s,%s,%s,%s) RETURNING id",
        (data.get("projectId"),project_name,data.get("name",""),data.get("version","1.0"),j.dumps(sections,ensure_ascii=False),smeta_type,work_package,status))
    conn.commit()
    row = cur.fetchone()
    cur.close(); conn.close()
    _run_project_ai_control_safely(project_name, "estimate:create")
    return {"id":row[0],"ok":True}

@app.put("/estimates/{id}")
def update_estimate(id: int, data: dict, _current_user: dict = Depends(require_roles(*ESTIMATE_WRITE_ROLES, *WORKER_EXECUTION_ROLES))):
    import json as j
    from datetime import date as _date
    conn = get_db()
    conn.autocommit = False
    cur = conn.cursor()
    cur.execute("SELECT sections_json, name, version, project_name, COALESCE(smeta_type,'Заказчик'), status, COALESCE(work_package,'Основная') FROM estimates WHERE id=%s", (id,))
    prev = cur.fetchone()
    if not prev:
        cur.close(); conn.close()
        raise HTTPException(status_code=404, detail="Смета не найдена")
    project_name = (prev[3] or "") if prev else ""
    require_project_access(_current_user, project_name)

    def _num(v):
        try:
            return float(v or 0)
        except Exception:
            return 0

    def _estimate_item_total(it):
        qty = _num(it.get("quantity"))
        if it.get("isImported"):
            total_work = _num(it.get("totalWork") or it.get("workTotal") or it.get("workSum"))
            total_material = _num(it.get("totalMaterial") or it.get("materialTotal") or it.get("materialSum"))
            line_total = _num(it.get("lineTotal") or it.get("currentTotal") or it.get("total") or it.get("sum") or it.get("amount") or it.get("totalSum"))
            if total_work or total_material:
                return total_work + total_material
            if line_total:
                return line_total
            return qty * (_num(it.get("priceWork")) + _num(it.get("priceMaterial")))
        return qty * (_num(it.get("priceWork")) + _num(it.get("priceMaterial")))

    def _estimate_item_unit_price(it):
        qty = _num(it.get("quantity"))
        return (_estimate_item_total(it) / qty) if qty > 0 else (_num(it.get("priceWork")) + _num(it.get("priceMaterial")))

    def _estimate_item_execution_price(it, customer_price):
        for key in ("executionPricePerUnit", "internalPricePerUnit", "masterPricePerUnit", "contractorPricePerUnit", "executorPricePerUnit"):
            value = _num(it.get(key))
            if value > 0:
                return value, "fixed"
        for key in ("executionCoefficient", "internalCoefficient", "masterCoefficient", "contractorCoefficient", "executorCoefficient"):
            value = _num(it.get(key))
            if value > 0:
                return customer_price * value, "coefficient:" + key
        return 0, "not_set"

    def _sections_equal_except_done(old_list, new_list):
        if len(old_list or []) != len(new_list or []):
            return False
        for old_section, new_section in zip(old_list or [], new_list or []):
            old_items = old_section.get("items") or []
            new_items = new_section.get("items") or []
            if len(old_items) != len(new_items):
                return False
            old_section_clean = {k: v for k, v in (old_section or {}).items() if k != "items"}
            new_section_clean = {k: v for k, v in (new_section or {}).items() if k != "items"}
            if old_section_clean != new_section_clean:
                return False
            for old_item, new_item in zip(old_items, new_items):
                old_clean = {k: v for k, v in (old_item or {}).items() if k != "doneQuantity"}
                new_clean = {k: v for k, v in (new_item or {}).items() if k != "doneQuantity"}
                if old_clean != new_clean:
                    return False
        return True

    old_sections = []
    if prev and prev[0]:
        try:
            old_sections = j.loads(prev[0])
            total = 0
            for s in old_sections:
                for it in (s.get("items") or []):
                    total += _estimate_item_total(it)
            cur.execute("INSERT INTO estimate_versions (estimate_id, version_label, sections_json, total, comment, created_by) VALUES (%s,%s,%s,%s,%s,%s)",
                (id, prev[2] or "", prev[0], total, data.get("versionComment",""), data.get("updatedBy","")))
        except Exception:
            pass

    new_sections, _ = _normalize_estimate_adjustment_rows(data.get("sections", []) or [])
    for s in new_sections:
        for it in (s.get("items") or []):
            try:
                qty = float(it.get("quantity") or 0)
                done = float(it.get("doneQuantity") or 0)
            except Exception:
                continue
            if qty > 0 and done > qty:
                it["doneQuantity"] = qty
            elif done < 0:
                it["doneQuantity"] = 0
    new_name = data.get("name") or prev[1] or ""
    new_version = data.get("version") or prev[2] or "1.0"
    new_status = data.get("status") or prev[5] or "Черновик"
    new_smeta_type = data.get("smetaType") or prev[4] or "Заказчик"
    new_work_package = data.get("workPackage") or data.get("work_package") or prev[6] or "Основная"
    prev_status = prev[5] or "Черновик"
    current_work_package = prev[6] or "Основная"
    if _current_user.get("role") in WORKER_EXECUTION_ROLES:
        allowed_rows = _worker_allowed_estimate_items_for_scopes(cur, _current_user, [(project_name, current_work_package)]).get((project_name, current_work_package), [])
        allowed_item_keys = set()
        allowed_item_names = set()
        for row in allowed_rows or []:
            row_key = str(row.get("estimate_item_key") or row.get("estimateItemKey") or "").strip()
            if row_key:
                allowed_item_keys.add(row_key)
            row_section = str(row.get("estimate_section") or row.get("section") or "").strip().lower()
            row_desc = str(row.get("description") or row.get("name") or "").strip().lower()
            if row_desc:
                allowed_item_names.add((row_section, row_desc))
        if not allowed_item_keys and not allowed_item_names:
            cur.close(); conn.close()
            raise HTTPException(status_code=403, detail="Исполнителю не назначены строки сметы для закрытия работ")

        def _worker_can_touch_estimate_item(section_name, item):
            item_key = str((item or {}).get("estimateItemKey") or (item or {}).get("estimate_item_key") or "").strip()
            if item_key and item_key in allowed_item_keys:
                return True
            name_key = (str(section_name or "").strip().lower(), str((item or {}).get("name") or "").strip().lower())
            return name_key in allowed_item_names

        def _is_worker_work_item(item):
            kind = str((item or {}).get("itemType") or (item or {}).get("type") or "").strip().lower()
            if kind in ("material", "equipment", "transport", "note", "adjustment"):
                return False
            if kind == "work":
                return True
            return not (_num((item or {}).get("priceMaterial")) > 0 and _num((item or {}).get("priceWork")) <= 0)
        incoming_done = {}
        unmatched = []
        for section in new_sections or []:
            section_name = section.get("name", "") if isinstance(section, dict) else ""
            for item in (section.get("items") or []) if isinstance(section, dict) else []:
                item_id = item.get("id")
                item_name = item.get("name", "")
                keys = []
                if item_id is not None:
                    keys.append(("id", str(item_id)))
                item_key = str(item.get("estimateItemKey") or item.get("estimate_item_key") or "").strip()
                if item_key:
                    keys.append(("estimateItemKey", item_key))
                keys.append(("name", section_name, item_name))
                try:
                    done_value = float(item.get("doneQuantity") or 0)
                except Exception:
                    done_value = 0
                for key in keys:
                    incoming_done[key] = done_value
                item_key = str(item.get("estimateItemKey") or item.get("estimate_item_key") or "").strip()
                unmatched.append((item_id, item_key, section_name, item_name))
        merged_sections = []
        matched = set()
        for section in old_sections or []:
            merged_section = dict(section)
            merged_items = []
            section_name = section.get("name", "")
            for item in section.get("items") or []:
                merged_item = dict(item)
                if not _is_worker_work_item(item):
                    merged_items.append(merged_item)
                    continue
                item_id = item.get("id")
                keys = []
                if item_id is not None:
                    keys.append(("id", str(item_id)))
                item_key = str(item.get("estimateItemKey") or item.get("estimate_item_key") or "").strip()
                if item_key:
                    keys.append(("estimateItemKey", item_key))
                keys.append(("name", section_name, item.get("name", "")))
                for key in keys:
                    if key in incoming_done:
                        if not _worker_can_touch_estimate_item(section_name, item):
                            cur.close(); conn.close()
                            raise HTTPException(status_code=403, detail="Исполнитель может закрывать только назначенные ему строки сметы")
                        done_value = incoming_done[key]
                        try:
                            qty_value = float(item.get("quantity") or 0)
                        except Exception:
                            qty_value = 0
                        try:
                            old_done_value = float(item.get("doneQuantity") or 0)
                        except Exception:
                            old_done_value = 0
                        if done_value + 0.000001 < old_done_value:
                            cur.close(); conn.close()
                            raise HTTPException(status_code=403, detail="Исполнитель не может уменьшать уже закрытый объём. Корректировку делает прораб или директор.")
                        if qty_value > 0:
                            done_value = min(done_value, qty_value)
                        merged_item["doneQuantity"] = max(0, done_value)
                        matched.add(key)
                        break
                merged_items.append(merged_item)
            merged_section["items"] = merged_items
            merged_sections.append(merged_section)
        for item_id, item_key, section_name, item_name in unmatched:
            if item_id is not None and ("id", str(item_id)) in matched:
                continue
            if item_key and ("estimateItemKey", item_key) in matched:
                continue
            if ("name", section_name, item_name) in matched:
                continue
            cur.close(); conn.close()
            raise HTTPException(status_code=403, detail="Исполнитель может закрывать только строки своей сметы")
        new_sections = merged_sections
        new_name = prev[1] or ""
        new_version = prev[2] or "1.0"
        new_status = prev_status
        new_smeta_type = prev[4] or "Заказчик"
        new_work_package = current_work_package
    elif not _sections_equal_except_done(old_sections, new_sections) and _current_user.get("role") in WORKER_EXECUTION_ROLES:
        cur.close(); conn.close()
        raise HTTPException(status_code=403, detail="Исполнитель может менять в смете только выполненный объём")
    if new_status not in ("Активная", "Черновик"):
        cur.close(); conn.close()
        raise HTTPException(status_code=400, detail="Недопустимый статус сметы")
    if _current_user.get("role") in PACKAGE_LIMIT_ROLES and (
        not has_package_access(_current_user, current_work_package)
        or not has_package_access(_current_user, new_work_package)
    ):
        cur.close(); conn.close()
        raise HTTPException(status_code=403, detail="Нет доступа к пакету сметы")
    if new_status == "Активная" and new_status != prev_status and _current_user.get("role") not in LEADERSHIP_ROLES:
        cur.close(); conn.close()
        raise HTTPException(status_code=403, detail="Активировать смету может только директор или замдиректора")
    cur.execute("UPDATE estimates SET name=%s,version=%s,sections_json=%s,smeta_type=%s,work_package=%s,status=%s WHERE id=%s",
        (new_name,new_version,j.dumps(new_sections,ensure_ascii=False),new_smeta_type,new_work_package,new_status,id))

    # Build lookup of old done qty by (section name, item name)
    old_done = {}
    for s in old_sections:
        for it in (s.get("items") or []):
            key = (s.get("name",""), it.get("name",""))
            old_done[key] = float(it.get("doneQuantity") or 0)

    today = _date.today().isoformat()
    journal_added = 0
    acts_added = 0
    auto_journal_status = "На проверке" if _current_user.get("role") in WORKER_EXECUTION_ROLES else "Подтверждено"
    auto_confirmed_by = "" if auto_journal_status != "Подтверждено" else (_current_user.get("name") or "")
    auto_confirmed_at = today if auto_journal_status == "Подтверждено" else None
    work_journal_materials = data.get("_workJournalMaterials") or {}
    work_journal_params = data.get("_workJournalParams") or {}

    def _journal_params_for_delta(section_idx, item_idx, section_name, item_name):
        keys = [
            str(id) + ":" + str(section_idx) + ":" + str(item_idx),
            str(section_idx) + ":" + str(item_idx),
            str(section_name or "") + "|" + str(item_name or ""),
        ]
        for k in keys:
            if k in work_journal_params and isinstance(work_journal_params.get(k), dict):
                params = dict(work_journal_params.get(k) or {})
                params["_estimateItemKey"] = params.get("estimateItemKey") or k
                return params
        return {"_estimateItemKey": str(id) + ":" + str(section_idx) + ":" + str(item_idx)}

    def _materials_for_delta(section_idx, item_idx, section_name, item_name):
        keys = [
            str(id) + ":" + str(section_idx) + ":" + str(item_idx),
            str(section_idx) + ":" + str(item_idx),
            str(section_name or "") + "|" + str(item_name or ""),
        ]
        raw = []
        for k in keys:
            if k in work_journal_materials:
                raw = work_journal_materials.get(k) or []
                break
        used = []
        for m in raw if isinstance(raw, list) else []:
            try:
                qty = float(m.get("quantity") or 0)
            except Exception:
                qty = 0
            name = (m.get("name") or "").strip()
            if name and qty > 0:
                row = {"name": name, "quantity": qty, "unit": m.get("unit") or "шт"}
                try:
                    norm_qty = float(m.get("normQuantity") or 0)
                except Exception:
                    norm_qty = 0
                if norm_qty > 0:
                    row["normQuantity"] = norm_qty
                if m.get("normSource"):
                    row["normSource"] = m.get("normSource")
                if m.get("normRuleId") or m.get("ruleId"):
                    row["normRuleId"] = m.get("normRuleId") or m.get("ruleId")
                if m.get("normThicknessMm") or m.get("thicknessMm"):
                    row["normThicknessMm"] = m.get("normThicknessMm") or m.get("thicknessMm")
                if "autoNorm" in m:
                    row["autoNorm"] = bool(m.get("autoNorm"))
                if "overNorm" in m:
                    row["overNorm"] = bool(m.get("overNorm"))
                if m.get("overNormReason"):
                    row["overNormReason"] = m.get("overNormReason")
                used.append(row)
        return used

    for section_idx, s in enumerate(new_sections):
        for item_idx, it in enumerate(s.get("items") or []):
            new_done = float(it.get("doneQuantity") or 0)
            key = (s.get("name",""), it.get("name",""))
            old_q = old_done.get(key, 0)
            delta = new_done - old_q
            if delta <= 0:
                continue
            brigade = (it.get("brigadeName") or "").strip()
            unit = it.get("unit") or "шт"
            customer_price = _estimate_item_unit_price(it)
            execution_price, execution_mode = _estimate_item_execution_price(it, customer_price)
            used_materials = _materials_for_delta(section_idx, item_idx, s.get("name",""), it.get("name",""))
            journal_params = _journal_params_for_delta(section_idx, item_idx, s.get("name",""), it.get("name",""))
            if _num(journal_params.get("customerPricePerUnit")) > 0:
                customer_price = _num(journal_params.get("customerPricePerUnit"))
            if _num(journal_params.get("executionPricePerUnit")) > 0:
                execution_price = _num(journal_params.get("executionPricePerUnit"))
                execution_mode = journal_params.get("executionPriceMode") or "fixed"
            try:
                room_id = int(journal_params.get("roomId") or 0) or None
            except Exception:
                room_id = None
            room_name = journal_params.get("roomName") or ""
            if _current_user.get("role") in WORKER_EXECUTION_ROLES and not room_id and not str(room_name).strip():
                cur.close(); conn.close()
                raise HTTPException(status_code=400, detail="Для закрытия работы нужно выбрать помещение. Так система не даст задвоить объём и свяжет работу с обмерами.")
            estimate_item_key = journal_params.get("estimateItemKey") or journal_params.get("_estimateItemKey") or (str(id) + ":" + str(section_idx) + ":" + str(item_idx))
            try:
                work_package_for_journal = journal_params.get("workPackage") or new_work_package
                if _current_user.get("role") in PACKAGE_LIMIT_ROLES and not has_work_execution_package_access(_current_user, project_name, work_package_for_journal):
                    raise HTTPException(status_code=403, detail="Нет доступа к пакету работ")
                contract_item_id = journal_params.get("contractItemId") or journal_params.get("contract_item_id")
                if _current_user.get("role") in WORKER_EXECUTION_ROLES:
                    assigned_item = _worker_contract_item_for_work(
                        cur,
                        _current_user,
                        project_name,
                        it.get("name",""),
                        unit,
                        contract_item_id,
                        work_package_for_journal,
                        estimate_item_key,
                        s.get("name", ""),
                    )
                    _validate_contract_item_capacity(assigned_item, delta)
                    contract_item_id = assigned_item.get("id")
                    execution_price = _float_or_zero(assigned_item.get("price_brigade"))
                    if execution_price <= 0:
                        raise HTTPException(status_code=400, detail="Для работы не задана цена исполнителя в договорной позиции")
                    execution_mode = "brigade_contract"
                _raise_work_journal_duplicate(_work_journal_duplicate(
                    cur,
                    project_name,
                    room_id=room_id,
                    room_name=journal_params.get("roomName") or "",
                    estimate_item_key=estimate_item_key,
                    description=it.get("name",""),
                    work_package=work_package_for_journal,
                ))
                used_materials = _force_work_material_package(used_materials, work_package_for_journal)
                _validate_work_material_norm_reasons(
                    used_materials,
                    cur,
                    project=project_name,
                    estimate_id=id,
                    work_name=it.get("name", ""),
                    section_name=s.get("name", ""),
                    work_qty=delta,
                    work_unit=unit,
                    actor_role=_current_user.get("role") or "",
                )
                for m in used_materials:
                    _apply_material_work_writeoff(cur, project_name, m, _current_user, today, brigade)
                materials_json = j.dumps(used_materials, ensure_ascii=False) if used_materials else None
                cur.execute("""INSERT INTO work_journal
                               (master_id, master_name, project, description, unit, quantity, price_per_unit, total, date, status, comment,
                                photo_url, materials_used, estimate_id, section_name, hidden_work, confirmed_by, confirmed_at,
                                work_package, room_id, room_name, surface, estimate_item_name, estimate_item_key,
                                contract_item_id, customer_price_per_unit, customer_total, execution_price_per_unit, execution_total, execution_price_mode)
                               VALUES (%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s)
                               RETURNING id""",
                            (_current_user.get("id"), _current_user.get("name") or brigade or "(из сметы)", project_name, it.get("name",""), unit, delta, execution_price, round(delta*execution_price,2), today,
                             auto_journal_status,
                             "Авто-запись при изменении doneQuantity по позиции сметы №"+str(id),
                             journal_params.get("photoUrl") or "",
                             materials_json, id, s.get("name",""), bool(it.get("hiddenWork")), auto_confirmed_by, auto_confirmed_at,
                             work_package_for_journal,
                             room_id,
                             room_name,
                             journal_params.get("surface") or "",
                             journal_params.get("estimateItemName") or it.get("name",""),
                             estimate_item_key,
                             contract_item_id, customer_price, round(delta*customer_price,2), execution_price, round(delta*execution_price,2), execution_mode))
                work_journal_id = cur.fetchone()[0]
                _sync_contract_item_done(cur, contract_item_id, delta)
                work_row = _work_journal_sync_row(cur, work_journal_id)
                _sync_room_work_from_journal(cur, work_row)
                acts_added += _sync_hidden_work_act_from_journal(cur, work_row)
                journal_added += 1
            except HTTPException:
                conn.rollback()
                cur.close(); conn.close()
                raise
            except Exception as e:
                conn.rollback()
                cur.close(); conn.close()
                raise HTTPException(status_code=500, detail="Не удалось создать ЖПР по выполненному объёму сметы: " + str(e))

            # If item flagged as hidden work — create draft АОСР (Акт освидетельствования скрытых работ)
            if it.get("hiddenWork"):
                try:
                    # Не плодим дубли: один АОСР на позицию сметы (estimate_id + наименование работы)
                    cur.execute("SELECT COUNT(*) FROM hidden_works_acts WHERE estimate_id=%s AND work_name=%s",
                                (id, it.get("name","")))
                    already = (cur.fetchone()[0] or 0) > 0
                    if not already:
                        cur.execute("SELECT COUNT(*) FROM hidden_works_acts WHERE project_name=%s", (project_name,))
                        next_num = (cur.fetchone()[0] or 0) + 1
                        act_number = "АОСР-"+str(next_num)+"/"+str(id)
                        act_work_package = (work_package_for_journal if 'work_package_for_journal' in locals() else new_work_package) or "Основная"
                        cur.execute("""INSERT INTO hidden_works_acts
                                       (project_name, estimate_id, act_number, work_name, section_name, work_package, brigade,
                                        quantity, unit, price_per_unit, total, work_date, status)
                                       VALUES (%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s)""",
                            (project_name, id, act_number, it.get("name",""), s.get("name",""), act_work_package,
                             brigade or "", delta, unit, customer_price, round(delta*customer_price,2), today, "Черновик"))
                        acts_added += 1
                except Exception as e:
                    print("AUTO-ACT ERROR:", str(e))

    # Смета — единый источник «Сделано»: синхронизируем выполнение в позиции бригады.
    # Позиция сметы привязана к бригаде через brigadeName (колонка «Кому»),
    # к позиции наряда — по совпадению наименования. Объём капается планом наряда.
    brigade_synced = 0
    try:
        cur.execute("SELECT id, brigade_name FROM brigade_contracts WHERE project_name=%s", (project_name,))
        bc_rows = cur.fetchall() or []
        bc_by_name = {}
        for bc_id, bname in bc_rows:
            bc_by_name.setdefault((bname or "").strip().lower(), []).append(bc_id)
        if bc_by_name:
            for s in new_sections:
                for it in (s.get("items") or []):
                    bn = (it.get("brigadeName") or "").strip().lower()
                    if not bn or bn not in bc_by_name:
                        continue
                    done = float(it.get("doneQuantity") or 0)
                    iname = (it.get("name") or "").strip().lower()
                    if not iname:
                        continue
                    qty = float(it.get("quantity") or 0)
                    for bc_id in bc_by_name[bn]:
                        cur.execute(
                            "UPDATE brigade_contract_items "
                            "SET quantity = CASE WHEN COALESCE(quantity,0)>0 THEN quantity ELSE %s END, "
                            "done_quantity = LEAST(%s, CASE WHEN COALESCE(quantity,0)>0 THEN quantity ELSE %s END) "
                            "WHERE contract_id=%s AND LOWER(TRIM(description))=%s",
                            (qty, done, qty, bc_id, iname))
                        brigade_synced += cur.rowcount or 0
    except Exception as e:
        print("BRIGADE-SYNC ERROR:", str(e))

    conn.commit()
    cur.close(); conn.close()
    _run_project_ai_control_safely(project_name, "estimate:update")
    return {"ok": True, "journalEntries": journal_added, "hiddenWorkActs": acts_added, "brigadeItemsSynced": brigade_synced}

@app.put("/estimates/{id}/status")
def update_estimate_status(id: int, data: dict, _current_user: dict = Depends(require_roles(*ESTIMATE_WRITE_ROLES))):
    status = data.get("status") or "Черновик"
    if status not in ("Активная", "Черновик"):
        raise HTTPException(status_code=400, detail="Недопустимый статус сметы")
    if status == "Активная" and _current_user.get("role") not in LEADERSHIP_ROLES:
        raise HTTPException(status_code=403, detail="Активировать смету может только директор или замдиректора")
    conn = get_db()
    cur = conn.cursor()
    cur.execute("SELECT project_name, COALESCE(smeta_type,'Заказчик'), COALESCE(work_package,'Основная') FROM estimates WHERE id=%s", (id,))
    row = cur.fetchone()
    if not row:
        cur.close(); conn.close()
        raise HTTPException(status_code=404, detail="Смета не найдена")
    project_name, smeta_type, work_package = row[0] or "", row[1] or "Заказчик", row[2] or "Основная"
    require_project_access(_current_user, project_name)
    if _current_user.get("role") in PACKAGE_LIMIT_ROLES and not has_package_access(_current_user, work_package):
        cur.close(); conn.close()
        raise HTTPException(status_code=403, detail="Нет доступа к пакету сметы")
    if status == "Активная":
        cur.execute("""UPDATE estimates
                       SET status='Черновик'
                       WHERE id<>%s
                         AND project_name=%s
                         AND COALESCE(smeta_type,'Заказчик')=%s
                         AND COALESCE(NULLIF(work_package,''),'Основная')=%s
                         AND status='Активная'""",
                    (id, project_name, smeta_type, work_package))
    cur.execute("UPDATE estimates SET status=%s WHERE id=%s", (status, id))
    conn.commit()
    cur.close(); conn.close()
    _run_project_ai_control_safely(project_name, "estimate:status")
    return {"ok": True, "status": status}

@app.post("/estimates/{id}/include-changes")
def include_estimate_changes(id: int, data: dict, current_user: dict = Depends(require_roles(*LEADERSHIP_ROLES))):
    """Создать новую активную версию сметы с утверждёнными изменениями без задвоения КС."""
    import copy
    import json as j
    import re
    import time
    conn = get_db()
    cur = conn.cursor()
    cur.execute("""SELECT project_id, project_name, name, version, sections_json,
                          COALESCE(smeta_type,'Заказчик'), COALESCE(work_package,'Основная'), status
                   FROM estimates WHERE id=%s""", (id,))
    est = cur.fetchone()
    if not est:
        cur.close(); conn.close()
        raise HTTPException(status_code=404, detail="Смета не найдена")
    project_id, project_name, name, version, sections_json, smeta_type, work_package, status = est
    require_project_access(current_user, project_name or "")
    try:
        sections = j.loads(sections_json) if sections_json else []
    except Exception:
        sections = []
    sections = copy.deepcopy(sections)

    change_ids = data.get("changeIds") or data.get("change_ids") or []
    if change_ids:
        change_ids = [int(x) for x in change_ids if str(x).strip().isdigit()]
    cols = """id, description, unit, quantity, price, total, change_type, estimate_id,
              section_name, estimate_item_name, base_quantity, new_required_quantity,
              delta_quantity, reason"""
    if change_ids:
        cur.execute(f"""SELECT {cols} FROM unexpected_works
                       WHERE project_name=%s
                         AND status = ANY(%s)
                         AND included_in_estimate_id IS NULL
                         AND id = ANY(%s)
                       ORDER BY id""", (project_name, list(ESTIMATE_CHANGE_APPROVED_STATUSES), change_ids))
    else:
        cur.execute(f"""SELECT {cols} FROM unexpected_works
                       WHERE project_name=%s
                         AND status = ANY(%s)
                         AND included_in_estimate_id IS NULL
                         AND (estimate_id=%s OR estimate_id IS NULL)
                       ORDER BY id""", (project_name, list(ESTIMATE_CHANGE_APPROVED_STATUSES), id))
    changes = cur.fetchall() or []
    if not changes:
        cur.close(); conn.close()
        raise HTTPException(status_code=400, detail="Нет утверждённых изменений для включения")

    def _num(v):
        try:
            return float(v or 0)
        except Exception:
            return 0.0

    def _norm(v):
        return re.sub(r"[^a-zа-я0-9]+", " ", str(v or "").lower().replace("ё", "е")).strip()

    def _next_version(v):
        raw = str(v or "1.0").strip()
        parts = raw.split(".")
        try:
            parts[-1] = str(int(parts[-1]) + 1)
            return ".".join(parts)
        except Exception:
            return raw + "+1"

    def _item_total(it):
        qty = _num(it.get("quantity"))
        if it.get("isImported"):
            total_work = _num(it.get("totalWork") or it.get("workTotal") or it.get("workSum"))
            total_material = _num(it.get("totalMaterial") or it.get("materialTotal") or it.get("materialSum"))
            line_total = _num(it.get("lineTotal") or it.get("currentTotal") or it.get("total") or it.get("sum") or it.get("amount") or it.get("totalSum"))
            if total_work or total_material:
                return total_work + total_material
            if line_total:
                return line_total
        work = qty * _num(it.get("priceWork"))
        mat = qty * _num(it.get("priceMaterial"))
        return work + mat

    def _item_unit_price(it):
        qty = _num(it.get("quantity"))
        return (_item_total(it) / qty) if qty > 0 else (_num(it.get("priceWork")) + _num(it.get("priceMaterial")))

    def _find_item(section_name, item_name):
        sec_key, item_key = _norm(section_name), _norm(item_name)
        fallback = None
        for s in sections:
            s_match = _norm(s.get("name")) == sec_key if sec_key else True
            for it in (s.get("items") or []):
                if _norm(it.get("name")) == item_key:
                    if s_match:
                        return s, it
                    fallback = fallback or (s, it)
        return fallback

    def _changes_section():
        for s in sections:
            if _norm(s.get("name")) == _norm("Изменения к смете"):
                return s
        s = {"id": int(time.time() * 1000), "name": "Изменения к смете", "items": []}
        sections.append(s)
        return s

    not_applied = []
    applied_ids = []
    for idx, r in enumerate(changes):
        ch_id, desc, unit, qty, price, total, change_type, estimate_id, section_name, estimate_item_name, base_qty, new_qty, delta_qty, reason = r
        qty = _num(delta_qty) or _num(qty)
        price = _num(price)
        change_type = change_type or "Работа вне сметы"
        target = _find_item(section_name, estimate_item_name or desc) if estimate_item_name or desc else None
        if change_type in ("Дополнительный объём к строке сметы", "Исключение объёма") and target:
            _s, it = target
            old_qty = _num(it.get("quantity"))
            required = _num(new_qty)
            if required <= 0:
                required = old_qty + qty if change_type == "Дополнительный объём к строке сметы" else max(0, old_qty - qty)
            it["quantity"] = required
            if _num(it.get("doneQuantity")) > required:
                it["doneQuantity"] = required
            if price > 0:
                if _num(it.get("priceWork")) > 0 or not _num(it.get("priceMaterial")):
                    it["priceWork"] = price
                else:
                    it["priceMaterial"] = price
            it["sourceUnexpectedWorkId"] = ch_id
            it["changeType"] = change_type
            applied_ids.append(ch_id)
            continue
        if change_type == "Исключение объёма":
            not_applied.append(desc or estimate_item_name or str(ch_id))
            continue
        section = _changes_section()
        item_id = int(time.time() * 1000) + idx + 1
        section.setdefault("items", []).append({
            "id": item_id,
            "itemType": "work",
            "name": desc or estimate_item_name or "Изменение к смете",
            "unit": unit or "шт",
            "quantity": qty,
            "priceWork": price,
            "priceMaterial": 0,
            "measurementBasis": "manual",
            "sourceUnexpectedWorkId": ch_id,
            "changeType": change_type,
            "reason": reason or "",
        })
        applied_ids.append(ch_id)

    if not_applied:
        cur.close(); conn.close()
        raise HTTPException(status_code=400, detail="Не найдены строки для исключения объёма: " + ", ".join(not_applied[:5]))
    if not applied_ids:
        cur.close(); conn.close()
        raise HTTPException(status_code=400, detail="Не удалось применить изменения")

    new_version = data.get("version") or _next_version(version)
    new_name = data.get("name") or (name or "Смета") + " — ред. " + str(new_version)
    conn.autocommit = False
    try:
        cur.execute("""INSERT INTO estimates
                       (project_id, project_name, name, version, sections_json, smeta_type, work_package, status)
                       VALUES (%s,%s,%s,%s,%s,%s,%s,'Активная') RETURNING id, created_at""",
                    (project_id, project_name, new_name, new_version, j.dumps(sections, ensure_ascii=False), smeta_type, work_package))
        new_id, created_at = cur.fetchone()
        cur.execute("""UPDATE unexpected_works
                       SET status='Включено в новую смету',
                           included_in_estimate_id=%s,
                           approved_by=COALESCE(NULLIF(approved_by,''), %s),
                           approved_at=COALESCE(approved_at, TO_CHAR(CURRENT_DATE,'YYYY-MM-DD'))
                       WHERE id = ANY(%s)""", (new_id, current_user.get("name") or "", applied_ids))
        conn.commit()
    except Exception:
        conn.rollback()
        raise
    cur.close(); conn.close()
    return {"ok": True, "id": new_id, "includedChangeIds": applied_ids,
            "estimate": {"id": new_id, "projectId": project_id, "projectName": project_name,
                         "name": new_name, "version": new_version, "sections": sections,
                         "smetaType": smeta_type, "workPackage": work_package,
                         "status": "Активная", "createdAt": str(created_at) if created_at else ""}}

@app.post("/estimates/{id}/reconcile-changes")
def reconcile_estimate_changes(id: int, data: dict, current_user: dict = Depends(require_roles(*ESTIMATE_WRITE_ROLES))):
    """Пометить утверждённые изменения как уже вошедшие в существующую новую смету."""
    conn = get_db()
    cur = conn.cursor()
    cur.execute("""SELECT project_name, COALESCE(smeta_type,'Заказчик'), COALESCE(work_package,'Основная'), status
                   FROM estimates WHERE id=%s""", (id,))
    est = cur.fetchone()
    if not est:
        cur.close(); conn.close()
        raise HTTPException(status_code=404, detail="Смета не найдена")
    project_name, smeta_type, _work_package, status = est
    require_project_access(current_user, project_name or "")
    if (smeta_type or "Заказчик") != "Заказчик" or (status or "Черновик") != "Активная":
        cur.close(); conn.close()
        raise HTTPException(status_code=400, detail="Сверка изменений доступна только для активной сметы заказчика")

    change_ids = data.get("changeIds") or data.get("change_ids") or []
    change_ids = [int(x) for x in change_ids if str(x).strip().isdigit()]
    if not change_ids:
        cur.close(); conn.close()
        return {"ok": True, "includedChangeIds": []}

    updated_by = data.get("updatedBy") or current_user.get("name") or ""
    cur.execute("""SELECT id FROM unexpected_works
                   WHERE project_name=%s
                     AND status = ANY(%s)
                     AND included_in_estimate_id IS NULL
                     AND id = ANY(%s)""",
                (project_name, list(ESTIMATE_CHANGE_APPROVED_STATUSES), change_ids))
    allowed_ids = [int(r[0]) for r in (cur.fetchall() or [])]
    if allowed_ids:
        note = "Автоматически сопоставлено с новой сметой №" + str(id)
        cur.execute("""UPDATE unexpected_works
                       SET status='Включено в новую смету',
                           included_in_estimate_id=%s,
                           approved_by=COALESCE(NULLIF(approved_by,''), %s),
                           approved_at=COALESCE(approved_at, TO_CHAR(CURRENT_DATE,'YYYY-MM-DD')),
                           reason=CASE
                             WHEN COALESCE(reason,'')='' THEN %s
                             WHEN reason LIKE %s THEN reason
                             ELSE reason || '; ' || %s
                           END
                       WHERE id = ANY(%s)""",
                    (id, updated_by, note, "%" + note + "%", note, allowed_ids))
    conn.commit()
    cur.close(); conn.close()
    return {"ok": True, "includedChangeIds": allowed_ids}

