def _material_norm_confidence_value(value) -> float:
    try:
        confidence = float(value or 0)
    except Exception:
        return 0.0
    if confidence > 1:
        confidence = confidence / 100
    return max(0.0, min(1.0, confidence))

@app.get("/material-aliases")
def list_material_aliases(project_name: str = None, current_user: dict = Depends(require_roles(*PROJECT_DOCUMENT_ROLES))):
    conn = get_db()
    cur = conn.cursor(cursor_factory=psycopg2.extras.RealDictCursor)
    where = ["active=TRUE"]
    params = []
    if project_name:
        require_project_access(current_user, project_name)
        where.append("(project_name=%s OR COALESCE(project_name,'')='')")
        params.append(project_name)
    else:
        allowed = visible_project_names(current_user)
        if allowed is not None:
            if not allowed:
                where.append("COALESCE(project_name,'')=''")
            else:
                where.append("(project_name = ANY(%s) OR COALESCE(project_name,'')='')")
                params.append(allowed)
    cur.execute(f"""SELECT *
                    FROM material_aliases
                    WHERE {' AND '.join(where)}
                    ORDER BY COALESCE(project_name,'') DESC, alias_name, id""", tuple(params))
    rows = cur.fetchall()
    cur.close(); conn.close()
    return [_material_alias_row(r) for r in rows]

@app.post("/material-aliases")
def create_material_alias(data: MaterialAliasModel, current_user: dict = Depends(require_roles(*LEADERSHIP_ROLES, "прораб", "главный_инженер", "сметчик", "снабженец", "кладовщик"))):
    project_name = (data.projectName or "").strip()
    alias_name = (data.aliasName or "").strip()
    canonical_name = (data.canonicalName or "").strip()
    if not alias_name or not canonical_name:
        raise HTTPException(status_code=400, detail="Укажите исходное и сметное название материала")
    if project_name:
        require_project_access(current_user, project_name)
    conn = get_db()
    cur = conn.cursor(cursor_factory=psycopg2.extras.RealDictCursor)
    vals = _material_alias_values(data, current_user.get("name", ""))
    cur.execute("""
        UPDATE material_aliases
        SET active=FALSE, updated_by=%s, updated_at=NOW()
        WHERE active=TRUE
          AND COALESCE(project_name,'')=%s
          AND LOWER(TRIM(alias_name))=LOWER(TRIM(%s))
    """, (current_user.get("name", ""), project_name, alias_name))
    cur.execute("""
        INSERT INTO material_aliases (
            project_name, alias_name, canonical_name, canonical_unit,
            source, active, updated_by, updated_at, created_at
        )
        VALUES (%s,%s,%s,%s,%s,%s,%s,NOW(),NOW())
        RETURNING *
    """, vals)
    row = cur.fetchone()
    cur.close(); conn.close()
    return _material_alias_row(row)

@app.delete("/material-aliases/{id}")
def delete_material_alias(id: int, current_user: dict = Depends(require_roles(*LEADERSHIP_ROLES, "прораб", "главный_инженер", "сметчик", "снабженец", "кладовщик"))):
    conn = get_db()
    cur = conn.cursor(cursor_factory=psycopg2.extras.RealDictCursor)
    cur.execute("SELECT project_name FROM material_aliases WHERE id=%s", (id,))
    row = cur.fetchone()
    if not row:
        cur.close(); conn.close()
        raise HTTPException(status_code=404, detail="Сопоставление материала не найдено")
    project_name = row["project_name"] or ""
    if project_name:
        require_project_access(current_user, project_name)
    cur.execute("UPDATE material_aliases SET active=FALSE, updated_by=%s, updated_at=NOW() WHERE id=%s", (current_user.get("name", ""), id))
    cur.close(); conn.close()
    return {"ok": True}

@app.get("/material-norms")
def list_material_norms(
    search: str = "",
    limit: Optional[int] = None,
    offset: int = 0,
    _current_user: dict = Depends(require_roles(*PROJECT_DOCUMENT_ROLES)),
):
    conn = get_db()
    cur = conn.cursor(cursor_factory=psycopg2.extras.RealDictCursor)
    where = ["active=TRUE"]
    params = []
    search_value = (search or "").strip()
    if search_value:
        where.append("""(
            COALESCE(rule_key, '') ILIKE %s OR
            COALESCE(name, '') ILIKE %s OR
            COALESCE(label, '') ILIKE %s OR
            COALESCE(array_to_string(work_keywords, ' '), '') ILIKE %s OR
            COALESCE(array_to_string(material_keywords, ' '), '') ILIKE %s
        )""")
        params.extend([f"%{search_value}%"] * 5)
    page_sql, page_params = limit_offset_sql(limit, offset)
    cur.execute("""SELECT id, rule_key, name, work_keywords, block_work_keywords, material_keywords,
                          work_unit, material_unit, qty_per_unit, thickness_base_mm,
                          default_thickness_mm, label, active, updated_by, updated_at
                   FROM material_norms
                   WHERE """ + " AND ".join(where) + """
                   ORDER BY name, id""" + page_sql, params + page_params)
    rows = cur.fetchall()
    cur.close(); conn.close()
    return [_material_norm_row(r) for r in rows]

@app.post("/material-norms")
def create_material_norm(data: MaterialNormModel, current_user: dict = Depends(require_roles(*LEADERSHIP_ROLES, "прораб", "главный_инженер", "сметчик"))):
    conn = get_db()
    cur = conn.cursor(cursor_factory=psycopg2.extras.RealDictCursor)
    vals = _material_norm_values(data, current_user.get("name", ""))
    try:
        cur.execute("""
            INSERT INTO material_norms (
                rule_key, name, work_keywords, block_work_keywords, material_keywords,
                work_unit, material_unit, qty_per_unit, thickness_base_mm,
                default_thickness_mm, label, active, updated_by, updated_at
            )
            VALUES (%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,NOW())
            RETURNING id, rule_key, name, work_keywords, block_work_keywords, material_keywords,
                      work_unit, material_unit, qty_per_unit, thickness_base_mm,
                      default_thickness_mm, label, active, updated_by, updated_at
        """, vals)
    except psycopg2.errors.UniqueViolation:
        cur.close(); conn.close()
        raise HTTPException(status_code=400, detail="Код нормы уже используется")
    row = cur.fetchone()
    cur.close(); conn.close()
    return _material_norm_row(row)

@app.get("/material-norms/overrides")
def list_material_norm_overrides(project_name: str = None, estimate_id: int = None, current_user: dict = Depends(require_roles(*PROJECT_DOCUMENT_ROLES))):
    conn = get_db()
    cur = conn.cursor(cursor_factory=psycopg2.extras.RealDictCursor)
    where = ["active=TRUE"]
    params = []
    if project_name:
        require_project_access(current_user, project_name)
        where.append("project_name=%s")
        params.append(project_name)
    else:
        allowed = visible_project_names(current_user)
        if allowed is not None:
            if not allowed:
                cur.close(); conn.close()
                return []
            where.append("project_name = ANY(%s)")
            params.append(allowed)
    if estimate_id:
        where.append("estimate_id=%s")
        params.append(estimate_id)
    cur.execute(f"""SELECT * FROM material_norm_overrides
                    WHERE {' AND '.join(where)}
                    ORDER BY updated_at DESC, id DESC""", tuple(params))
    rows = cur.fetchall()
    cur.close(); conn.close()
    return [_material_norm_override_row(r) for r in rows]

