def _safe_float(value, default=0.0):
    try:
        if value is None or value == "":
            return default
        if isinstance(value, str):
            text = value.strip().replace("\xa0", " ").replace(" ", "").replace(",", ".")
            if not text:
                return default
            return float(text)
        return float(value)
    except Exception:
        return default

def _norm_key_text(value: str) -> str:
    import re
    return re.sub(r"\s+", " ", re.sub(r"[.,;:()«»\"'`/\\]+", " ", str(value or "").lower())).strip()

def _norm_keywords_from_text(value: str, limit: int = 5) -> list[str]:
    stop = {"работ", "работа", "монтаж", "установка", "устройство", "демонтаж", "разбор", "прочее", "раздел", "материал", "для", "при", "под"}
    words = []
    for token in _norm_key_text(value).split():
        if len(token) < 4 or token in stop:
            continue
        if token not in words:
            words.append(token)
    return words[:limit]

def _estimate_item_type_backend(item: dict, section_name: str = "") -> str:
    raw = str(item.get("itemType") or item.get("type") or item.get("kind") or "").lower()
    text = _norm_key_text((item.get("name") or "") + " " + section_name)
    source_code = str(item.get("sourceCode") or item.get("obosn") or item.get("code") or "").strip()
    material_markers = ("смесь", "ротбанд", "кнауф", "штукатурка", "штукатурк", "шпатлевка", "шпатлевк", "шпаклевка", "шпаклевк", "пескобетон", "наливн", "ровнител", "затир", "клей", "краска", "акрил", "грунтовка", "грунтовк", "кабель", "провод", "гофра", "лист гкл", "гклв", "гипрок", "гвлв", "гипсовол", "аквапан", "профиль", "саморез", "шуруп", "самонар", "анкер", "болт", "гайк", "шайб", "прессшайб", "дюб", "кирпич", "бетон", "плитка", "плитк", "керамическ", "керамогранит", "гранит", "livorno", "ливорно", "axima", "аксима", "пвх", "уголок", "подвес", "маяк", "рейк", "лента", "серпян", "панель", "плинтус", "наличник", "металлочереп", "черепиц", "монтеррей", "кровл", "кроншт", "направл", "фитинг", "муфт", "тройник", "отвод", "нипп", "переход", "заглуш", "коллект", "клапан", "американ", "воздухоотвод", "радиатор", "бимет", "светиль", "светодиод", "прожектор", "ламп", "розет", "выключ", "автомат", "узо", "щит", "ппр", "ppr", "полипроп", "канализ", "доска", "брус", "фанер", "осп", "osb", "гвозд", "шпил", "перфолента")
    strong_work_markers = ("монтаж", "установка", "устройство", "демонтаж", "разбор", "разборка", "прокладка", "замена", "подключение", "снятие", "очистка", "ремонт", "облицовка", "окраска", "кладка", "стяжка", "отбивка", "отбивк", "грунтование")
    source_looks_work = bool(re.match(r"^(ГЭСН|ФЕР|ТЕР)", source_code, re.I))
    source_looks_resource = bool(re.match(r"^\d{2,}[-/]\d+", source_code) or re.match(r"^\d{3,}$", source_code) or re.match(r"^(ТЦ_|ФСБЦ|ФССЦ)", source_code, re.I))
    if raw in ("adjustment", "корректировка", "note", "примечание"):
        return "other"
    if raw in ("work", "работа", "works", "работы") and item.get("isImported") and source_looks_work:
        return "work"
    if raw in ("work", "работа", "works", "работы") and item.get("isImported"):
        if (source_looks_resource or any(m in text for m in material_markers)) and not any(w in text for w in strong_work_markers):
            return "material"
    if raw in ("work", "работа", "works", "работы"):
        return "work"
    if raw in ("material", "материал", "materials", "материалы") or "материал" in raw:
        return "material"
    if raw in ("equipment", "оборудование", "delivery", "доставка", "other", "прочее"):
        return "other"
    if any(m in text for m in material_markers) and not any(w in text for w in strong_work_markers):
        return "material"
    return "work"

def _norm_base_unit(value: str) -> str:
    import re
    text = _norm_key_text(str(value or "").replace("²", "2").replace("³", "3"))
    text = re.sub(r"^\d{2,}\s*", "", text).strip()
    compact = text.replace(" ", "")
    if compact in ("м", "мп", "пм", "погм", "погметр", "метр", "метра", "метров"):
        return "м"
    if compact in ("м2", "квм", "квадратныйметр", "квадратногометра", "квадратныхметров"):
        return "м2"
    if compact in ("м3", "кубм", "кубическийметр", "кубическогометра", "кубическихметров"):
        return "м3"
    if compact in ("шт", "штук", "штука", "штуки"):
        return "шт"
    if compact in ("компл", "комплект", "комплекта", "комплектов"):
        return "компл"
    if compact in ("кг", "килограмм", "килограмма", "килограммов"):
        return "кг"
    if compact in ("л", "литр", "литра", "литров"):
        return "л"
    if compact in ("т", "тонна", "тонны", "тонн"):
        return "т"
    if compact in ("мешок", "мешка", "мешков"):
        return "мешок"
    return text

def _round_norm_qty(qty) -> float:
    q = _safe_float(qty)
    if q <= 0:
        return 0
    if q >= 100:
        import math
        return float(math.ceil(q))
    if q >= 10:
        return round(q, 1)
    return round(q, 2)

def _convert_norm_material_qty(material_name: str, qty, from_unit: str, to_unit: str):
    import re
    from_key = _norm_base_unit(from_unit)
    to_key = _norm_base_unit(to_unit)
    q = _safe_float(qty)
    if from_key == to_key:
        return q, "единицы совпадают"
    name = _norm_key_text(material_name or "")
    if {from_key, to_key} == {"т", "кг"}:
        return (q * 1000, "1 т = 1000 кг") if from_key == "т" else (q / 1000, "1000 кг = 1 т")
    if any(w in name for w in ("краск", "эмал", "грунтов", "лак")) and {from_key, to_key} == {"л", "кг"}:
        density = 1.4
        return (q * density, "1 л ≈ 1.4 кг") if from_key == "л" else (q / density, "1 кг ≈ 0.71 л")
    if "цемент" in name and {from_key, to_key} == {"мешок", "кг"}:
        return (q * 50, "1 мешок = 50 кг") if from_key == "мешок" else (q / 50, "50 кг = 1 мешок")
    if any(w in name for w in ("штукатур", "шпаклев", "шпатлев", "клей", "пескобетон", "стяжк", "смесь")) and {from_key, to_key} == {"мешок", "кг"}:
        return (q * 25, "1 мешок ≈ 25 кг") if from_key == "мешок" else (q / 25, "25 кг ≈ 1 мешок")
    if "бетон" in name:
        if from_key == "м3" and to_key == "т":
            return q * 2.4, "1 м3 ≈ 2.4 т"
        if from_key == "т" and to_key == "м3":
            return q / 2.4, "1 т ≈ 0.42 м3"
    if any(w in name for w in ("арматур", "арм")) and {from_key, to_key} == {"м", "кг"}:
        weights = {6: 0.222, 8: 0.395, 10: 0.617, 12: 0.888, 14: 1.21, 16: 1.58, 18: 2.0, 20: 2.47, 22: 2.98, 25: 3.85, 28: 4.83, 32: 6.31}
        m = re.search(r"(?:Ø|Ф|ф)?\s*(\d{1,2})\s*мм", material_name or "")
        diameter = int(m.group(1)) if m else None
        factor = weights.get(diameter)
        if factor:
            return (q * factor, f"1 м ≈ {factor:g} кг") if from_key == "м" else (q / factor, f"1 кг ≈ {1/factor:.3f} м")
    return None

def _sql_norm_unit(column: str = "unit") -> str:
    # Только для внутренних SQL-фрагментов с заранее заданными именами колонок.
    if not all(ch.isalnum() or ch in "._" for ch in column):
        column = "unit"
    return "LOWER(REPLACE(REPLACE(REPLACE(REPLACE(TRIM(COALESCE(" + column + ",'')),'²','2'),'³','3'),'.',''),' ',''))"

def _estimate_scaled_unit(value: str) -> tuple[int, str]:
    import re
    raw = str(value or "").strip().replace("\xa0", " ")
    raw = re.sub(r"\s+", " ", raw)
    m = re.match(r"^(\d{2,})\s*(.+)$", raw)
    if not m:
        return 1, raw
    factor = int(m.group(1) or 1)
    return (factor, m.group(2).strip()) if factor >= 10 else (1, raw)

def _estimate_imported_quantity(item: dict) -> float:
    qty = _safe_float(item.get("quantity"))
    if not item.get("isImported"):
        return qty
    unit_factor = _safe_float(item.get("unitFactor") or item.get("unit_factor"), 1)
    unit_factor = unit_factor if unit_factor > 0 else 1
    unit_scale, _ = _estimate_scaled_unit(item.get("unit") or "")
    raw_unit_scale, _ = _estimate_scaled_unit(item.get("rawUnit") or item.get("raw_unit") or "")
    factor = max(unit_factor, unit_scale, raw_unit_scale, 1)
    if factor <= 1:
        return qty
    source = None
    for key in ("rawQuantity", "raw_quantity", "quantityFinal", "quantity_final", "quantityBase", "quantity_base"):
        if item.get(key) not in (None, ""):
            source = _safe_float(item.get(key))
            break
    source = qty if source is None else source
    expected = source if abs(source) >= factor else source * factor
    if qty == 0:
        return expected
    inflated = abs(qty) > max(1000, abs(expected) * 10)
    scaled_unit_visible = unit_scale > 1 or raw_unit_scale > 1
    if inflated or scaled_unit_visible:
        return expected
    return qty

def _estimate_material_plan_issue_backend(item: dict, section_name: str = "") -> str:
    if _estimate_item_type_backend(item, section_name) != "material":
        return ""
    qty = _estimate_imported_quantity(item)
    unit = _norm_base_unit(item.get("unit") or "")
    raw_qty_present = any(item.get(key) not in (None, "") for key in ("rawQuantity", "raw_quantity", "quantityFinal", "quantity_final", "quantityBase", "quantity_base"))
    unit_factor = _safe_float(item.get("unitFactor") or item.get("unit_factor"), 1)
    unit_scale, _ = _estimate_scaled_unit(item.get("unit") or "")
    raw_unit_scale, _ = _estimate_scaled_unit(item.get("rawUnit") or item.get("raw_unit") or "")
    has_scale = unit_factor > 1 or unit_scale > 1 or raw_unit_scale > 1
    if qty <= 0:
        return "Количество материала не задано или меньше нуля"
    if item.get("isImported") and has_scale and not raw_qty_present and abs(_safe_float(item.get("quantity"))) > max(100000, abs(qty) * 100):
        return "Импортная ресурсная строка потеряла исходный объём. Проверьте строку перед закупкой"
    if abs(qty) > 10000000:
        return "Подозрительно большое количество. Проверь импорт сметы и исходную единицу измерения"
    if unit in ("шт", "компл") and abs(qty) > 1000000:
        return "Подозрительно большое штучное количество. Проверь ресурсную строку сметы"
    if not unit or unit == "1":
        return "Не распознана единица измерения материала"
    return ""

def _estimate_parent_work_for_material(material: dict, works: list[dict]) -> dict:
    if not material or not works:
        return {}
    parent_key = str(material.get("parentWorkKey") or material.get("parent_work_key") or "").strip()
    parent_code = str(material.get("parentWorkSourceCode") or material.get("parent_work_source_code") or "").strip()
    parent_name = _norm_key_text(material.get("parentWorkName") or material.get("parent_work_name") or "")
    if parent_key:
        for work in works:
            if parent_key == str(work.get("workKey") or work.get("work_key") or "").strip():
                return work
    if parent_code:
        for work in works:
            if parent_code == str(work.get("sourceCode") or work.get("source_code") or work.get("obosn") or work.get("code") or "").strip():
                return work
    if parent_name:
        for work in works:
            work_name = _norm_key_text(work.get("workName") or work.get("name") or "")
            if work_name == parent_name:
                return work
        for work in works:
            work_name = _norm_key_text(work.get("workName") or work.get("name") or "")
            if work_name and (parent_name in work_name or work_name in parent_name):
                return work
    return {}

def _work_no_material_norm_reason(work_name: str = "", section_name: str = "") -> str:
    text = _norm_key_text((work_name or "") + " " + (section_name or ""))
    if any(w in text for w in ("демонтаж", "разбор", "разборка", "снятие", "отбивка")):
        return "Демонтажная/разборочная работа — материал по норме не требуется."
    if any(w in text for w in ("очистка", "обеспыливание", "пробивка", "погрузка", "перевозка", "затаривание")):
        return "Подготовительная или транспортная операция — материал по норме не требуется."
    if "без стоимости оборудования" in text or "ранее демонтирован" in text:
        return "Установка ранее демонтированного оборудования — новый материал по норме не требуется."
    return ""

def _material_no_norm_reason(material_name: str = "") -> str:
    text = _norm_key_text(material_name or "")
    if any(w in text for w in ("сверло", "бур", "диск отрез", "круг отрез", "коронка алмаз", "оснастк", "инструмент")):
        return "Расходный инструмент/оснастка — не участвует в подборе нормы строительного материала."
    return ""

def _norm_spec_text(value: str = "") -> str:
    import re
    text = str(value or "").lower().replace("ё", "е").replace(",", ".")
    text = text.replace("×", "х").replace("x", "х").replace("Ø", " диаметр ").replace("ø", " диаметр ")
    text = text.replace("–", "-").replace("—", "-")
    return re.sub(r"\s+", " ", text).strip()

def _norm_spec_num(value):
    try:
        return round(float(str(value or "").replace(",", ".")), 3)
    except Exception:
        return None

def _norm_unique_nums(items):
    return sorted({float(x) for x in items if x is not None})

def _norm_extract_diameters(value: str = "") -> list[float]:
    import re
    text = _norm_spec_text(value)
    out = []
    for m in re.finditer(r"(?:диаметр(?:ом)?|диам\.?|ф)\D{0,45}(\d{1,3}(?:\.\d+)?)(?:\s*х\s*(\d{1,3}(?:\.\d+)?))?", text):
        for raw in (m.group(1), m.group(2)):
            n = _norm_spec_num(raw)
            if n is not None and 6 <= n <= 250:
                out.append(n)
    return _norm_unique_nums(out)

def _norm_extract_rect_sizes(value: str = "") -> list[str]:
    import re
    text = _norm_spec_text(value)
    out = []
    for m in re.finditer(r"(\d{1,4})\s*х\s*(\d{1,4})(?:\s*х\s*(\d{1,4}))?\s*мм", text):
        nums = [int(x) for x in m.groups() if x]
        if len(nums) >= 2 and all(0 < n <= 2000 for n in nums):
            out.append("х".join(str(n) for n in nums))
    return sorted(set(out))

def _norm_extract_cable_sections(value: str = "") -> list[str]:
    import re
    text = _norm_spec_text(value)
    out = []
    for m in re.finditer(r"(\d{1,2})\s*х\s*(\d{1,2}(?:\.\d+)?)(?:\s*х\s*(\d{1,2}(?:\.\d+)?))?(?=\s*(?:мм2|мм²|кв\.?\s*мм|ок|нг|fr|ls|hf|$))", text):
        parts = []
        for raw in (m.group(1), m.group(2), m.group(3)):
            if not raw:
                continue
            n = _norm_spec_num(raw)
            if n is not None:
                parts.append(str(n).rstrip("0").rstrip(".").replace(".", ","))
        if len(parts) >= 2:
            out.append("х".join(parts))
    return sorted(set(out))

def _norm_specs_overlap(left: list, right: list) -> bool:
    return not left or not right or any(v in right for v in left)

def _norm_rule_specific_enough(rule: dict, work_text: str) -> bool:
    text = _norm_key_text(work_text or "")
    words = text.split()
    has_cable_word = any(
        w.startswith("кабел") or w.startswith("гофр") or (w.startswith("провод") and not w.startswith("трубопровод"))
        for w in words
    )
    rule_key = _norm_key_text(rule.get("rule_key") or "")
    material_text = _norm_key_text(" ".join(_norm_list(rule.get("material_keywords"))))
    material_words = material_text.split()
    is_cable_rule = (
        "cable" in rule_key or
        any(w in material_text for w in ("кабел", "utp", "ftp", "гофр", "кабель канал")) or
        any(w.startswith("провод") and not w.startswith("трубопровод") for w in material_words)
    )
    if is_cable_rule and "проклад" in text and not has_cable_word:
        return False
    if "cable_line" in rule_key and any(w in text for w in ("труба гофр", "гофрирован", "кабель канал", "короб", "лоток", "металлорукав")) and not any(w in text for w in ("затягивание", "прокладка кабел", "прокладка провод", "провод в короб", "кабель в короб")):
        return False
    if "pipe_insulation" in rule_key and not any(w in text for w in ("изоляц", "теплоизоляц", "утепл", "энергофлекс")):
        return False
    return True

def _norm_material_unit_compatible(rule: dict, material_name: str = "", material_unit: str = "") -> bool:
    rule_unit = _norm_base_unit(rule.get("material_unit") or "")
    unit = _norm_base_unit(material_unit or "")
    if not rule_unit or not unit or rule_unit == unit:
        return True
    material_text = _norm_key_text(material_name or "")
    pair = {rule_unit, unit}
    if pair == {"кг", "мешок"} and any(w in material_text for w in ("цемент", "штукатур", "шпаклев", "шпатлев", "клей", "пескобетон", "стяжк", "смесь")):
        return True
    if pair == {"л", "кг"} and any(w in material_text for w in ("краск", "эмал", "грунтов", "лак")):
        return True
    if pair == {"т", "кг"}:
        return True
    if pair == {"м", "кг"} and any(w in material_text for w in ("арматур", "арм")):
        return True
    return False

def _norm_material_family_compatible(rule: dict, material_name: str = "") -> bool:
    rule_key = _norm_key_text(rule.get("rule_key") or "")
    rule_text = _norm_key_text(" ".join([rule_key, rule.get("name") or "", " ".join(_norm_list(rule.get("material_keywords")))]))
    material_text = _norm_key_text(material_name or "")
    def has(words):
        return any(w in material_text for w in words)
    fitting_words = ("муфта", "угольник", "угол", "тройник", "переход", "кран", "фитинг", "отвод", "вентиль", "клапан")
    pipe_words = ("труба", "трубы", "трубн", "ppr", "pprc", "ppr c", "ppr-c", "полипропилен")
    pipe_clamp_words = ("хомут", "кронштейн", "клипс", "клипса", "скоба", "держатель", "опора", "подвес", "консоль")
    insulation_words = ("изоляц", "теплоизоляц", "утепл", "утеплител", "минераловат", "минвата", "вата", "изовер", "технониколь", "пенополиэтилен", "энергофлекс")
    fastener_words = ("дюбел", "дюбель", "саморез", "шуруп", "анкер", "гвозд", "болт")
    cable_words = ("кабель", "провод", "utp", "ftp", "sftp", "f-utp", "u-utp", "кпс", "ксвв", "кспв", "квп", "ввг", "nym", "frls", "frhf")
    cable_protection_words = ("кабель канал", "короб", "гофр", "гофра", "гофрирован", "труба пнд", "труба пвх", "трубы гибкие", "лоток", "металлорукав")
    cable_fastener_words = ("скоб", "хомут", "крепеж", "креплен", "клипс", "держатель", "дюбел", "дюбель", "саморез", "анкер", "болт", "шуруп")
    if "cable_fasteners" in rule_key:
        return has(cable_fastener_words)
    if "cable_line" in rule_key:
        return has(cable_words) and not has(cable_protection_words) and not has(cable_fastener_words)
    if "cable_protection" in rule_key:
        return has(cable_protection_words)
    if "cable_channel_box" in rule_key:
        return has(("кабель канал", "короб"))
    if "pipe_pp" in rule_key:
        return has(pipe_words) and not has(fitting_words) and not has(pipe_clamp_words) and not has(fastener_words)
    if "pipe_fittings" in rule_key:
        return has(fitting_words)
    if "pipe_clamps" in rule_key:
        return has(pipe_clamp_words)
    if "pipe_insulation" in rule_key:
        return has(insulation_words) and not has(fastener_words)
    if "thermal_insulation_board" in rule_key:
        return has(insulation_words) and not has(fastener_words)
    if "thermal_insulation_fasteners" in rule_key:
        return has(fastener_words) and has(("теплоизоляц", "изоляц"))
    if "radiator_connection_kit" in rule_key:
        return has(("комплект монтаж", "комплект подключ", "подключения радиатор", "радиаторный комплект"))
    if "radiator_mount" in rule_key:
        return has(("кронштейн", "консоль", "крепление радиатор", "крепеж радиатор", "комплект крепления"))
    if "изоляция труб" in rule_text:
        return has(insulation_words) and not has(fastener_words)
    if "трубопровод" in rule_text and has(fastener_words) and not has(pipe_clamp_words):
        return False
    return True

def _norm_material_spec_compatible(rule: dict, work_text: str = "", material_name: str = "") -> bool:
    rule_key = _norm_key_text(rule.get("rule_key") or "")
    work_diameters = _norm_extract_diameters(work_text)
    material_diameters = _norm_extract_diameters(material_name)
    diameter_rules = ("pipe_pp", "pipe_fittings", "pipe_clamps", "pipe_insulation", "cable_protection")
    if any(k in rule_key for k in diameter_rules) and not _norm_specs_overlap(work_diameters, material_diameters):
        return False
    if "cable_line" in rule_key and not _norm_specs_overlap(_norm_extract_cable_sections(work_text), _norm_extract_cable_sections(material_name)):
        return False
    if ("cable_channel_box" in rule_key or "cable_protection" in rule_key) and not _norm_specs_overlap(_norm_extract_rect_sizes(work_text), _norm_extract_rect_sizes(material_name)):
        return False
    return True

def _norm_rule_matches(rule: dict, work_name: str, section_name: str, material_name: str, work_unit: str = "", material_unit: str = "") -> bool:
    work_text = _norm_key_text((work_name or "") + " " + (section_name or ""))
    mat_text = _norm_key_text(material_name or "")
    work_words = _norm_list(rule.get("work_keywords"))
    block_words = _norm_list(rule.get("block_work_keywords"))
    material_words = _norm_list(rule.get("material_keywords"))
    if _work_no_material_norm_reason(work_name, section_name):
        return False
    if work_unit and rule.get("work_unit") and _norm_base_unit(work_unit) != _norm_base_unit(rule.get("work_unit")):
        return False
    if not _norm_rule_specific_enough(rule, work_text):
        return False
    if not _norm_material_unit_compatible(rule, material_name, material_unit):
        return False
    if not _norm_material_family_compatible(rule, material_name):
        return False
    if not _norm_material_spec_compatible(rule, (work_name or "") + " " + (section_name or ""), material_name):
        return False
    return (
        any(_norm_key_text(w) and _norm_key_text(w) in work_text for w in work_words) and
        not any(_norm_key_text(w) and _norm_key_text(w) in work_text for w in block_words) and
        any(_norm_key_text(w) and _norm_key_text(w) in mat_text for w in material_words)
    )

def _estimate_norm_candidate_work(material_name: str, works: list[dict], section_name: str = "", material_unit: str = "") -> dict:
    material_text = _norm_key_text(material_name)
    if not material_text or not works:
        return {}
    pairs = [
        (("штукатур", "ротбанд", "гипсов"), ("штукатур",)),
        (("грунтов",), ("грунтов",)),
        (("краск", "эмал"), ("окраск", "покраск")),
        (("шпаклев", "шпатлев"), ("шпаклев", "шпатлев")),
        (("клей", "плиточ", "затир"), ("плитк", "керамогранит", "облицов")),
        (("кабель", "провод", "ввг", "nym", "utp", "ftp", "кпс", "кпкв"), ("кабел", "провод", "проклад")),
        (("гофр", "кабель канал", "короб"), ("гофр", "труб", "кабель", "короб")),
        (("коробка ответв", "распаечн"), ("коробка ответв", "распаечн")),
        (("розет", "выключател", "штепсель"), ("розет", "выключател", "штепсель")),
        (("щит", "шкаф", "бокс распредел"), ("щит", "шкаф", "распределительн")),
        (("труб", "полипропилен", "муфта", "угольник", "хомут"), ("трубопровод", "водоснаб", "отоплен")),
        (("радиатор", "кронштейн", "клапан"), ("радиатор", "отоплен")),
        (("светильник", "табло", "транспарант"), ("светильник", "табло", "транспарант")),
        (("фанер",), ("фанер", "пол")),
        (("osb", "древесн", "плиты"), ("основан", "фанер", "пол")),
        (("линолеум", "плинтус"), ("линолеум", "плинтус")),
        (("двер", "блок двер"), ("двер", "блок")),
        (("окон", "подокон"), ("окон", "подокон")),
        (("бетон",), ("бетон",)),
        (("кирпич",), ("кладк", "кирпич")),
        (("сетка", "маяч"), ("штукатур",)),
        (("дюбель", "саморез"), ("креп", "гипсокарт", "гкл", "профиль", "теплоизоляц")),
        (("сверло", "алмаз"), ("пробив", "отверст")),
        (("изоляц", "пенополиэтилен"), ("изоляц", "теплоизоляц")),
    ]
    stop = {"материал", "изделия", "разные", "прочие", "наружный", "диаметр", "номинальный", "давление", "размер"}
    material_tokens = {t for t in material_text.split() if len(t) >= 5 and t not in stop}
    material_base_unit = _norm_base_unit(material_unit)
    best = (0, {})
    for work in works:
        work_text = _norm_key_text(work.get("name") or "")
        if _work_no_material_norm_reason(work.get("name"), section_name):
            continue
        work_words = work_text.split()
        has_cable_word = any(
            w.startswith("кабел") or w.startswith("гофр") or (w.startswith("провод") and not w.startswith("трубопровод"))
            for w in work_words
        )
        if any(w in material_text for w in ("кабел", "провод", "utp", "ftp", "кпс", "кпкв")) and not has_cable_word:
            continue
        semantic_score = 0
        for material_words, work_words in pairs:
            if any(w in material_text for w in material_words) and any(w in work_text for w in work_words):
                semantic_score += 5
        work_tokens = {t for t in work_text.split() if len(t) >= 5 and t not in stop}
        semantic_score += min(3, len(material_tokens & work_tokens))
        if semantic_score <= 0:
            continue
        score = semantic_score
        work_base_unit = _norm_base_unit(work.get("unit"))
        if material_base_unit and work_base_unit:
            if material_base_unit == work_base_unit:
                score += 4
            elif material_base_unit in ("шт", "компл") and work_base_unit in ("шт", "соединений", "точк"):
                score += 2
        if score > best[0]:
            best = (score, work)
    return best[1] if best[0] >= 2 else {}

def _material_norm_suggestion_row(row):
    return {
        "id": row["id"],
        "projectName": row["project_name"] or "",
        "suggestionType": row["suggestion_type"] or "",
        "status": row["status"] or "Новая",
        "severity": row["severity"] or "Проверить",
        "workName": row["work_name"] or "",
        "sectionName": row["section_name"] or "",
        "workUnit": row["work_unit"] or "",
        "materialName": row["material_name"] or "",
        "materialUnit": row["material_unit"] or "",
        "currentNormId": row["current_norm_id"],
        "currentQtyPerUnit": _safe_float(row["current_qty_per_unit"]),
        "suggestedQtyPerUnit": _safe_float(row["suggested_qty_per_unit"]),
        "sampleCount": int(row["sample_count"] or 0),
        "actualQty": _safe_float(row["actual_qty"]),
        "normQty": _safe_float(row["norm_qty"]),
        "confidence": _safe_float(row["confidence"]),
        "reason": row["reason"] or "",
        "aiSummary": row["ai_summary"] or "",
        "work": _norm_list(row["work_keywords"]),
        "material": _norm_list(row["material_keywords"]),
        "blockWork": _norm_list(row["block_work_keywords"]),
        "label": row["label"] or "",
        "source": row["source"] or "rules",
        "dedupeKey": row["dedupe_key"] or "",
        "createdBy": row["created_by"] or "",
        "appliedNormId": row["applied_norm_id"],
        "createdAt": str(row["created_at"]) if row["created_at"] else "",
        "updatedAt": str(row["updated_at"]) if row["updated_at"] else "",
    }

def _cursor_rows_as_dicts(cur, rows, columns=None):
    if columns is None:
        columns = [d[0] for d in (cur.description or [])]
    out = []
    for row in rows:
        if isinstance(row, dict):
            out.append(dict(row))
        else:
            out.append({columns[i]: row[i] for i in range(min(len(columns), len(row)))})
    return out

def _load_active_norm_rules(cur, project_name: str = "", estimate_id: int = None):
    cur.execute("""SELECT id, rule_key, name, work_keywords, block_work_keywords, material_keywords,
                          work_unit, material_unit, qty_per_unit, thickness_base_mm,
                          default_thickness_mm, label
                   FROM material_norms WHERE active=TRUE ORDER BY id""")
    base_rules = _cursor_rows_as_dicts(cur, cur.fetchall())
    if not project_name:
        return base_rules
    params = [project_name]
    estimate_clause = ""
    if estimate_id:
        estimate_clause = "AND (estimate_id IS NULL OR estimate_id=%s)"
        params.append(estimate_id)
    cur.execute(f"""SELECT * FROM material_norm_overrides
                    WHERE active=TRUE AND project_name=%s {estimate_clause}
                    ORDER BY CASE WHEN estimate_id IS NULL THEN 1 ELSE 0 END, id DESC""", tuple(params))
    overrides = []
    for r in _cursor_rows_as_dicts(cur, cur.fetchall()):
        overrides.append({
            "id": r.get("base_norm_id"),
            "override_id": r.get("id"),
            "base_norm_id": r.get("base_norm_id"),
            "rule_key": "override_" + str(r.get("id")),
            "name": r.get("material_name") or r.get("label") or "Поправка нормы",
            "work_keywords": r.get("work_keywords"),
            "block_work_keywords": r.get("block_work_keywords"),
            "material_keywords": r.get("material_keywords"),
            "work_unit": r.get("work_unit"),
            "material_unit": r.get("material_unit"),
            "qty_per_unit": r.get("qty_per_unit"),
            "thickness_base_mm": r.get("thickness_base_mm"),
            "default_thickness_mm": r.get("default_thickness_mm"),
            "label": r.get("label") or ("Поправка объекта: " + str(r.get("qty_per_unit") or 0)),
            "project_name": r.get("project_name"),
            "estimate_id": r.get("estimate_id"),
            "reason": r.get("reason"),
        })
    return overrides + base_rules

def _upsert_material_norm_suggestion(cur, suggestion: dict, current_user: dict):
    project_name = suggestion.get("projectName") or ""
    if project_name:
        require_project_access(current_user, project_name)
    dedupe_key = suggestion.get("dedupeKey") or ""
    fields = (
        project_name,
        suggestion.get("suggestionType") or "without_norm",
        suggestion.get("severity") or "Проверить",
        suggestion.get("workName") or "",
        suggestion.get("sectionName") or "",
        suggestion.get("workUnit") or "",
        suggestion.get("materialName") or "",
        suggestion.get("materialUnit") or "",
        suggestion.get("currentNormId"),
        suggestion.get("currentQtyPerUnit") or 0,
        suggestion.get("suggestedQtyPerUnit") or 0,
        int(suggestion.get("sampleCount") or 0),
        suggestion.get("actualQty") or 0,
        suggestion.get("normQty") or 0,
        suggestion.get("confidence") or 0,
        suggestion.get("reason") or "",
        suggestion.get("aiSummary") or "",
        json.dumps(_norm_list(suggestion.get("work")), ensure_ascii=False),
        json.dumps(_norm_list(suggestion.get("material")), ensure_ascii=False),
        json.dumps(_norm_list(suggestion.get("blockWork")), ensure_ascii=False),
        suggestion.get("label") or "",
        suggestion.get("source") or "rules",
        dedupe_key,
        current_user.get("name") or "",
    )
    if dedupe_key:
        cur.execute("""SELECT id FROM material_norm_suggestions
                       WHERE dedupe_key=%s AND status NOT IN ('Принята','Отклонена')
                       LIMIT 1""", (dedupe_key,))
        row = cur.fetchone()
        if row:
            sid = row["id"] if isinstance(row, dict) else row[0]
            cur.execute("""
                UPDATE material_norm_suggestions
                SET project_name=%s, suggestion_type=%s, severity=%s, work_name=%s,
                    section_name=%s, work_unit=%s, material_name=%s, material_unit=%s,
                    current_norm_id=%s, current_qty_per_unit=%s, suggested_qty_per_unit=%s,
                    sample_count=%s, actual_qty=%s, norm_qty=%s, confidence=%s,
                    reason=%s, ai_summary=%s, work_keywords=%s, material_keywords=%s,
                    block_work_keywords=%s, label=%s, source=%s, dedupe_key=%s,
                    created_by=%s, updated_at=NOW()
                WHERE id=%s
            """, fields + (sid,))
            return sid, False
    cur.execute("""
        INSERT INTO material_norm_suggestions (
            project_name, suggestion_type, severity, work_name, section_name, work_unit,
            material_name, material_unit, current_norm_id, current_qty_per_unit,
            suggested_qty_per_unit, sample_count, actual_qty, norm_qty, confidence,
            reason, ai_summary, work_keywords, material_keywords, block_work_keywords,
            label, source, dedupe_key, created_by, created_at, updated_at
        ) VALUES (%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,NOW(),NOW())
        RETURNING id
    """, fields)
    row = cur.fetchone()
    return (row["id"] if isinstance(row, dict) else row[0]), True

def _enhance_norm_suggestions_with_ai(suggestions: list[dict]) -> list[dict]:
    if not suggestions or not (YANDEX_API_KEY and YANDEX_FOLDER_ID):
        return suggestions
    try:
        import openai as oa
        import re as _re
        compact = [{
            "dedupeKey": s.get("dedupeKey"),
            "type": s.get("suggestionType"),
            "work": s.get("workName"),
            "section": s.get("sectionName"),
            "material": s.get("materialName"),
            "unit": s.get("materialUnit"),
            "suggestedQtyPerUnit": s.get("suggestedQtyPerUnit"),
            "reason": s.get("reason"),
        } for s in suggestions[:12]]
        instructions = "Ты отвечаешь строго валидным JSON без markdown. Не выдумывай объёмы, только уточняй ключевые слова, краткое объяснение и уверенность."
        prompt = (
            "Нужно улучшить предложения норм расхода материалов в строительной CRM.\n"
            "Верни JSON: {\"suggestions\":[{\"dedupeKey\":\"...\",\"workKeywords\":[\"...\"],\"materialKeywords\":[\"...\"],\"blockWorkKeywords\":[\"демонтаж\",\"разбор\"],\"label\":\"краткая норма\",\"reason\":\"почему предложено\",\"confidence\":0.0-0.95}]}\n\n"
            "ДАННЫЕ:\n" + json.dumps(compact, ensure_ascii=False)
        )
        client = oa.OpenAI(api_key=YANDEX_API_KEY, base_url="https://ai.api.cloud.yandex.net/v1", project=YANDEX_FOLDER_ID)
        raw = ""
        for model_id in ("qwen3.6-35b-a3b/latest", "yandexgpt-5.1/latest"):
            try:
                r = client.responses.create(
                    model="gpt://" + YANDEX_FOLDER_ID + "/" + model_id,
                    temperature=0.1,
                    instructions=instructions,
                    input=prompt,
                    max_output_tokens=3000,
                )
                raw = (r.output_text or "").strip()
                if raw:
                    break
            except Exception as e:
                print("MATERIAL NORM SUGGEST AI ERROR:", str(e))
        if not raw:
            return suggestions
        clean = _re.sub(r"^```(?:json)?\s*", "", raw).strip()
        clean = _re.sub(r"\s*```\s*$", "", clean).strip()
        s_idx = clean.find("{"); e_idx = clean.rfind("}")
        parsed = json.loads(clean[s_idx:e_idx+1]) if s_idx >= 0 and e_idx > s_idx else {}
        ai_by_key = {str(x.get("dedupeKey") or ""): x for x in (parsed.get("suggestions") or []) if isinstance(x, dict)}
        out = []
        for s in suggestions:
            ai = ai_by_key.get(str(s.get("dedupeKey") or ""))
            if ai:
                s = dict(s)
                s["work"] = _norm_list(ai.get("workKeywords")) or s.get("work") or []
                s["material"] = _norm_list(ai.get("materialKeywords")) or s.get("material") or []
                s["blockWork"] = _norm_list(ai.get("blockWorkKeywords")) or s.get("blockWork") or []
                s["label"] = str(ai.get("label") or s.get("label") or "")
                s["aiSummary"] = str(ai.get("reason") or s.get("aiSummary") or "")
                s["confidence"] = max(_safe_float(s.get("confidence")), min(0.95, _safe_float(ai.get("confidence"))))
                s["source"] = "rules+yandexgpt"
            out.append(s)
        return out
    except Exception as e:
        print("MATERIAL NORM SUGGEST AI PARSE ERROR:", str(e))
        return suggestions

def _generate_material_norm_suggestions(cur, current_user: dict, project_name: str = "", use_ai: bool = True, diagnostics: dict = None) -> list[dict]:
    allowed_projects = visible_project_names(current_user)
    norm_rules = _load_active_norm_rules(cur, project_name)
    if diagnostics is not None:
        diagnostics.update({
            "projectName": project_name or "",
            "activeNormRules": len(norm_rules),
            "workJournalRows": 0,
            "workJournalRowsWithMaterials": 0,
            "workJournalMaterialFacts": 0,
            "activeCustomerEstimates": 0,
            "estimateWorks": 0,
            "estimateMaterials": 0,
            "estimateMaterialsLinkedByParent": 0,
            "estimateMaterialsLinkedByHeuristic": 0,
            "estimateMaterialsCoveredByNorm": 0,
            "estimateMaterialsWithoutCandidateWork": 0,
        })
    suggestions = {}
    where = "WHERE COALESCE(status,'') NOT IN ('Отклонено','Аннулировано')"
    params = []
    if project_name:
        where += " AND project=%s"
        params.append(project_name)
    elif allowed_projects is not None:
        if not allowed_projects:
            return []
        where += " AND project = ANY(%s)"
        params.append(allowed_projects)
    cur.execute(f"""SELECT id, project, description, section_name, unit, quantity, materials_used, date
                    FROM work_journal {where}
                    ORDER BY id DESC LIMIT 800""", tuple(params))
    journal_rows = cur.fetchall()
    if diagnostics is not None:
        diagnostics["workJournalRows"] = len(journal_rows)
    for row in journal_rows:
        work = dict(row)
        try:
            used = json.loads(work.get("materials_used") or "[]")
        except Exception:
            used = []
        if not isinstance(used, list):
            used = []
        if used and diagnostics is not None:
            diagnostics["workJournalRowsWithMaterials"] += 1
        work_qty = _safe_float(work.get("quantity"))
        if work_qty <= 0:
            continue
        for mat in used:
            material_name = str((mat or {}).get("name") or "").strip()
            mat_qty = _safe_float((mat or {}).get("quantity"))
            if not material_name or mat_qty <= 0:
                continue
            if diagnostics is not None:
                diagnostics["workJournalMaterialFacts"] += 1
            if _material_no_norm_reason(material_name):
                continue
            mat_unit = str((mat or {}).get("unit") or "шт")
            norm_qty = _safe_float((mat or {}).get("normQuantity"))
            matching_rule = next((r for r in norm_rules if _norm_rule_matches(r, work.get("description"), work.get("section_name"), material_name, work.get("unit"), mat_unit)), None)
            if norm_qty > 0 and mat_qty <= norm_qty * 1.15:
                continue
            suggestion_type = "over_norm" if norm_qty > 0 else "without_norm"
            dedupe = "|".join([
                suggestion_type,
                _norm_key_text(work.get("project")),
                _norm_key_text(work.get("description"))[:70],
                _norm_key_text(material_name)[:70],
                _norm_key_text(mat_unit),
            ])
            item = suggestions.setdefault(dedupe, {
                "projectName": work.get("project") or "",
                "suggestionType": suggestion_type,
                "severity": "Критично" if suggestion_type == "without_norm" else "Проверить",
                "workName": work.get("description") or "",
                "sectionName": work.get("section_name") or "",
                "workUnit": work.get("unit") or "",
                "materialName": material_name,
                "materialUnit": mat_unit,
                "currentNormId": matching_rule.get("id") if matching_rule and suggestion_type == "over_norm" else None,
                "currentQtyPerUnit": _safe_float(matching_rule.get("qty_per_unit")) if matching_rule else 0,
                "_workQty": 0.0,
                "actualQty": 0.0,
                "normQty": 0.0,
                "sampleCount": 0,
                "reason": "",
                "work": _norm_keywords_from_text((work.get("description") or "") + " " + (work.get("section_name") or "")),
                "material": _norm_keywords_from_text(material_name),
                "blockWork": ["демонтаж", "разбор"],
                "dedupeKey": dedupe,
            })
            item["_workQty"] += work_qty
            item["actualQty"] += mat_qty
            item["normQty"] += norm_qty
            item["sampleCount"] += 1
    for s in suggestions.values():
        work_qty = _safe_float(s.pop("_workQty", 0))
        s["suggestedQtyPerUnit"] = round(s["actualQty"] / work_qty, 4) if work_qty > 0 else 0
        if s["suggestionType"] == "without_norm":
            s["reason"] = "Материал списывали в ЖПР без привязанной нормы. Нужно завести норму или уточнить материал."
            s["confidence"] = min(0.9, 0.55 + s["sampleCount"] * 0.08)
        else:
            over = max(0, s["actualQty"] - s["normQty"])
            pct = round(over / s["normQty"] * 100) if s["normQty"] > 0 else 0
            s["reason"] = f"Фактическое списание выше нормы на {pct}%. Нужно проверить: ошибка списания, слой/условия работы или устаревшая норма."
            s["confidence"] = min(0.85, 0.5 + s["sampleCount"] * 0.06)
        s["label"] = f"{s['materialName']} {s['suggestedQtyPerUnit']} {s['materialUnit']} / {s['workUnit'] or 'ед.'}"

    estimate_where = "WHERE COALESCE(e.is_template,FALSE)=FALSE AND e.status='Активная' AND COALESCE(e.smeta_type,'Заказчик')='Заказчик'"
    estimate_params = []
    if project_name:
        estimate_where += " AND e.project_name=%s"
        estimate_params.append(project_name)
    elif allowed_projects is not None:
        if not allowed_projects:
            return list(suggestions.values())
        estimate_where += " AND e.project_name = ANY(%s)"
        estimate_params.append(allowed_projects)
    cur.execute(f"""SELECT e.id, e.project_name, e.sections_json, COALESCE(e.work_package,'Основная') AS work_package
                    FROM estimates e {estimate_where}
                    ORDER BY e.id DESC LIMIT 120""", tuple(estimate_params))
    estimate_rows = cur.fetchall()
    if diagnostics is not None:
        diagnostics["activeCustomerEstimates"] = len(estimate_rows)
    for est in estimate_rows:
        est_norm_rules = _load_active_norm_rules(cur, est["project_name"] or "", est["id"])
        try:
            sections = json.loads(est["sections_json"] or "[]")
        except Exception:
            sections = []
        for section in sections:
            section_name = section.get("name") or ""
            items = section.get("items") or []
            works = [it for it in items if _estimate_item_type_backend(it, section_name) == "work"]
            mats = [
                it for it in items
                if _estimate_item_type_backend(it, section_name) == "material"
                and not _estimate_material_plan_issue_backend(it, section_name)
            ]
            if diagnostics is not None:
                diagnostics["estimateWorks"] += len(works)
                diagnostics["estimateMaterials"] += len(mats)
            for mat in mats:
                material_name = str(mat.get("name") or "").strip()
                if not material_name:
                    continue
                if _material_no_norm_reason(material_name):
                    continue
                mat_qty = _estimate_imported_quantity(mat)
                if mat_qty <= 0:
                    continue
                parent_work = _estimate_parent_work_for_material(mat, works)
                candidate_works = [parent_work] if parent_work else works
                if any(_norm_rule_matches(r, w.get("name"), section_name, material_name, w.get("unit"), mat.get("unit") or "") for r in est_norm_rules for w in candidate_works):
                    if diagnostics is not None:
                        diagnostics["estimateMaterialsCoveredByNorm"] += 1
                    continue
                work = parent_work or _estimate_norm_candidate_work(material_name, works, section_name, mat.get("unit") or "")
                if not work:
                    if diagnostics is not None:
                        diagnostics["estimateMaterialsWithoutCandidateWork"] += 1
                    continue
                if diagnostics is not None:
                    if parent_work:
                        diagnostics["estimateMaterialsLinkedByParent"] += 1
                    else:
                        diagnostics["estimateMaterialsLinkedByHeuristic"] += 1
                work_qty = _estimate_imported_quantity(work)
                suggested = round(mat_qty / work_qty, 4) if work_qty > 0 and mat_qty > 0 else 0
                dedupe = "|".join([
                    "estimate_material_without_norm",
                    _norm_key_text(est["project_name"]),
                    _norm_key_text(section_name)[:70],
                    _norm_key_text(work.get("name") or "")[:70],
                    _norm_key_text(material_name)[:70],
                ])
                suggestions.setdefault(dedupe, {
                    "projectName": est["project_name"] or "",
                    "workPackage": est.get("work_package") or "Основная",
                    "suggestionType": "estimate_material_without_norm",
                    "severity": "Проверить",
                    "workName": work.get("name") or ("Раздел: " + section_name),
                    "sectionName": section_name,
                    "workUnit": work.get("unit") or "",
                    "materialName": material_name,
                    "materialUnit": mat.get("unit") or "",
                    "currentNormId": None,
                    "currentQtyPerUnit": 0,
                    "suggestedQtyPerUnit": suggested,
                    "sampleCount": 1,
                    "actualQty": mat_qty,
                    "normQty": 0,
                    "confidence": (0.78 if parent_work else 0.52) if suggested else 0.35,
                    "reason": "В активной смете есть материал без нормы. Связка взята из родительской работы сметы." if parent_work else "В активной смете есть материал, но справочник норм не связывает его с работами этого раздела.",
                    "work": _norm_keywords_from_text((work.get("name") or "") + " " + section_name),
                    "material": _norm_keywords_from_text(material_name),
                    "blockWork": ["демонтаж", "разбор"],
                    "label": f"{material_name}" + (f" {suggested} {mat.get('unit') or ''} / {work.get('unit') or 'ед.'}" if suggested else ""),
                    "source": "estimate-parent" if parent_work else "estimate-search",
                    "dedupeKey": dedupe,
                })
    result = list(suggestions.values())
    if diagnostics is not None:
        diagnostics["suggestions"] = len(result)
    return _enhance_norm_suggestions_with_ai(result) if use_ai else result

@app.get("/material-norm-suggestions")
def list_material_norm_suggestions(project_name: str = None, current_user: dict = Depends(require_roles(*PROJECT_DOCUMENT_ROLES))):
    conn = get_db()
    cur = conn.cursor(cursor_factory=psycopg2.extras.RealDictCursor)
    if project_name:
        require_project_access(current_user, project_name)
        cur.execute("""SELECT * FROM material_norm_suggestions WHERE project_name=%s ORDER BY updated_at DESC, id DESC""", (project_name,))
    else:
        allowed_projects = visible_project_names(current_user)
        if allowed_projects is not None:
            if not allowed_projects:
                cur.close(); conn.close()
                return []
            cur.execute("""SELECT * FROM material_norm_suggestions WHERE project_name = ANY(%s) ORDER BY updated_at DESC, id DESC""", (allowed_projects,))
        else:
            cur.execute("""SELECT * FROM material_norm_suggestions ORDER BY updated_at DESC, id DESC""")
    rows = cur.fetchall()
    cur.close(); conn.close()
    return [_material_norm_suggestion_row(dict(r)) for r in rows]

@app.post("/material-norm-suggestions/generate")
def generate_material_norm_suggestions(data: dict = None, current_user: dict = Depends(require_roles(*LEADERSHIP_ROLES, "прораб", "главный_инженер", "сметчик"))):
    data = data or {}
    project_name = data.get("projectName") or data.get("project_name") or ""
    dry_run = bool(data.get("dryRun") or data.get("dry_run"))
    use_ai = False if dry_run else (data.get("useAi", data.get("use_ai", True)) is not False)
    if project_name:
        require_project_access(current_user, project_name)
    conn = get_db()
    cur = conn.cursor(cursor_factory=psycopg2.extras.RealDictCursor)
    diagnostics = {}
    suggestions = _generate_material_norm_suggestions(cur, current_user, project_name, use_ai=use_ai, diagnostics=diagnostics)
    if dry_run:
        for idx, suggestion in enumerate(suggestions, start=1):
            suggestion["id"] = "preview-" + str(idx)
            suggestion["status"] = "Предпросмотр"
            suggestion["source"] = suggestion.get("source") or "rules-preview"
        cur.close(); conn.close()
        return {"ok": True, "dryRun": True, "created": 0, "updated": 0, "findings": 0, "total": len(suggestions), "aiUsed": False, "diagnostics": diagnostics, "suggestions": suggestions}
    created = updated = findings = 0
    for suggestion in suggestions:
        sid, is_created = _upsert_material_norm_suggestion(cur, suggestion, current_user)
        suggestion["id"] = sid
        if is_created:
            created += 1
        else:
            updated += 1
        if suggestion.get("projectName") and suggestion.get("suggestionType") in ("without_norm", "over_norm", "estimate_material_without_norm"):
            _, f_created = _upsert_ai_finding(cur, {
                "projectName": suggestion.get("projectName"),
                "findingType": "ai",
                "category": "Материалы",
                "severity": suggestion.get("severity") or "Проверить",
                "title": "Нужно уточнить норму: " + (suggestion.get("materialName") or ""),
                "description": (suggestion.get("aiSummary") or suggestion.get("reason") or "") + "\nРабота: " + (suggestion.get("workName") or ""),
                "source": suggestion.get("source") or "rules+yandexgpt",
                "linkedEntityType": "material_norm_suggestion",
                "linkedEntityId": str(sid),
                "suggestedAction": "Проверить предложение в Сметы → Нормы материалов и принять норму или отклонить.",
                "assignedRole": "сметчик",
                "dedupeKey": "material_norm_suggestion:" + (suggestion.get("dedupeKey") or str(sid)),
            }, current_user)
            if f_created:
                findings += 1
    cur.close(); conn.close()
    return {"ok": True, "created": created, "updated": updated, "findings": findings, "total": len(suggestions), "aiUsed": bool(YANDEX_API_KEY and YANDEX_FOLDER_ID), "diagnostics": diagnostics}

def _material_pricelist_match_score(material_name: str, material_unit: str, price_item: dict) -> int:
    material_key = _norm_key_text(material_name)
    item_key = _norm_key_text(price_item.get("name") or "")
    if not material_key or not item_key:
        return 0
    score = 0
    item_type = _norm_key_text(price_item.get("item_type") or price_item.get("itemType") or "")
    if "материал" in item_type or item_type == "material":
        score += 20
    if "работ" in item_type or item_type == "work":
        score -= 35
    if material_key == item_key:
        score += 100
    elif material_key in item_key or item_key in material_key:
        score += 70
    else:
        material_tokens = {w for w in material_key.split() if len(w) >= 4}
        item_tokens = {w for w in item_key.split() if len(w) >= 4}
        common = material_tokens & item_tokens
        if common:
            score += min(60, len(common) * 18)
    material_unit_key = _norm_base_unit(material_unit)
    item_unit_key = _norm_base_unit(price_item.get("unit") or "")
    if material_unit_key and item_unit_key:
        score += 15 if material_unit_key == item_unit_key else -10
    return score

def _find_material_pricelist_price(material_name: str, material_unit: str, price_items: list[dict]) -> dict:
    best = None
    best_score = 0
    for item in price_items:
        score = _material_pricelist_match_score(material_name, material_unit, item)
        if score > best_score:
            best = item
            best_score = score
    if not best or best_score < 65:
        return {"price": 0, "source": "", "score": best_score}
    return {"price": _safe_float(best.get("price")), "source": best.get("name") or "", "score": best_score}

@app.post("/material-norm-suggestions/create-estimate")
def create_estimate_from_material_norm_suggestions(data: dict = None, current_user: dict = Depends(require_roles(*ESTIMATE_WRITE_ROLES))):
    import json as _json
    data = data or {}
    project_name = (data.get("projectName") or data.get("project_name") or "").strip()
    if not project_name:
        raise HTTPException(status_code=400, detail="Укажите объект")
    require_project_access(current_user, project_name)

    min_confidence = _safe_float(data.get("minConfidence"), 0.75)
    min_confidence = min(max(min_confidence, 0.0), 1.0)
    include_search = bool(data.get("includeSearch") or data.get("include_search"))
    # Черновик материалов по нормам не должен менять активную смету заказчика.
    # Не доверяем входящим status/smetaType: этот endpoint всегда создает
    # отдельный черновик материалов.
    status = "Черновик"
    smeta_type = "Материалы"
    work_package = data.get("workPackage") or data.get("work_package") or "Доп. материалы"

    conn = get_db()
    cur = conn.cursor(cursor_factory=psycopg2.extras.RealDictCursor)
    cur.execute("SELECT id, pricelist_id FROM projects WHERE name=%s LIMIT 1", (project_name,))
    project = cur.fetchone()
    if not project:
        cur.close(); conn.close()
        raise HTTPException(status_code=404, detail="Объект не найден")

    pricelist_id = data.get("pricelistId") or data.get("pricelist_id") or project.get("pricelist_id")
    price_items = []
    if pricelist_id:
        try:
            cur.execute("""SELECT id, name, unit, price, category, item_type
                           FROM pricelist_items
                           WHERE pricelist_id=%s
                           ORDER BY category, name""", (int(pricelist_id),))
            price_items = [dict(r) for r in cur.fetchall()]
        except Exception:
            price_items = []

    diagnostics = {}
    raw_suggestions = _generate_material_norm_suggestions(cur, current_user, project_name, use_ai=False, diagnostics=diagnostics)
    rows_by_section = {}
    skipped_low_confidence = 0
    skipped_no_quantity = 0
    priced_count = 0
    missing_price_count = 0
    total_amount = 0.0
    now_id = int(time.time() * 1000)

    for suggestion in raw_suggestions:
        if suggestion.get("suggestionType") != "estimate_material_without_norm":
            continue
        source = suggestion.get("source") or ""
        confidence = _safe_float(suggestion.get("confidence"))
        if source != "estimate-parent":
            if not include_search:
                skipped_low_confidence += 1
                continue
            if confidence < min_confidence:
                skipped_low_confidence += 1
                continue
        elif confidence < min_confidence:
            skipped_low_confidence += 1
            continue
        qty = _safe_float(suggestion.get("actualQty"))
        if qty <= 0:
            skipped_no_quantity += 1
            continue
        material_name = (suggestion.get("materialName") or "").strip()
        if not material_name:
            continue
        material_unit = suggestion.get("materialUnit") or "шт"
        price_match = _find_material_pricelist_price(material_name, material_unit, price_items)
        price = price_match["price"]
        if price > 0:
            priced_count += 1
            total_amount += qty * price
        else:
            missing_price_count += 1
        suggestion_package = _supply_work_package(suggestion.get("workPackage") or work_package)
        section_name = suggestion.get("sectionName") or "Материалы по нормам"
        section_key = suggestion_package + " / " + section_name
        rows_by_section.setdefault(section_key, {"name": section_name, "workPackage": suggestion_package, "items": []})["items"].append({
            "id": now_id + sum(len((v or {}).get("items") or []) for v in rows_by_section.values()) + 1,
            "name": material_name,
            "unit": material_unit,
            "quantity": round(qty, 6),
            "priceWork": 0,
            "priceMaterial": round(price, 2) if price else 0,
            "itemType": "material",
            "resourceRole": "material",
            "workPackage": suggestion_package,
            "source": "material_norm_suggestion",
            "normSource": source,
            "confidence": confidence,
            "workName": suggestion.get("workName") or "",
            "parentWorkName": suggestion.get("workName") or "",
            "sectionName": section_name,
            "suggestedQtyPerUnit": suggestion.get("suggestedQtyPerUnit") or 0,
            "workUnit": suggestion.get("workUnit") or "",
            "priceSource": price_match["source"],
            "priceMatchScore": price_match["score"],
            "note": "Цена подтянута из прайса" if price > 0 else "Цена не найдена в прайсе, нужно проверить вручную",
        })

    if not rows_by_section:
        cur.close(); conn.close()
        raise HTTPException(status_code=400, detail="Нет безопасных строк для черновика. Сначала проверьте предложения норм или включите предложения по поиску.")

    sections = []
    for idx, section_data in enumerate(rows_by_section.values(), start=1):
        section_name = section_data.get("name") or "Материалы по нормам"
        section_package = section_data.get("workPackage") or work_package
        sections.append({
            "id": now_id + idx,
            "name": "Материалы по нормам / " + section_name,
            "workPackage": section_package,
            "items": section_data.get("items") or [],
        })

    estimate_name = (data.get("name") or f"Черновик материалов по нормам — {project_name}").strip()
    version = data.get("version") or "norm-" + dt.datetime.now().strftime("%Y%m%d-%H%M")
    cur.execute("""INSERT INTO estimates
                   (project_id, project_name, name, version, sections_json, smeta_type, work_package, status)
                   VALUES (%s,%s,%s,%s,%s,%s,%s,%s)
                   RETURNING id""",
        (project["id"], project_name, estimate_name, version, _json.dumps(sections, ensure_ascii=False), smeta_type, work_package, status))
    estimate_id = cur.fetchone()["id"]
    supply_request = None
    supply_requests = []
    if data.get("createSupplyRequest") or data.get("create_supply_request"):
        grouped = {}
        for section in sections:
            section_package = _supply_work_package(section.get("workPackage") or work_package)
            for item in section.get("items") or []:
                item_package = _supply_work_package(item.get("workPackage") or section_package)
                key = "|".join([
                    item_package,
                    _norm_key_text(item.get("name") or ""),
                    _norm_base_unit(item.get("unit") or ""),
                ])
                if not key.strip("|"):
                    continue
                if key not in grouped:
                    grouped[key] = {
                        "materialName": item.get("name") or "",
                        "quantity": 0.0,
                        "unit": item.get("unit") or "шт",
                        "workPackage": item_package,
                        "pricePerUnit": item.get("priceMaterial") or 0,
                        "estimateId": estimate_id,
                    }
                grouped[key]["quantity"] += _safe_float(item.get("quantity"))
                if not grouped[key].get("pricePerUnit") and item.get("priceMaterial"):
                    grouped[key]["pricePerUnit"] = item.get("priceMaterial")
        supply_items = []
        for item in grouped.values():
            qty = _safe_float(item.get("quantity"))
            if qty <= 0:
                continue
            price = _safe_float(item.get("pricePerUnit"))
            supply_items.append({
                "materialName": item.get("materialName") or "",
                "quantity": round(qty, 6),
                "unit": item.get("unit") or "шт",
                "workPackage": _supply_work_package(item.get("workPackage") or work_package),
                "pricePerUnit": round(price, 2) if price else 0,
                "totalPrice": round(qty * price, 2) if price else 0,
            })
        if supply_items:
            supply_items_by_package = {}
            for item in supply_items:
                supply_items_by_package.setdefault(_supply_work_package(item.get("workPackage") or work_package), []).append(item)
            for package_name, package_items in supply_items_by_package.items():
                request_package = _resolve_supply_request_package(current_user, package_items, package_name)
                package_items = _attach_supply_estimate_control(cur, project_name, package_items)
                if project_name != "Основной склад":
                    _enforce_supply_estimate_control(package_items, source="заявка")
                marker = "NORM_ESTIMATE_REQUEST:" + str(estimate_id) + ":" + request_package
                package_total = sum(_safe_float(it.get("quantity")) * _safe_float(it.get("pricePerUnit")) for it in package_items)
                notes = "\n".join([
                    "Пакетная заявка из черновика сметы по нормам.",
                    marker,
                    "Объект: " + project_name,
                    "Раздел сметы: " + request_package,
                    "Смета: " + estimate_name,
                    "ID сметы: " + str(estimate_id),
                    "Позиций: " + str(len(package_items)),
                    "Сумма по найденным ценам: " + str(round(package_total, 2)),
                ])
                agg_name = package_items[0]["materialName"] + (" и ещё " + str(len(package_items)-1) + " поз." if len(package_items) > 1 else "")
                agg_qty = float(len(package_items)) if len(package_items) > 1 else _safe_float(package_items[0].get("quantity"))
                agg_unit = "поз." if len(package_items) > 1 else package_items[0].get("unit") or "шт"
                cur.execute(
                    "INSERT INTO supply_requests "
                    "(material_name,quantity,unit,project,work_package,created_by,date,notes,selected_suppliers,"
                    "status,requested_by_role,requested_by_id,urgency,category,items_json) "
                    "VALUES (%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s) RETURNING id",
                    (
                        agg_name,
                        agg_qty,
                        agg_unit,
                        project_name,
                        request_package,
                        current_user.get("name") or "",
                        dt.date.today().isoformat(),
                        notes,
                        [],
                        "Новая",
                        current_user.get("role") or "",
                        current_user.get("id"),
                        "обычная",
                        "Нормы материалов",
                        _json.dumps(package_items, ensure_ascii=False),
                    ),
                )
                supply_id = cur.fetchone()["id"]
                cur.execute(SUPPLY_SELECT + " WHERE id=%s", (supply_id,))
                sr = cur.fetchone()
                created_request = dict(sr) if sr else {"id": supply_id}
                supply_requests.append(created_request)
            supply_request = supply_requests[0] if supply_requests else None
    conn.commit()
    cur.close(); conn.close()
    return {
        "ok": True,
        "id": estimate_id,
        "name": estimate_name,
        "version": version,
        "projectName": project_name,
        "smetaType": smeta_type,
        "workPackage": work_package,
        "status": status,
        "sections": sections,
        "items": sum(len(s["items"]) for s in sections),
        "priced": priced_count,
        "missingPrice": missing_price_count,
        "total": round(total_amount, 2),
        "skippedLowConfidence": skipped_low_confidence,
        "skippedNoQuantity": skipped_no_quantity,
        "diagnostics": diagnostics,
        "supplyRequest": supply_request,
        "supplyRequests": supply_requests,
    }

