    cur = conn.cursor()
    status = data.get("status", "Ожидает")
    cur.execute(
        """
        UPDATE own_expenses
           SET status=%s, approved_by=%s
         WHERE id=%s
     RETURNING project_name, employee_name, description, amount, date, photo_url
        """,
        (status, data.get("approvedBy", ""), id),
    )
    row = cur.fetchone()
    if not row:
        conn.rollback()
